_py_ver = sys.version_info[:2]
if _py_ver >= (3, 13):
    logger.warning(
        f"Python {_py_ver[0]}.{_py_ver[1]} detected. This is verified working on recent "
        f"Resolve builds (Studio 20.3.2), but older builds may not load the scripting "
        f"bridge on 3.13+. If scriptapp('Resolve') returns None, recreate the venv with "
        f"Python 3.10-3.12."
    )

# ─── Resolve Connection (lazy) ───────────────────────────────────────────────

sys.path.insert(0, RESOLVE_MODULES_PATH)
resolve = None
dvr_script = None
_resolve_lock = threading.RLock()

try:
    import DaVinciResolveScript as dvr_script
    logger.info("DaVinciResolveScript module loaded")
except ImportError as e:
    logger.error(f"Cannot import DaVinciResolveScript: {e}")

def _is_resolve_handle_live(candidate) -> bool:
    """Return True when a cached Resolve handle still answers root API calls."""
    try:
        get_version = getattr(candidate, "GetVersion", None)
        if not callable(get_version):
            return False
        return bool(get_version())
    except Exception as exc:
        logger.warning(f"Cached Resolve handle is stale: {exc}")
        return False


def _try_connect():
    """Attempt to connect to Resolve once. Returns resolve object or None."""
    global resolve
    with _resolve_lock:
        if dvr_script is None:
            return None
        try:
            candidate = dvr_script.scriptapp("Resolve")
            if candidate and _is_resolve_handle_live(candidate):
                resolve = candidate
                logger.info(f"Connected: {resolve.GetProductName()} {resolve.GetVersionString()}")
            else:
                resolve = None
            return resolve
        except Exception as e:
            logger.error(f"Connection error: {e}")
            resolve = None
            return None

def _launch_resolve():
    """Launch DaVinci Resolve and wait for it to become available."""
    sys_name = platform.system().lower()
    if sys_name == "darwin":
        app_path = "/Applications/DaVinci Resolve/DaVinci Resolve.app"
        if not os.path.exists(app_path):
            logger.error(f"DaVinci Resolve not found at {app_path}")
            return False
        subprocess.Popen(["open", app_path], stdin=subprocess.DEVNULL)
    elif sys_name == "windows":
        app_path = r"C:\Program Files\Blackmagic Design\DaVinci Resolve\Resolve.exe"
        if not os.path.exists(app_path):
            logger.error(f"DaVinci Resolve not found at {app_path}")
            return False
        subprocess.Popen([app_path], stdin=subprocess.DEVNULL)
    elif sys_name == "linux":
        app_path = "/opt/resolve/bin/resolve"
        if not os.path.exists(app_path):
            logger.error(f"DaVinci Resolve not found at {app_path}")
            return False
        subprocess.Popen([app_path], stdin=subprocess.DEVNULL)
    else:
        return False
    logger.info("Launched DaVinci Resolve, waiting for it to respond...")
    for i in range(30):
        time.sleep(2)
        if _try_connect():
            logger.info(f"Resolve responded after {(i+1)*2}s")
            return True
    logger.warning("Resolve did not respond within 60s after launch")
    return False

def get_resolve():
    """Lazy connection to Resolve — connects on first tool call, auto-launches if needed."""
    global resolve
    with _resolve_lock:
        if resolve is not None and _is_resolve_handle_live(resolve):
            return resolve
        resolve = None
        # Try to connect to an already-running Resolve.
        if _try_connect():
            return resolve
        # Not running — launch it automatically.
        logger.info("Resolve not running, attempting to launch automatically...")
        _launch_resolve()
        return resolve


def _destructive_versioning_provider() -> Optional[Tuple[Any, Any, str, Optional[str]]]:
    """Provider used by the C6 version-on-mutate hook.

    Returns (resolve, project, project_root, project_name) or None if any piece
    can't be resolved. The hook degrades silently when this returns None.
    """
    try:
        r = get_resolve()
        if r is None:
            return None
        pm = r.GetProjectManager()
        if pm is None:
            return None
        proj = pm.GetCurrentProject()
        if proj is None:
            return None
        try:
            project_name = proj.GetName()
        except Exception:
            project_name = None
        try:
            project_id = proj.GetUniqueId() if hasattr(proj, "GetUniqueId") else None
        except Exception:
            project_id = None
        root = resolve_media_analysis_output_root(
            project_name=project_name,
            project_id=project_id,
            create=True,
        )
        if not root or not root.get("success"):
            return None
        return (r, proj, root["project_root"], project_name)
    except Exception as exc:
        logger.debug("destructive versioning provider failed: %s", exc)
        return None


_destructive_hook.register_project_root_provider(_destructive_versioning_provider)


