def _ensure_timeline_tracks(tl, track_type: str, needed: int, *, audio_type: str = "stereo"):
    """Ensure a timeline exposes at least `needed` tracks of the requested type."""
    needed = max(0, int(needed or 0))
    added = 0
    try:
        current = int(tl.GetTrackCount(track_type) or 0)
    except Exception as exc:
        return {"success": False, "error": f"GetTrackCount({track_type}) failed: {exc}"}
    while current < needed:
        try:
            if track_type == "audio":
                ok = tl.AddTrack(track_type, {"audioType": audio_type})
            else:
                ok = tl.AddTrack(track_type)
        except TypeError:
            ok = tl.AddTrack(track_type)
        except Exception as exc:
            return {"success": False, "error": f"AddTrack({track_type}) failed: {exc}"}
        if not ok:
            return {"success": False, "error": f"AddTrack({track_type}) returned false at track {current + 1}"}
        added += 1
        current += 1
    return {"success": True, "existing": current - added, "added": added, "count": current}


def _set_multicam_track_names(tl, plan: Dict[str, Any]):
    results = []
    for angle in plan.get("angles") or []:
        angle_name = angle.get("angle_name") or f"Angle {angle.get('angle_index')}"
        v_index = angle.get("video_track_index")
        if v_index:
            try:
                results.append({
                    "track_type": "video",
                    "track_index": v_index,
                    "name": angle_name,
                    "success": bool(tl.SetTrackName("video", int(v_index), str(angle_name))),
                })
            except Exception as exc:
                results.append({"track_type": "video", "track_index": v_index, "success": False, "error": str(exc)})
        a_index = angle.get("audio_track_index")
        if a_index:
            try:
                results.append({
                    "track_type": "audio",
                    "track_index": a_index,
                    "name": angle_name,
                    "success": bool(tl.SetTrackName("audio", int(a_index), str(angle_name))),
                })
            except Exception as exc:
                results.append({"track_type": "audio", "track_index": a_index, "success": False, "error": str(exc)})
    return results


def _setup_multicam_timeline(proj, mp, p: Dict[str, Any]):
    root = mp.GetRootFolder()
    plan, plan_err = build_multicam_setup_plan(root, p, _find_clip)
    if plan_err:
        return plan_err
    if p.get("dry_run", False):
        return {
            **plan,
            "dry_run": True,
            "would_create_timeline": True,
            "would_append": len(plan.get("append_rows") or []),
        }

    new_tl = mp.CreateEmptyTimeline(plan["name"])
    if not new_tl:
        return _err(f"Failed to create multicam setup timeline: {plan['name']}")
    try:
        proj.SetCurrentTimeline(new_tl)
    except Exception:
        pass
    if plan.get("start_timecode"):
        try:
            new_tl.SetStartTimecode(plan["start_timecode"])
        except Exception:
            pass

    audio_type = str(p.get("audio_type", p.get("audioType", "stereo")) or "stereo")
    video_tracks = _ensure_timeline_tracks(new_tl, "video", plan.get("max_video_track", 0))
    if not video_tracks.get("success"):
        return video_tracks
    audio_tracks = _ensure_timeline_tracks(new_tl, "audio", plan.get("max_audio_track", 0), audio_type=audio_type)
    if not audio_tracks.get("success"):
        return audio_tracks
    track_names = _set_multicam_track_names(new_tl, plan)

    timeline_start = _timeline_start_frame(new_tl)
    append_infos = []
    append_rows = plan.get("append_rows") or []
    for index, row in enumerate(append_rows):
        clip_info, clip_err = _build_append_clip_info_dict(root, row, index, timeline_start)
        if clip_err:
            return clip_err
        append_infos.append(clip_info)
    appended = mp.AppendToTimeline(append_infos)
    if not appended:
        return _err("AppendToTimeline returned no items for multicam setup")

    items_out = []
    for index, item in enumerate(appended):
        item_out, item_err = _serialize_appended_timeline_item(item, index, allow_empty_timeline_item_id=True)
        if item_err:
            return item_err
        item_out["setup_row"] = append_rows[index]
        items_out.append(item_out)

    return {
        **plan,
        "dry_run": False,
        "timeline_name": new_tl.GetName(),
        "timeline_id": new_tl.GetUniqueId(),
        "items": items_out,
        "track_setup": {"video": video_tracks, "audio": audio_tracks, "names": track_names},
    }


def _safe_clip_call(clip, method_name: str, *args):
    method = getattr(clip, method_name, None)
    if not callable(method):
        return None, f"{method_name} unavailable"
    try:
        return _ser(method(*args)), None
    except Exception as exc:
        return None, str(exc)


# Clip-property keys whose SetClipProperty/SetMetadata write returns True but is
# silently dropped by Resolve under common project configurations (issue #77).
# For these we read the value back and refuse to report success unless it stuck.
_WRITEBACK_VERIFY_KEYS = frozenset({"Reel Name"})

# Per-key hint explaining the most common cause of a non-persisting write.
_WRITEBACK_VERIFY_HINTS = {
    "Reel Name": (
        "Reel Name is commonly gated by the project setting "
        "'General Options > Assist using reel names from the:'. When that is "
        "set to derive reel names from the source clip / embedding / filename "
        "pattern, Resolve ignores scripted writes to 'Reel Name' (the call "
        "still returns True). Set that option to blank/manual, or assign reel "
        "names in the Resolve UI; the scripting API cannot override the gate."
    ),
}


def _normalize_clip_property_value(value):
    """Coerce a clip-property value to a comparable, trimmed string."""
    if value is None:
        return ""
    return str(value).strip()


def _verify_clip_property_writeback(clip, key, value):
    """Confirm a just-written, known-unreliable clip property actually persisted.

    Returns a structured failure dict when Resolve accepted the write (returned
    True) but the value did not stick on read-back; returns ``None`` when the
    write verified, the key is not in the watch list, or we cannot read it back
    (in which case we don't override the original success). See issue #77.
    """
    if key not in _WRITEBACK_VERIFY_KEYS:
        return None
    actual, err = _safe_clip_call(clip, "GetClipProperty", key)
    if err is not None:
        return None  # can't read back — don't contradict the reported result
    if isinstance(actual, dict):  # GetClipProperty('') style dict, just in case
        actual = actual.get(key)
    if _normalize_clip_property_value(actual) == _normalize_clip_property_value(value):
        return None
    return {
        "success": False,
        "verified": False,
        "key": key,
        "requested": value,
        "actual": actual,
        "error": (
            f"Resolve reported success writing {key!r} but the value did not "
            f"persist (read-back returned {actual!r})."
        ),
        "hint": _WRITEBACK_VERIFY_HINTS.get(key),
    }


def _verify_writeback(clip, written):
    """Verify a batch of just-written {key: value} pairs.

    Returns the first silent-revert failure dict, else ``None``. Only keys in
    ``_WRITEBACK_VERIFY_KEYS`` are checked, so ordinary writes pay nothing.
    """
    if not isinstance(written, dict):
        return None
    for key, value in written.items():
        if key in _WRITEBACK_VERIFY_KEYS:
            fail = _verify_clip_property_writeback(clip, key, value)
            if fail:
                return fail
    return None


def _media_pool_item_summary(clip):
    if not clip:
        return None
    summary = {
        "name": _safe_media_pool_item_name(clip),
        "id": _safe_media_pool_item_id(clip),
        "media_id": None,
        "file_path": None,
        "type": None,
        "duration": None,
    }
    media_id, _ = _safe_clip_call(clip, "GetMediaId")
    if media_id is not None:
        summary["media_id"] = media_id
    properties, _ = _safe_clip_call(clip, "GetClipProperty", "")
    if isinstance(properties, dict):
        summary["file_path"] = properties.get("File Path") or properties.get("FilePath")
        summary["type"] = properties.get("Type")
        summary["duration"] = properties.get("Duration")
    return summary


def _project_name_and_id(project) -> Tuple[Optional[str], Optional[str]]:
    name = project_id = None
    if project and _has_method(project, "GetName"):
        try:
            name = project.GetName()
        except Exception:
            name = None
    if project and _has_method(project, "GetUniqueId"):
        try:
            project_id = project.GetUniqueId()
        except Exception:
            project_id = None
    return name, project_id


def _media_analysis_clip_record(clip, bin_path: Optional[str] = None) -> Optional[Dict[str, Any]]:
    if not clip:
        return None
    props, props_error = _safe_clip_call(clip, "GetClipProperty", "")
    props = props if isinstance(props, dict) else {}
    file_path = props.get("File Path") or props.get("FilePath")
    record = {
        "clip_id": _safe_media_pool_item_id(clip),
        "clip_name": _safe_media_pool_item_name(clip),
        "bin_path": bin_path,
        "file_path": file_path,
        "media_id": _safe_clip_call(clip, "GetMediaId")[0],
        "duration": props.get("Duration"),
        "fps": props.get("FPS"),
        "resolution": props.get("Resolution"),
        "media_type": props.get("Type"),
        "clip_properties_error": props_error,
    }
    third_party, _ = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
    if isinstance(third_party, dict):
        mcp_third_party = {
            key: value for key, value in third_party.items()
            if str(key).startswith("davinci_resolve_mcp.")
        }
        if mcp_third_party:
            record["third_party_metadata"] = mcp_third_party
        report_path = third_party.get("davinci_resolve_mcp.analysis_report_path")
        if report_path:
            record["analysis_report_path"] = report_path
        signature = third_party.get("davinci_resolve_mcp.analysis_signature")
        if signature:
            record["published_analysis_signature"] = signature
        published_at = third_party.get("davinci_resolve_mcp.published_at")
        if published_at:
            record["published_analysis_at"] = published_at
    metadata, _ = _safe_clip_call(clip, "GetMetadata", "")
    if isinstance(metadata, dict):
        fields_with_analysis = []
        for field in ("Description", "Comments", "Keywords", "Keyword", "People"):
            value = metadata.get(field)
            if isinstance(value, (list, tuple, set)):
                text = "\n".join(str(item) for item in value)
            else:
                text = str(value or "")
            if "[DaVinci Resolve MCP Analysis]" in text or "davinci_resolve_mcp." in text:
                fields_with_analysis.append(field)
        if fields_with_analysis:
            record["analysis_metadata_present"] = True
            record["analysis_metadata_fields"] = fields_with_analysis
    provenance = {}
    if record.get("analysis_report_path"):
        provenance["analysis_report_path"] = record["analysis_report_path"]
    if record.get("published_analysis_signature"):
        provenance["analysis_signature"] = record["published_analysis_signature"]
    if record.get("published_analysis_at"):
        provenance["published_at"] = record["published_analysis_at"]
    if record.get("analysis_metadata_present"):
        provenance["standard_metadata_fields"] = record.get("analysis_metadata_fields", [])
    if record.get("third_party_metadata"):
        provenance["third_party_keys"] = sorted(record["third_party_metadata"].keys())
    if provenance:
        record["analysis_provenance"] = provenance
    return record


_MEDIA_ANALYSIS_CONTAINER_TYPE_PARTS = (
    "adjustment",
    "compound",
    "fusion",
    "generator",
    "multicam",
    "multi cam",
    "sequence",
    "subclip",
    "sub clip",
    "timeline",
    "title",
)


def _media_analysis_record_analyzable(record: Dict[str, Any]) -> Tuple[bool, str]:
    media_type = str(record.get("media_type") or "").strip().lower()
    for marker in _MEDIA_ANALYSIS_CONTAINER_TYPE_PARTS:
        if marker in media_type:
            return False, f"Resolve {record.get('media_type') or 'container'} item"
    file_path = record.get("file_path")
    if not file_path:
        return False, "No source file path exposed"
    extension = os.path.splitext(str(file_path))[1].lower()
    if extension not in MEDIA_EXTENSIONS:
        return False, f"Unsupported extension: {extension or 'none'}"
    if not os.path.isfile(str(file_path)):
        return False, "Source file missing"
    return True, "Online source media"


def _media_analysis_folder_records(folder, bin_path: str = "Master", recursive: bool = True) -> Tuple[List[Dict[str, Any]], List[str]]:
    records: List[Dict[str, Any]] = []
    warnings: List[str] = []
    if not folder:
        return records, ["Folder unavailable"]

    try:
        clips = folder.GetClipList() or []
    except Exception as exc:
        return records, [f"GetClipList failed for {bin_path}: {exc}"]
    for clip in clips:
        record = _media_analysis_clip_record(clip, bin_path)
        if not record:
            continue
        if not record.get("file_path"):
            warnings.append(f"Skipping clip without file path: {record.get('clip_name')}")
            continue
        records.append(record)

    if recursive:
        try:
            subfolders = folder.GetSubFolderList() or []
        except Exception as exc:
            warnings.append(f"GetSubFolderList failed for {bin_path}: {exc}")
            subfolders = []
        for sub in subfolders:
            try:
                sub_name = sub.GetName()
            except Exception:
                sub_name = "Unnamed"
            child_records, child_warnings = _media_analysis_folder_records(
                sub,
                f"{bin_path}/{sub_name}",
                recursive=True,
            )
            records.extend(child_records)
            warnings.extend(child_warnings)

    return records, warnings


def _media_analysis_dedupe_records(records: List[Dict[str, Any]], include_duplicates: bool = False) -> Tuple[List[Dict[str, Any]], int]:
    if include_duplicates:
        return records, 0
    seen = set()
    deduped = []
    duplicate_count = 0
    for record in records:
        key = record.get("file_path") or record.get("media_id") or record.get("clip_id")
        if key in seen:
            duplicate_count += 1
            continue
        seen.add(key)
        deduped.append(record)
    return deduped, duplicate_count


def _media_analysis_sequence_track_types(raw: Any) -> List[str]:
    if raw in (None, "", []):
        return ["video", "audio"]
    if isinstance(raw, str):
        values = re.split(r"[\s,]+", raw.strip())
    elif isinstance(raw, list):
        values = [str(value).strip() for value in raw]
    else:
        values = [str(raw).strip()]
    out: List[str] = []
    for value in values:
        lower = value.lower()
        if lower in {"all", "*"}:
            return ["video", "audio", "subtitle"]
        if lower in {"video", "audio", "subtitle"} and lower not in out:
            out.append(lower)
    return out or ["video", "audio"]


def _media_analysis_timeline_records(project, target: Dict[str, Any], p: Dict[str, Any]) -> Tuple[List[Dict[str, Any]], Dict[str, Any], List[str], Optional[Dict[str, Any]]]:
    warnings: List[str] = []
    if project is None:
        return [], {}, warnings, _err("Resolve project is required for sequence/timeline targets")

    timeline_index = target.get("timeline_index") or target.get("timelineIndex") or p.get("timeline_index") or p.get("timelineIndex")
    if timeline_index not in (None, ""):
        try:
            tl = project.GetTimelineByIndex(int(timeline_index))
        except Exception as exc:
            return [], {}, warnings, _err(f"GetTimelineByIndex failed: {exc}")
    else:
        try:
            tl = project.GetCurrentTimeline()
        except Exception as exc:
            return [], {}, warnings, _err(f"GetCurrentTimeline failed: {exc}")
    if not tl:
        return [], {}, warnings, _err("No current timeline for sequence analysis")

    track_types = _media_analysis_sequence_track_types(
        target.get("track_types") or target.get("trackTypes") or p.get("track_types") or p.get("trackTypes")
    )
    records_by_key: Dict[str, Dict[str, Any]] = {}
    occurrence_count = 0
    for track_type in track_types:
        try:
            track_count = int(tl.GetTrackCount(track_type) or 0)
        except Exception as exc:
            warnings.append(f"GetTrackCount failed for {track_type}: {exc}")
            continue
        for track_index in range(1, track_count + 1):
            try:
                items = tl.GetItemListInTrack(track_type, track_index) or []
            except Exception as exc:
                warnings.append(f"GetItemListInTrack failed for {track_type} {track_index}: {exc}")
                continue
            for item_index, item in enumerate(items):
                occurrence_count += 1
                media_pool_item = _timeline_item_media_pool_item(item)
                summary = _timeline_item_summary(item, track_info=(track_type, track_index)) or {}
                summary["item_index"] = item_index
                if not media_pool_item:
                    warnings.append(f"Skipping timeline item without Media Pool source: {summary.get('name') or summary.get('timeline_item_id')}")
                    continue
                record = _media_analysis_clip_record(media_pool_item)
                if not record:
                    continue
                if not record.get("file_path"):
                    warnings.append(f"Skipping timeline source without file path: {record.get('clip_name')}")
                    continue
                key = str(record.get("file_path") or record.get("media_id") or record.get("clip_id"))
                if key not in records_by_key:
                    record["timeline_occurrences"] = []
                    records_by_key[key] = record
                records_by_key[key].setdefault("timeline_occurrences", []).append(summary)

    timeline_info = {
        "name": None,
        "id": None,
        "track_types": track_types,
        "occurrence_count": occurrence_count,
        "asset_count": len(records_by_key),
    }
    try:
        timeline_info["name"] = tl.GetName()
    except Exception:
        pass
    try:
        timeline_info["id"] = tl.GetUniqueId()
    except Exception:
        pass
    return list(records_by_key.values()), timeline_info, warnings, None


def _media_analysis_bool(value: Any, default: bool = False) -> bool:
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        return value.strip().lower() in {"1", "true", "yes", "y", "on"}
    return bool(value)


def _media_analysis_target_dict(raw_target: Any, p: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    p = p or {}
    if raw_target is None:
        return {}
    if isinstance(raw_target, dict):
        return dict(raw_target)
    if isinstance(raw_target, str):
        value = raw_target.strip()
        if not value:
            return {}
        lower = value.lower()
        if lower in {"project", "all", "all_media", "all media"}:
            return {"type": "project", "recursive": True}
        if lower in {"timeline", "sequence", "current_timeline", "current timeline", "current_sequence", "current sequence"}:
            return {"type": "sequence"}
        if lower in {"selected", "selected_clip", "selected clip", "current", "current clip"}:
            return {"type": "clip", "selected": True}
        if lower.startswith("bin:"):
            path = value.split(":", 1)[1].strip() or "Master"
            return {"type": "bin", "path": path, "recursive": True}
        if lower in {"bin", "folder"}:
            return {
                "type": "bin",
                "path": p.get("bin_path") or p.get("path") or "Master",
                "recursive": True,
            }
        if lower in {"clip", "clips", "file"}:
            return {"type": lower}
        expanded = os.path.expanduser(value)
        if os.path.isabs(expanded):
            return {"type": "file", "path": expanded}
        return {
            "_invalid_target": (
                "Unsupported media_analysis target string. Use 'project', "
                "'selected', 'timeline', 'sequence', 'bin:<path>', or an absolute file path."
            )
        }
    return {"_invalid_target": f"target must be an object or string, got {type(raw_target).__name__}"}


def _media_analysis_extract_json_text(text: str) -> Tuple[Optional[Dict[str, Any]], Optional[str]]:
    raw = (text or "").strip()
    if raw.startswith("```"):
        raw = re.sub(r"^```(?:json)?\s*", "", raw, flags=re.IGNORECASE)
        raw = re.sub(r"\s*```$", "", raw)
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        start = raw.find("{")
        end = raw.rfind("}")
        if start < 0 or end <= start:
            return None, "Sampling response did not contain a JSON object"
        try:
            payload = json.loads(raw[start:end + 1])
        except json.JSONDecodeError as exc:
            return None, f"Sampling response JSON parse failed: {exc}"
    if not isinstance(payload, dict):
        return None, "Sampling response JSON must be an object"
    return payload, None


def _media_analysis_capabilities_for_request(ctx: Optional[Context]) -> Dict[str, Any]:
    """Capabilities report shaped for the active MCP request.

    Vision uses host_chat_paths: the server emits a deferred payload with
    absolute frame paths and the host chat completes the analysis via
    media_analysis(action="commit_vision"). No sampling/createMessage required.
    """
    caps = detect_media_analysis_capabilities()
    vision = caps.setdefault("vision", {})
    prefs = _media_analysis_effective_preferences()
    default_on = prefs.get("vision_default") == "on"
    configured_provider = vision.get("provider") or HOST_CHAT_PATHS_PROVIDER
    vision["enabled_by_default"] = default_on
    vision["default_provider"] = HOST_CHAT_PATHS_PROVIDER
    vision["provider"] = configured_provider
    vision["available"] = True
    vision["availability"] = "ready" if configured_provider in HOST_CHAT_VISION_PROVIDERS or configured_provider in {"mock", "local_mock"} else "configured_provider"
    vision["host_chat_paths"] = {
        "available": True,
        "provider": HOST_CHAT_PATHS_PROVIDER,
        "requires": "MCP host chat able to read local image files (e.g. Claude Code Read tool, Claude Desktop image input)",
        "commit_action": {"tool": "media_analysis", "action": "commit_vision"},
        "schema_reference": VISION_SCHEMA_REFERENCE,
    }
    vision["note"] = (
        "Vision is enabled by default through host_chat_paths. Analyze actions "
        "return absolute frame paths in a deferred payload; the host chat reads "
        "them as images, produces JSON per the included schema, and calls "
        "media_analysis(action='commit_vision', ...) to merge and publish. "
        "Works with any MCP client whose chat model is vision-capable."
    )
    return caps


DEFAULT_TIMELINE_MARKER_REVIEW_PROMPT = """Return only strict JSON for Resolve marker/contact-sheet review.

Read the contact-sheet image at image_path as a local image, then check whether
marker names/notes match what the rendered Resolve frames actually show. Be
precise, editorial, and source-safe.

Use this schema:
{
  "success": true,
  "provider": "host_chat_paths",
  "timeline_summary": "Concise editorial read of the marker frames.",
  "marker_checks": [
    {
      "label": "Contact-sheet label or timecode.",
      "matches_marker_intent": "yes|no|unclear",
      "visible_evidence": "What the frame shows.",
      "recommended_action": "keep|rename_marker|move_marker|review_cut|ignore"
    }
  ],
  "editorial_risks": [],
  "next_actions": [],
  "confidence": "low|medium|high"
}
Do not include markdown fences, prose outside JSON, or keys outside this schema."""


def _media_analysis_host_chat_image_review_payload(
    image_path: str,
    metadata: Dict[str, Any],
    vision: Dict[str, Any],
) -> Dict[str, Any]:
    """Return a deferred host_chat_paths payload pointing at an image to review.

    Unlike clip analysis, marker review writes nothing back to Resolve, so there
    is no commit step — the host chat can read the image and answer inline.
    """
    if not image_path or not os.path.isfile(image_path):
        return {
            "success": False,
            "status": "skipped",
            "provider": HOST_CHAT_PATHS_PROVIDER,
            "reason": f"Review image not found: {image_path}",
        }
    return {
        "success": True,
        "status": "pending_host_analysis",
        "provider": HOST_CHAT_PATHS_PROVIDER,
        "image_path": os.path.realpath(os.path.abspath(image_path)),
        "metadata": metadata,
        "prompt": str(vision.get("prompt") or DEFAULT_TIMELINE_MARKER_REVIEW_PROMPT),
        "instructions": (
            "Read image_path as a local image using your client's image-reading "
            "capability. Produce a single JSON object matching the structure in "
            "prompt and return it to the user inline. No follow-up tool call is "
            "required — marker review does not persist to Resolve."
        ),
    }


def _media_analysis_records_from_target(mp, p: Dict[str, Any], project=None) -> Tuple[Optional[List[Dict[str, Any]]], Dict[str, Any], List[str], Optional[Dict[str, Any]]]:
    target = _media_analysis_target_dict(p.get("target"), p)
    if target.get("_invalid_target"):
        return None, target, [], _err(target["_invalid_target"])
    target_type = str(target.get("type") or p.get("target_type") or "clip").strip().lower()
    warnings: List[str] = []

    if target_type == "file":
        file_path = target.get("path") or p.get("path") or p.get("file_path") or p.get("filePath")
        if not file_path:
            return None, target, warnings, _err("file target requires path or file_path")
        file_path = os.path.realpath(os.path.abspath(os.path.expanduser(str(file_path))))
        if not os.path.isfile(file_path):
            return None, target, warnings, _err(f"Media file not found: {file_path}")
        target.update({"type": "file", "path": file_path})
        return ([{
            "clip_id": None,
            "clip_name": os.path.basename(file_path),
            "bin_path": None,
            "file_path": file_path,
            "media_id": None,
            "duration": None,
            "fps": None,
            "resolution": None,
            "media_type": "file",
        }], target, warnings, None)

    if target_type in {"sequence", "timeline", "current_timeline", "current_sequence"}:
        records, timeline_info, timeline_warnings, timeline_err = _media_analysis_timeline_records(project, target, p)
        warnings.extend(timeline_warnings)
        if timeline_err:
            return None, target, warnings, timeline_err
        target.update({"type": "sequence", "timeline": timeline_info})
    elif mp is None:
        return None, target, warnings, _err("Resolve Media Pool is required for clip, bin, project, and sequence targets")

    elif target_type == "clip":
        clip_id = target.get("clip_id") or p.get("clip_id")
        selected = bool(target.get("selected") or p.get("selected"))
        clips = []
        if selected:
            try:
                clips = mp.GetSelectedClips() or []
            except Exception as exc:
                return None, target, warnings, _err(f"GetSelectedClips failed: {exc}")
            if not clips:
                return None, target, warnings, _err("No Media Pool clips are selected")
        else:
            if not clip_id:
                return None, target, warnings, _err("clip target requires clip_id or selected=true")
            clip = _find_clip(mp.GetRootFolder(), clip_id)
            if not clip:
                return None, target, warnings, _err(f"Clip not found: {clip_id}")
            clips = [clip]
        records = []
        for clip in clips:
            record = _media_analysis_clip_record(clip)
            if record and record.get("file_path"):
                records.append(record)
            elif record:
                warnings.append(f"Skipping clip without file path: {record.get('clip_name')}")
        target.update({"type": "clip", "selected": selected, "clip_id": clip_id})
    elif target_type == "clips":
        raw_ids = target.get("clip_ids") or target.get("clipIds") or p.get("clip_ids") or p.get("clipIds") or p.get("ids")
        if isinstance(raw_ids, str):
            clip_ids = [item.strip() for item in raw_ids.split(",") if item.strip()]
        elif isinstance(raw_ids, list):
            clip_ids = [str(item).strip() for item in raw_ids if str(item).strip()]
        else:
            clip_ids = []
        if not clip_ids:
            return None, target, warnings, _err("clips target requires clip_ids")
        root_folder = mp.GetRootFolder()
        records = []
        missing_ids = []
        skipped = []
        for clip_id in clip_ids:
            clip = _find_clip(root_folder, clip_id)
            if not clip:
                missing_ids.append(clip_id)
                continue
            record = _media_analysis_clip_record(clip)
            if not record:
                skipped.append({"clip_id": clip_id, "reason": "clip record unavailable"})
                continue
            analyzable, reason = _media_analysis_record_analyzable(record)
            if not analyzable:
                skipped.append({"clip_id": clip_id, "clip_name": record.get("clip_name"), "reason": reason})
                continue
            records.append(record)
        if missing_ids:
            return None, target, warnings, _err(f"Clip(s) not found: {', '.join(missing_ids)}")
        if skipped:
            warnings.extend([
                f"Skipping non-analyzable clip {item.get('clip_name') or item.get('clip_id')}: {item.get('reason')}"
                for item in skipped
            ])
        target.update({"type": "clips", "clip_ids": clip_ids, "skipped": skipped})
    elif target_type == "bin":
        path = target.get("path") or p.get("bin_path") or p.get("path") or "Master"
        recursive = bool(target.get("recursive", p.get("recursive", True)))
        folder = _navigate_folder(mp, path)
        if not folder:
            return None, target, warnings, _err(f"Folder not found: {path}")
        records, folder_warnings = _media_analysis_folder_records(folder, path if path else "Master", recursive)
        warnings.extend(folder_warnings)
        target.update({"type": "bin", "path": path, "recursive": recursive})
    elif target_type == "project":
        recursive = bool(target.get("recursive", True))
        records, folder_warnings = _media_analysis_folder_records(mp.GetRootFolder(), "Master", recursive=recursive)
        warnings.extend(folder_warnings)
        target.update({"type": "project", "recursive": recursive})
    else:
        return None, target, warnings, _err("target.type must be one of file, clip, clips, bin, project, sequence, timeline")

    records, duplicate_count = _media_analysis_dedupe_records(records, bool(p.get("include_duplicates", target.get("include_duplicates", False))))
    if duplicate_count:
        warnings.append(f"Deduped {duplicate_count} repeated source media reference(s)")
    if not records:
        return None, target, warnings, _err("No analyzable media with file paths found for target")
    return records, target, warnings, None


def _media_analysis_sync_event_records(proj, p: Dict[str, Any]):
    paths = p.get("paths") or p.get("file_paths") or p.get("filePaths")
    warnings: List[str] = []
    normalized_target: Dict[str, Any] = {"type": "paths"} if paths else _media_analysis_target_dict(p.get("target"), p)
    if paths:
        if isinstance(paths, str):
            paths = [paths]
        if not isinstance(paths, list) or not paths:
            return None, normalized_target, warnings, _err("paths must be a non-empty string or list")
        records = []
        for index, path in enumerate(paths):
            expanded = os.path.realpath(os.path.abspath(os.path.expanduser(str(path))))
            if not os.path.isfile(expanded):
                return None, normalized_target, warnings, _err(f"Media file not found: {expanded}")
            records.append({
                "clip_id": None,
                "clip_name": os.path.basename(expanded),
                "bin_path": None,
                "file_path": expanded,
                "media_id": None,
                "duration": None,
                "fps": p.get("fps"),
                "resolution": None,
                "media_type": "file",
                "source_index": index,
            })
        normalized_target["paths"] = [record["file_path"] for record in records]
        return records, normalized_target, warnings, None

    if not p.get("target") and (p.get("path") or p.get("file_path") or p.get("filePath")):
        p["target"] = {
            "type": "file",
            "path": p.get("path") or p.get("file_path") or p.get("filePath"),
        }
    mp = proj.GetMediaPool()
    if not mp:
        return None, normalized_target, warnings, _err("Failed to get MediaPool")
    records, normalized_target, warnings, target_err = _media_analysis_records_from_target(mp, p, project=proj)
    return records, normalized_target, warnings, target_err


def _media_analysis_confirmed(p: Dict[str, Any]) -> bool:
    return _media_analysis_bool(
        p.get("confirm", p.get("confirmed", p.get("apply", p.get("write_markers")))),
        False,
    )


def _media_analysis_publish_confirmed(p: Dict[str, Any]) -> bool:
    explicit = _first_param(p, "confirm", "confirmed", "apply")
    if explicit is not None:
        return _media_analysis_bool(explicit, False)
    return not _media_analysis_effective_preferences().get("ask_before_metadata_publish")


