_METADATA_FIELD_PROPERTY_ALIASES = {
    "Keywords": ("Keyword",),
    "Roll/Card": ("Roll Card #",),
}

_METADATA_FIELD_WRITE_ALIASES = {
    "Keyword": "Keywords",
    "Roll/Card": "Roll Card #",
}


def _metadata_clip_property_key_for_field(field: str, properties: Dict[str, Any]) -> Optional[str]:
    if field in properties:
        return field
    for alias in _METADATA_FIELD_PROPERTY_ALIASES.get(field, ()):
        if alias in properties:
            return alias
    return None


def _metadata_write_field_for_field(field: str) -> str:
    return _METADATA_FIELD_WRITE_ALIASES.get(field, field)


def _metadata_panel_group_for_field(field: str) -> str:
    for group, fields in _METADATA_PANEL_GROUP_FIELD_HINTS.items():
        if field in fields:
            return group
    if re.fullmatch(r"Track\s+\d+", field or ""):
        return "Audio Tracks"
    if field.startswith("Audio "):
        return "Audio"
    if field.startswith("Camera "):
        return "Camera"
    if field.startswith("VFX ") or field.startswith("S3D ") or field.startswith("3D "):
        return "Stereo3D & VFX"
    if field.endswith(" Reviewed"):
        return "Reviewed By"
    return "Unclassified"


def _metadata_panel_group_inventory(fields: List[str]) -> List[Dict[str, Any]]:
    grouped: Dict[str, List[str]] = {"All Groups": list(fields)}
    for field in fields:
        grouped.setdefault(_metadata_panel_group_for_field(field), []).append(field)

    ordered_names = list(_METADATA_PANEL_GROUP_ORDER)
    if grouped.get("Unclassified"):
        ordered_names.append("Unclassified")
    return [
        {"name": name, "field_count": len(grouped.get(name, [])), "fields": grouped.get(name, [])}
        for name in ordered_names
        if name == "All Groups" or grouped.get(name)
    ]


def _media_analysis_metadata_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, (list, tuple, set)):
        return ", ".join(str(item).strip() for item in value if str(item).strip())
    return str(value).strip()


def _media_analysis_as_list(value: Any) -> List[str]:
    if value is None:
        return []
    if isinstance(value, (list, tuple, set)):
        raw_items = value
    else:
        raw_items = re.split(r"[,;\n]+", str(value))
    out: List[str] = []
    seen = set()
    for item in raw_items:
        text = str(item).strip()
        if not text:
            continue
        key = text.casefold()
        if key in seen:
            continue
        seen.add(key)
        out.append(text)
    return out


def _media_analysis_merge_lists(existing: Any, proposed: Any) -> Tuple[str, List[str]]:
    existing_items = _media_analysis_as_list(existing)
    merged = list(existing_items)
    seen = {item.casefold() for item in merged}
    added = []
    for item in _media_analysis_as_list(proposed):
        key = item.casefold()
        if key in seen:
            continue
        seen.add(key)
        merged.append(item)
        added.append(item)
    return ", ".join(merged), added


def _media_analysis_replace_owned_block(existing: Any, body: Any) -> str:
    existing_text = _media_analysis_metadata_text(existing)
    body_text = _media_analysis_metadata_text(body)
    block = f"{_MCP_METADATA_BLOCK_START}\n{body_text}\n{_MCP_METADATA_BLOCK_END}"
    pattern = (
        re.escape(_MCP_METADATA_BLOCK_START)
        + r".*?"
        + re.escape(_MCP_METADATA_BLOCK_END)
    )
    if re.search(pattern, existing_text, flags=re.DOTALL):
        return re.sub(pattern, block, existing_text, flags=re.DOTALL).strip()
    return f"{existing_text}\n\n{block}".strip() if existing_text else block


def _media_analysis_confidence_rank(value: Any) -> int:
    raw = str(value or "").strip().lower()
    return {"none": 0, "low": 1, "medium": 2, "high": 3}.get(raw, 0)


def _media_analysis_pick_nested(payload: Dict[str, Any], *paths: Tuple[str, ...]) -> Any:
    for path in paths:
        current: Any = payload
        for key in path:
            if not isinstance(current, dict) or key not in current:
                current = None
                break
            current = current[key]
        if current not in (None, "", [], {}):
            return current
    return None


def _media_analysis_best_sync_event(detection: Optional[Dict[str, Any]], clip_id: Optional[str]) -> Optional[Dict[str, Any]]:
    if not isinstance(detection, dict):
        return None
    best = None
    best_score = -1.0
    for file_result in detection.get("files") or []:
        if clip_id and file_result.get("clip_id") not in (None, clip_id):
            continue
        for event in file_result.get("events") or []:
            if event.get("type") != "slate_clap":
                continue
            try:
                score = float(event.get("confidence") or 0)
            except (TypeError, ValueError):
                score = 0.0
            if score > best_score:
                best_score = score
                best = dict(event)
                best["clip_id"] = file_result.get("clip_id")
                best["clip_name"] = file_result.get("clip_name")
    return best


def _media_analysis_visual_analysis_succeeded(report: Dict[str, Any]) -> bool:
    visual = report.get("visual") if isinstance(report.get("visual"), dict) else {}
    if str(visual.get("status") or "").strip().lower() in {"skipped", "disabled"}:
        return False
    has_visual_content = bool(
        visual.get("clip_summary")
        or visual.get("content")
        or visual.get("editing_notes")
        or visual.get("analysis_keyframes")
        or visual.get("slate")
    )
    if visual.get("success") is False and not has_visual_content:
        return False
    return has_visual_content


def _media_analysis_slate_visible(source: Any) -> bool:
    if not isinstance(source, dict):
        return False
    value = _first_param(
        source,
        "slate_visible",
        "slateVisible",
        "visible",
        "is_slate",
        "isSlate",
        "has_slate",
        "hasSlate",
    )
    if value is None:
        return False
    return _media_analysis_bool(value, False)


def _media_analysis_slate_visual_confirmed(
    report: Dict[str, Any],
    slate_review: Optional[Dict[str, Any]] = None,
) -> bool:
    sources: List[Any] = []
    if isinstance(slate_review, dict):
        sources.extend([
            slate_review,
            slate_review.get("slate") if isinstance(slate_review.get("slate"), dict) else {},
        ])
    visual = report.get("visual") if isinstance(report.get("visual"), dict) else {}
    sources.extend([
        report.get("slate") if isinstance(report.get("slate"), dict) else {},
        visual.get("slate") if isinstance(visual.get("slate"), dict) else {},
    ])
    return any(_media_analysis_slate_visible(source) for source in sources)


def _media_analysis_confirmed_slate_sources(
    report: Dict[str, Any],
    slate_review: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    sources: List[Dict[str, Any]] = []

    def add_confirmed(container: Any) -> None:
        if not isinstance(container, dict):
            return
        nested_slate = container.get("slate") if isinstance(container.get("slate"), dict) else {}
        if not (_media_analysis_slate_visible(container) or _media_analysis_slate_visible(nested_slate)):
            return
        sources.append(container)
        fields = container.get("fields") if isinstance(container.get("fields"), dict) else {}
        if fields:
            sources.append(fields)
        if nested_slate:
            sources.append(nested_slate)

    add_confirmed(slate_review)
    add_confirmed(report.get("slate") if isinstance(report.get("slate"), dict) else {})
    visual = report.get("visual") if isinstance(report.get("visual"), dict) else {}
    add_confirmed(visual.get("slate") if isinstance(visual.get("slate"), dict) else {})
    return sources


def _media_analysis_collect_slate_fields(report: Dict[str, Any], slate_review: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    slate_sources = _media_analysis_confirmed_slate_sources(report, slate_review)

    field_aliases = {
        "Scene": ("scene", "scene_number", "sceneNumber"),
        "Shot": ("shot", "shot_number", "shotNumber"),
        "Take": ("take", "take_number", "takeNumber"),
        "Camera #": ("camera", "camera_id", "cameraId", "camera_number", "cameraNumber"),
        "Roll/Card": ("roll", "reel", "card", "roll_card", "rollCard"),
    }
    collected: Dict[str, Any] = {}
    confidence = None
    for source in slate_sources:
        confidence = _media_analysis_pick_nested(source, ("confidence", "overall"), ("confidence",))
        if confidence:
            break
    collected["_confidence"] = confidence or "unknown"
    for resolve_field, aliases in field_aliases.items():
        for source in slate_sources:
            if not isinstance(source, dict):
                continue
            for alias in aliases:
                if source.get(alias) not in (None, ""):
                    collected[resolve_field] = source.get(alias)
                    break
            if resolve_field in collected:
                break
    visible_text = None
    for source in slate_sources:
        visible_text = _media_analysis_pick_nested(source, ("visible_text",), ("visibleText",))
        if visible_text:
            break
    if visible_text:
        collected["_visible_text"] = visible_text
    return collected


def _media_analysis_report_metadata_candidates(
    report: Dict[str, Any],
    *,
    detection: Optional[Dict[str, Any]] = None,
    slate_review: Optional[Dict[str, Any]] = None,
    fields: Optional[List[str]] = None,
    require_visual_description: bool = False,
    require_visual_slate: bool = True,
) -> Dict[str, Any]:
    requested_fields = fields or list(_MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
    visual = report.get("visual") if isinstance(report.get("visual"), dict) else {}
    content = visual.get("content") if isinstance(visual.get("content"), dict) else {}
    classification = visual.get("editorial_classification") if isinstance(visual.get("editorial_classification"), dict) else {}
    editing_notes = visual.get("editing_notes") if isinstance(visual.get("editing_notes"), dict) else {}
    shot_style = visual.get("shot_and_style") if isinstance(visual.get("shot_and_style"), dict) else {}
    visual_succeeded = _media_analysis_visual_analysis_succeeded(report)

    summary = visual.get("clip_summary") if visual_succeeded else None
    if not summary and not require_visual_description:
        summary = (
            report.get("summary")
            or (report.get("clip") or {}).get("clip_name")
            or "Analyzed media clip"
        )
    comments = [f"Summary: {summary}"] if summary else []
    primary_use = classification.get("primary_use")
    select_potential = classification.get("select_potential")
    if primary_use and primary_use != "unknown":
        use_line = f"Editorial use: {primary_use}"
        if select_potential and select_potential != "unknown":
            use_line += f" ({select_potential} select potential)"
        comments.append(use_line)
    if classification.get("reason"):
        comments.append(f"Reason: {classification['reason']}")
    best_moments = editing_notes.get("best_moments") or []
    if best_moments:
        comments.append("Best moments: " + "; ".join(_media_analysis_as_list(best_moments)[:4]))
    qc_flags = list(report.get("technical_warnings") or []) + list(editing_notes.get("qc_flags") or [])
    if qc_flags:
        comments.append("Warnings: " + "; ".join(_media_analysis_as_list(qc_flags)[:6]))
    visible_text = content.get("visible_text") or []
    if visible_text:
        comments.append("Visible text: " + "; ".join(_media_analysis_as_list(visible_text)[:5]))
    sync_event = _media_analysis_best_sync_event(detection, (report.get("clip") or {}).get("clip_id"))
    slate_visual_confirmed = _media_analysis_slate_visual_confirmed(report, slate_review)
    if sync_event and (slate_visual_confirmed or not require_visual_slate):
        slate_label = "Confirmed slate clap" if slate_visual_confirmed else "Likely slate clap"
        comments.append(
            f"{slate_label}: "
            f"{sync_event.get('time_seconds')}s"
            + (f", frame {sync_event.get('frame')}" if sync_event.get("frame") is not None else "")
            + (f", confidence {sync_event.get('confidence')}" if sync_event.get("confidence") is not None else "")
        )

    slate = _media_analysis_collect_slate_fields(report, slate_review)
    if any(key in slate for key in ("Scene", "Shot", "Take", "Camera #")):
        slate_bits = [
            f"{key}: {slate[key]}"
            for key in ("Scene", "Shot", "Take", "Camera #", "Roll/Card")
            if slate.get(key) not in (None, "")
        ]
        comments.append("Slate read: " + ", ".join(slate_bits))
    if slate.get("_visible_text"):
        comments.append("Slate visible text: " + "; ".join(_media_analysis_as_list(slate["_visible_text"])[:5]))

    keywords: List[Any] = []
    keywords.extend(editing_notes.get("search_tags") or [])
    if primary_use and primary_use != "unknown":
        keywords.append(primary_use)
    for key in ("actions", "objects", "locations", "notable_audio_context"):
        keywords.extend(_media_analysis_as_list(content.get(key)))
    keywords.extend(_media_analysis_as_list(shot_style.get("shot_sizes")))
    keywords.extend(_media_analysis_as_list(shot_style.get("camera_motion")))
    if sync_event and (slate_visual_confirmed or not require_visual_slate):
        keywords.append("slate clap")

    people: List[Any] = []
    for key in ("people", "people_names", "named_people", "identified_people"):
        people.extend(_media_analysis_as_list(content.get(key)))
    people.extend(_media_analysis_as_list(visual.get("people")))

    candidates: Dict[str, Any] = {}
    if "Description" in requested_fields and summary:
        candidates["Description"] = _media_analysis_metadata_text(summary)
    if "Comments" in requested_fields and comments:
        candidates["Comments"] = "\n".join(_media_analysis_metadata_text(line) for line in comments if _media_analysis_metadata_text(line))
    keyword_field = "Keywords" if "Keywords" in requested_fields else ("Keyword" if "Keyword" in requested_fields else None)
    if keyword_field:
        candidates[keyword_field] = _media_analysis_as_list(keywords)
    if "People" in requested_fields:
        candidates["People"] = _media_analysis_as_list(people)
    slate_confidence = slate.get("_confidence")
    high_confidence_slate = _media_analysis_confidence_rank(slate_confidence) >= 3
    for field in ("Scene", "Shot", "Take", "Camera #", "Roll/Card"):
        target_field = field
        if field == "Roll/Card" and field not in requested_fields and "Roll Card #" in requested_fields:
            target_field = "Roll Card #"
        if target_field in requested_fields and slate.get(field) not in (None, ""):
            candidates[target_field] = _media_analysis_metadata_text(slate[field]) if high_confidence_slate else ""
    return {
        "fields": candidates,
        "evidence": {
            "summary": summary,
            "sync_event": sync_event,
            "visual_analysis_required": bool(require_visual_description),
            "visual_analysis_succeeded": visual_succeeded,
            "slate_visual_required": bool(require_visual_slate),
            "slate_visual_confirmed": slate_visual_confirmed,
            "slate": slate,
            "slate_confidence": slate_confidence,
        },
    }


def _media_analysis_merge_metadata_field(field: str, existing: Any, proposed: Any, p: Dict[str, Any]) -> Dict[str, Any]:
    proposed_text = _media_analysis_metadata_text(proposed)
    existing_text = _media_analysis_metadata_text(existing)
    overwrite = _media_analysis_bool(p.get("overwrite"), False)
    merge_policy = str(p.get("merge_policy") or p.get("mergePolicy") or "append_relevant").strip().lower()

    if field in _MEDIA_ANALYSIS_LIST_FIELDS:
        merged, added = _media_analysis_merge_lists(existing, proposed)
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed,
            "value": merged,
            "changed": bool(added),
            "reason": "deduped_append" if added else "no_new_values",
            "added": added,
        }

    if not proposed_text:
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": existing_text,
            "changed": False,
            "reason": "no_confident_proposal",
        }

    if overwrite:
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": proposed_text,
            "changed": proposed_text != existing_text,
            "reason": "overwrite",
        }

    if merge_policy in {"fill_empty", "empty_only"} and existing_text:
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": existing_text,
            "changed": False,
            "reason": "preserved_existing_fill_empty_policy",
        }

    if field in _MEDIA_ANALYSIS_FILL_EMPTY_FIELDS:
        if existing_text:
            return {
                "field": field,
                "existing": existing_text,
                "proposed": proposed_text,
                "value": existing_text,
                "changed": False,
                "reason": "preserved_existing_fill_empty_field",
            }
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": proposed_text,
            "changed": True,
            "reason": "filled_empty_field",
        }

    if field in {"Comments", "Description"} and (merge_policy in {"append_relevant", "append", "update_block"} or existing_text):
        merged = _media_analysis_replace_owned_block(existing_text, proposed_text)
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": merged,
            "changed": merged != existing_text,
            "reason": "updated_mcp_block",
        }

    if existing_text:
        return {
            "field": field,
            "existing": existing_text,
            "proposed": proposed_text,
            "value": existing_text,
            "changed": False,
            "reason": "preserved_existing",
        }
    return {
        "field": field,
        "existing": existing_text,
        "proposed": proposed_text,
        "value": proposed_text,
        "changed": True,
        "reason": "filled_empty_field",
    }


def _media_analysis_provenance_metadata(report: Dict[str, Any], report_path: Optional[str], changed_fields: List[str]) -> Dict[str, str]:
    signature = report.get("analysis_signature") if isinstance(report.get("analysis_signature"), dict) else {}
    payload = {
        "analysis_report_path": report_path or "",
        "analysis_signature": signature.get("signature_hash") or "",
        "analysis_version": str(report.get("analysis_version") or ""),
        "published_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        "publisher_version": VERSION,
        "changed_fields": ",".join(changed_fields),
    }
    return {
        f"{_MCP_METADATA_PROVENANCE_PREFIX}{key}": value
        for key, value in payload.items()
        if value not in (None, "")
    }


def _has_any_param(p: Dict[str, Any], *keys: str) -> bool:
    return any(key in p and p[key] is not None for key in keys)


def _media_analysis_vision_options(enabled: bool) -> Dict[str, Any]:
    options = {"enabled": bool(enabled)}
    if enabled:
        options["provider"] = HOST_CHAT_PATHS_PROVIDER
    return options


def _media_analysis_transcription_options(enabled: bool) -> Dict[str, Any]:
    options = {"enabled": bool(enabled)}
    if enabled:
        options["allow_model_download"] = True
    return options


def _media_analysis_metadata_writeback_enabled(p: Dict[str, Any]) -> bool:
    raw = _first_param(
        p,
        "publish_metadata",
        "publishMetadata",
        "write_metadata",
        "writeMetadata",
        "metadata_writeback",
        "metadataWriteback",
        "write_to_resolve",
        "writeToResolve",
    )
    if raw is None:
        return bool(_media_analysis_effective_preferences().get("metadata_writeback_default", True))
    return _media_analysis_bool(raw, True)


def _compact_clip_row_for_response(clip: Any) -> Any:
    """Build a compact per-clip row for tool-result responses (V2 P9).

    Heavy fields (visual.prompt ~9k chars, visual.frame_metadata, visual.shot_table,
    visual.frame_paths in full) are replaced with summaries. The complete payload
    remains on disk at analysis_json; consumers can read from there when needed.
    """
    if not isinstance(clip, dict):
        return clip
    record = clip.get("record") if isinstance(clip.get("record"), dict) else {}
    visual = clip.get("visual") if isinstance(clip.get("visual"), dict) else None
    out: Dict[str, Any] = {
        "success": clip.get("success"),
        "analysis_json": clip.get("analysis_json"),
        "clip_dir": clip.get("clip_dir"),
        "marker_plan_json": clip.get("marker_plan_json"),
        "vision_status": clip.get("vision_status"),
        "reused": clip.get("reused"),
        "reused_from": clip.get("reused_from"),
        "reuse_source": clip.get("reuse_source"),
        "reuse_reason": clip.get("reuse_reason"),
        "cache_status": clip.get("cache_status"),
        "cache_warnings": clip.get("cache_warnings"),
        "record": {
            k: record.get(k)
            for k in ("clip_id", "clip_name", "file_path", "duration_seconds",
                     "fps", "media_type", "resolution", "bin_path", "media_id")
            if record.get(k) is not None
        },
    }
    if "error" in clip:
        out["error"] = clip.get("error")
    if "caps_refusal" in clip:
        out["caps_refusal"] = clip.get("caps_refusal")
    if isinstance(visual, dict):
        frame_paths = visual.get("frame_paths") or []
        shot_table = visual.get("shot_table") or []
        prompt = visual.get("prompt")
        out["visual"] = {
            "status": visual.get("status"),
            "provider": visual.get("provider"),
            "schema_reference": visual.get("schema_reference"),
            "vision_token": visual.get("vision_token"),
            "frame_count": len(frame_paths),
            "frame_paths_summary": {
                "directory": (frame_paths[0].rsplit("/", 1)[0] if frame_paths else None),
                "first": frame_paths[0] if frame_paths else None,
                "last": frame_paths[-1] if frame_paths else None,
                "count": len(frame_paths),
            },
            "shot_count": len(shot_table),
            "commit_action": visual.get("commit_action"),
            "prompt_size_chars": (len(prompt) if isinstance(prompt, str) else None),
            "instructions": (
                "Full vision payload (prompt, schema, frame_paths[], frame_metadata[], shot_table[]) "
                "is on disk at analysis_json. Read it for vision pass; call media_analysis"
                "(action='commit_vision', params={clip_id, visual, vision_token}) when done. "
                "Use verbose=true on analyze to inline the full payload instead."
            ),
        }
    return out


def _compact_manifest_for_response(manifest: Any, *, verbose: bool = False) -> Any:
    """Compact manifest for tool-result return (V2 P9 — fixes 25k-token overflow).

    When verbose=False (default), heavy clip-level fields are replaced with summaries.
    The full manifest is always persisted to disk; this only affects what gets returned
    over the wire to the calling chat / agent.
    """
    if verbose or not isinstance(manifest, dict):
        return manifest
    compact = {
        k: manifest.get(k)
        for k in (
            "success", "analysis_version", "schema_version",
            "vision_pending", "vision_pending_clip_count",
            "clip_count", "successful_clip_count", "failed_clip_count",
            "caps_refusal_clip_count", "error",
            "partial_success", "completed_clip_ids", "failed_clip_ids",
            "started_at", "completed_at",
            "project_name", "project_id",
            "depth", "session_only", "session_token",
            "pending_action", "index", "analysis_registry", "reuse_summary", "memory_layer_warnings",
            "artifacts_cleaned_up", "artifact_cleanup_root",
        )
        if k in manifest
    }
    compact["clips"] = [
        _compact_clip_row_for_response(c) for c in (manifest.get("clips") or [])
    ]
    # Drop the heavy 'reports' field that session_only mode inlines. Consumers
    # who need it should call verbose=true or read analysis_json from disk.
    if isinstance(manifest.get("reports"), list):
        compact["reports_summary"] = {
            "count": len(manifest["reports"]),
            "note": "Full reports inlined only when verbose=true. Read analysis_json on disk per clip.",
        }
    return compact


def _media_analysis_missing_capabilities_response(plan: Dict[str, Any], *, action_label: str = "analysis") -> Dict[str, Any]:
    gaps = plan.get("capability_gaps") or []
    install = plan.get("install_guidance") or {}
    return {
        "success": False,
        "status": "missing_required_capabilities",
        "error": f"Cannot start {action_label} because required local analysis tools are missing.",
        "capability_gaps": gaps,
        "install_guidance": install,
        "next_step": (
            "Install or configure the missing tools, then rerun the analysis. "
            "The MCP reports guidance only and does not install packages automatically."
        ),
        "plan": plan,
    }


def _compact_metadata_publish_for_response(publish: Any, *, verbose: bool = False) -> Any:
    """Compact publish_clip_metadata response for wire return (V2 P9).

    The full response carries the analysis manifest, marker plans, evidence blocks,
    and per-field write attempts — easily 100k+ chars for a normal clip. The compact
    view keeps the success/error signal and the per-clip outcome summary, drops bulk.
    """
    if verbose or not isinstance(publish, dict):
        return publish
    compact = {
        k: publish.get(k)
        for k in (
            "success", "dry_run", "confirmation_required",
            "marker_writeback_enabled", "timed_marker_decision",
            "target", "clip_count", "changed_clip_count",
            "warnings", "setup_defaults_applied",
        )
        if k in publish
    }
    if isinstance(publish.get("timed_marker_prompt"), str) or publish.get("timed_marker_prompt") is None:
        compact["timed_marker_prompt"] = publish.get("timed_marker_prompt")
    results = publish.get("results")
    if isinstance(results, list):
        compact["results"] = [
            {
                "clip_id": (r.get("clip_id") if isinstance(r, dict) else None),
                "clip_name": (r.get("clip_name") if isinstance(r, dict) else None),
                "success": (r.get("success") if isinstance(r, dict) else None),
                "metadata_error": (r.get("metadata_error") if isinstance(r, dict) else None),
                "third_party_metadata_error": (r.get("third_party_metadata_error") if isinstance(r, dict) else None),
                "marker_writeback_enabled": (r.get("marker_writeback_enabled") if isinstance(r, dict) else None),
                "fields_written": (
                    list((r.get("metadata_writes") or {}).keys())
                    if isinstance(r, dict) and isinstance(r.get("metadata_writes"), dict)
                    else []
                ),
                "third_party_keys_written": (
                    list((r.get("third_party_metadata_writes") or {}).keys())
                    if isinstance(r, dict) and isinstance(r.get("third_party_metadata_writes"), dict)
                    else []
                ),
                "analysis_report": (r.get("analysis_report") if isinstance(r, dict) else None),
                "write_errors": (r.get("write_errors") if isinstance(r, dict) else None),
            }
            for r in results
        ]
    # Drop the heavy analysis_manifest from the publish response — caller has it
    # in the parent result['manifest'] already (also compacted).
    return compact


def _media_analysis_apply_setup_defaults(action: str, p: Dict[str, Any]) -> Dict[str, Any]:
    prefs = _media_analysis_effective_preferences()
    applied: Dict[str, Any] = {}
    out = dict(p)

    preferred_root = prefs.get("preferred_analysis_root")
    if preferred_root and not _has_any_param(out, "analysis_root", "analysisRoot"):
        out["analysis_root"] = preferred_root
        applied["preferred_analysis_root"] = preferred_root

    if not _has_any_param(out, "include_confidence_scores", "includeConfidenceScores"):
        out["include_confidence_scores"] = prefs.get("include_confidence_scores")
        applied["include_confidence_scores"] = prefs.get("include_confidence_scores")
    if not _has_any_param(out, "include_source_time_notes", "includeSourceTimeNotes"):
        out["include_source_time_notes"] = prefs.get("include_source_time_notes")
        applied["include_source_time_notes"] = prefs.get("include_source_time_notes")
    if not _has_any_param(out, "analysis_summary_style", "analysisSummaryStyle"):
        out["analysis_summary_style"] = prefs.get("analysis_summary_style")
        applied["analysis_summary_style"] = prefs.get("analysis_summary_style")
    if not _has_any_param(out, "report_format", "reportFormat"):
        out["report_format"] = prefs.get("report_format")
        applied["report_format"] = prefs.get("report_format")
    if not _has_any_param(out, "source_trust", "sourceTrust"):
        pref_trust = prefs.get("source_trust")
        if pref_trust and pref_trust != "auto":
            out["source_trust"] = pref_trust
            applied["source_trust"] = pref_trust

    if action in {"plan", "analyze_file", "analyze_clip", "analyze_bin", "analyze_project", "analyze_timeline", "analyze_sequence", "start_batch_job", "review_timeline_markers", "publish_clip_metadata"}:
        include_visuals = _first_param(out, "include_visuals", "includeVisuals")
        if isinstance(out.get("vision"), bool):
            out["vision"] = _media_analysis_vision_options(out["vision"])
            applied["vision_shorthand"] = out["vision"]["enabled"]
        elif not _has_any_param(out, "vision"):
            if include_visuals is not None:
                visuals_enabled = _media_analysis_bool(include_visuals, True)
                out["vision"] = _media_analysis_vision_options(visuals_enabled)
                applied["include_visuals"] = visuals_enabled
            else:
                vision_default = prefs.get("vision_default")
                if vision_default == "on":
                    out["vision"] = _media_analysis_vision_options(True)
                    applied["vision_default"] = vision_default
                elif vision_default in {"off", "technical_only"}:
                    out["vision"] = _media_analysis_vision_options(False)
                    applied["vision_default"] = vision_default
        include_transcription = _first_param(out, "include_transcription", "includeTranscription")
        if not _has_any_param(out, "transcription"):
            if include_transcription is not None:
                out["transcription"] = _media_analysis_transcription_options(
                    _media_analysis_bool(include_transcription, False)
                )
                applied["include_transcription"] = out["transcription"]["enabled"]
            else:
                transcription_default = prefs.get("transcription_default")
                if transcription_default in {"yes", "no"}:
                    out["transcription"] = _media_analysis_transcription_options(
                        transcription_default == "yes"
                    )
                    applied["transcription_default"] = transcription_default

    # Frame-sampling mode: resolve from explicit param > saved default > first-run
    # prompt (recommended fallback). Inject mode + tunables so the analysis engine
    # picks them up via _resolve_sampling_config; stash the decision so the entry
    # point can surface the first-run prompt.
    if action in {"plan", "analyze_file", "analyze_clip", "analyze_bin", "analyze_project", "analyze_timeline", "analyze_sequence", "start_batch_job"}:
        sampling_decision = _media_analysis_sampling_mode_decision(out)
        if not _has_any_param(out, "sampling_mode", "samplingMode", "frame_sampling_mode", "frameSamplingMode"):
            out["sampling_mode"] = sampling_decision["mode"]
            applied["sampling_mode"] = sampling_decision["mode"]
        if not _has_any_param(out, "frames_per_minute", "framesPerMinute"):
            out["frames_per_minute"] = prefs.get("sampling_frames_per_minute")
        if not _has_any_param(out, "frame_floor", "frameFloor"):
            out["frame_floor"] = prefs.get("sampling_frame_floor")
        if not _has_any_param(out, "frame_ceiling", "frameCeiling"):
            out["frame_ceiling"] = prefs.get("sampling_frame_ceiling")
        out["_sampling_mode_decision"] = sampling_decision

    if action in {"plan", "analyze_file", "analyze_clip", "analyze_bin", "analyze_project", "analyze_timeline", "analyze_sequence", "start_batch_job", "publish_clip_metadata"}:
        if not _has_any_param(
            out,
            "publish_metadata",
            "publishMetadata",
            "write_metadata",
            "writeMetadata",
            "metadata_writeback",
            "metadataWriteback",
            "write_to_resolve",
            "writeToResolve",
        ):
            out["publish_metadata"] = bool(prefs.get("metadata_writeback_default", True))
            applied["metadata_writeback_default"] = out["publish_metadata"]

        persistence = prefs.get("analysis_persistence")
        if persistence == "keep_reports":
            if not _has_any_param(out, "persist"):
                out["persist"] = True
            if not _has_any_param(out, "session_only", "sessionOnly"):
                out["session_only"] = False
            if not _has_any_param(out, "cleanup_frames", "cleanupFrames"):
                out["cleanup_frames"] = True
            applied["analysis_persistence"] = persistence
        elif persistence == "keep_artifacts":
            if not _has_any_param(out, "persist"):
                out["persist"] = True
            if not _has_any_param(out, "session_only", "sessionOnly"):
                out["session_only"] = False
            if not _has_any_param(out, "keep_artifacts", "keepArtifacts"):
                out["keep_artifacts"] = True
            if not _has_any_param(out, "cleanup_frames", "cleanupFrames"):
                out["cleanup_frames"] = False
            applied["analysis_persistence"] = persistence

    if action == "publish_clip_metadata":
        if not _has_any_param(out, "fields"):
            out["fields"] = list(prefs.get("metadata_publish_fields") or _MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
            applied["metadata_publish_fields"] = out["fields"]

        policy = prefs.get("metadata_overwrite_policy")
        if policy == "overwrite_all" and not _has_any_param(out, "overwrite"):
            out["overwrite"] = True
            applied["metadata_overwrite_policy"] = policy
        elif policy == "fill_empty" and not _has_any_param(out, "merge_policy", "mergePolicy"):
            out["merge_policy"] = "fill_empty"
            applied["metadata_overwrite_policy"] = policy
        elif policy == "overwrite_owned_blocks" and not _has_any_param(out, "merge_policy", "mergePolicy"):
            out["merge_policy"] = "update_block"
            applied["metadata_overwrite_policy"] = policy
        elif policy == "preserve_human" and not _has_any_param(out, "merge_policy", "mergePolicy"):
            out["merge_policy"] = "append_relevant"
            applied["metadata_overwrite_policy"] = policy

        if not _has_any_param(out, "slate_detection", "slateDetection"):
            slate_default = prefs.get("slate_detection_default")
            if slate_default in {"yes", "no"}:
                out["slate_detection"] = {
                    "enabled": slate_default == "yes",
                    "use_vision": slate_default == "yes" and (prefs.get("vision_default") == "on"),
                }
                applied["slate_detection_default"] = slate_default
        if not _has_any_param(out, "confirm", "confirmed", "apply") and not prefs.get("ask_before_metadata_publish"):
            out["confirm"] = True
            applied["ask_before_metadata_publish"] = False
        if not _has_any_param(out, "dry_run", "dryRun") and not prefs.get("dry_run_first_default") and _media_analysis_publish_confirmed(out):
            out["dry_run"] = False
            applied["dry_run_first_default"] = False

    if applied:
        out["_setup_defaults_applied"] = applied
    return out


async def _media_analysis_chat_context_slate_review(
    record: Dict[str, Any],
    sync_event: Optional[Dict[str, Any]],
    slate_detection: Dict[str, Any],
    ctx: Optional[Context],
) -> Dict[str, Any]:
    """Slate vision is now handled by the main commit_vision payload's `slate` block.

    The vision schema (see DEFAULT_VISION_ANALYSIS_PROMPT) already includes a
    slate block; the host chat fills it in during commit_vision when a slate or
    clapper is visible in the sampled keyframes. This stub keeps the publish
    flow happy when slate_detection.use_vision is set but takes no action.
    """
    if not sync_event:
        return {"success": True, "status": "skipped", "reason": "No slate-clap event detected."}
    vision = slate_detection.get("vision") or {}
    if not _media_analysis_bool(slate_detection.get("use_vision", slate_detection.get("useVision", vision.get("enabled"))), False):
        return {"success": True, "status": "skipped", "reason": "Slate vision disabled."}
    return {
        "success": True,
        "status": "skipped",
        "provider": HOST_CHAT_PATHS_PROVIDER,
        "reason": (
            "Slate vision is embedded in the host_chat_paths commit_vision payload; "
            "fill in visual.slate during commit_vision instead of running a separate slate pass."
        ),
        "sync_event": sync_event,
    }


async def _publish_clip_metadata_from_analysis(
    proj,
    p: Dict[str, Any],
    ctx: Optional[Context],
) -> Dict[str, Any]:
    mp = proj.GetMediaPool()
    if not mp:
        return _err("Failed to get MediaPool")
    target = _media_analysis_target_dict(p.get("target"), p)
    if str(target.get("type") or p.get("target_type") or "clip").strip().lower() == "file":
        return _err("publish_clip_metadata requires Resolve Media Pool clips, not raw file targets")

    records, normalized_target, warnings, target_err = _media_analysis_records_from_target(mp, p, project=proj)
    if target_err:
        if warnings:
            target_err["warnings"] = warnings
        return target_err
    assert records is not None

    marker_decision = _media_analysis_timed_marker_decision(p)
    p = dict(p)
    p["_timed_marker_decision"] = marker_decision
    caller_dry_run = _media_analysis_bool(p.get("dry_run"), True)  # what the caller asked for
    dry_run = caller_dry_run
    # V2 P10: track WHY dry_run might get auto-flipped, so we can report it
    # honestly. Previous behavior: auto-flip to dry_run=True and still return
    # success=True per-clip, producing a silent lie ("publish succeeded" when
    # nothing was written). Fix: surface the flip reason in the response so
    # callers can distinguish "no writes attempted" from "writes succeeded".
    auto_dry_run_flip = False
    auto_dry_run_flip_reason: Optional[str] = None

    if not _media_analysis_metadata_writeback_enabled(p):
        if not dry_run:
            auto_dry_run_flip = True
            auto_dry_run_flip_reason = "metadata_writeback_disabled"
        dry_run = True

    if not dry_run and not _media_analysis_publish_confirmed(p):
        dry_run = True
        auto_dry_run_flip = True
        auto_dry_run_flip_reason = auto_dry_run_flip_reason or "publish_not_confirmed"
        confirmation_required = True
    elif not dry_run and marker_decision.get("prompt_required"):
        dry_run = True
        auto_dry_run_flip = True
        auto_dry_run_flip_reason = auto_dry_run_flip_reason or "marker_prompt_required"
        confirmation_required = True
    else:
        confirmation_required = bool(not caller_dry_run and dry_run)

    project_name, project_id = _project_name_and_id(proj)
    analysis_params = dict(p)
    analysis_params["target"] = normalized_target
    analysis_params["dry_run"] = False
    if "persist" not in analysis_params and "session_only" not in analysis_params:
        analysis_params["session_only"] = dry_run
        analysis_params["persist"] = not dry_run
    if dry_run and "cleanup_frames" not in analysis_params:
        analysis_params["cleanup_frames"] = True

    caps = _media_analysis_capabilities_for_request(ctx)

    # Auto-publish-after-commit_vision fast path. When the caller has just
    # written a fresh analysis report (commit_vision did the merge), it passes
    # `_pre_resolved_report_paths={clip_id: analysis_json_path, ...}` so we
    # skip the re-analysis step entirely. Re-running execute_plan here is
    # fragile: any cache-reuse miss (path normalization, signature drift,
    # record-shape difference) causes a fresh analysis pass, which re-emits
    # `vision_status=pending_host_analysis` and silently lies in the response
    # ("status=pending_host_vision_analysis") even though the disk artifact
    # is fine. Reading the just-written report directly removes that class.
    pre_resolved_paths = p.get("_pre_resolved_report_paths") or {}
    plan: Dict[str, Any] = {}
    manifest: Dict[str, Any] = {}
    reports_by_clip_id: Dict[str, Tuple[Dict[str, Any], Optional[str]]] = {}

    if pre_resolved_paths and isinstance(pre_resolved_paths, dict):
        for clip_id_key, report_path in pre_resolved_paths.items():
            if not clip_id_key or not report_path or not os.path.isfile(report_path):
                continue
            try:
                with open(report_path, "r", encoding="utf-8") as handle:
                    reports_by_clip_id[str(clip_id_key)] = (json.load(handle), report_path)
            except (OSError, json.JSONDecodeError):
                continue
        manifest = {
            "success": True,
            "vision_pending": False,
            "pre_resolved": True,
            "clips": [
                {
                    "record": rec,
                    "success": True,
                    "reused": True,
                    "analysis_json": reports_by_clip_id.get(str(rec.get("clip_id") or ""), (None, None))[1],
                }
                for rec in records
            ],
        }
        plan = {"success": True, "pre_resolved": True, "clip_count": len(records)}
    else:
        plan = build_media_analysis_plan(
            project_name=project_name,
            project_id=project_id,
            records=records,
            target=normalized_target,
            params=analysis_params,
            capabilities=caps,
        )
        if not plan.get("success"):
            return plan
        if plan.get("capability_gaps") and media_analysis_plan_requires_capabilities(plan):
            return _media_analysis_missing_capabilities_response(plan, action_label="metadata publish analysis")

        manifest = await execute_media_analysis_plan_async(
            plan,
            params=analysis_params,
            capabilities=caps,
        )
        if not manifest.get("success"):
            return {"success": False, "manifest": manifest, "plan": plan}
        if manifest.get("vision_pending"):
            return {
                "success": True,
                "status": "pending_host_vision_analysis",
                "manifest": manifest,
                "plan": plan,
                "pending_action": manifest.get("pending_action"),
                "reason": (
                    "Visual analysis is deferred to the host chat. Inspect manifest.clips[*].visual "
                    "for each clip's frame_paths and call media_analysis(action='commit_vision', ...) "
                    "per clip. Metadata writeback will run automatically when commit_vision finalizes."
                ),
            }

        for report in manifest.get("reports") or []:
            clip_id = ((report.get("clip") or {}).get("clip_id"))
            if clip_id:
                reports_by_clip_id[str(clip_id)] = (report, None)
    for row in manifest.get("clips") or []:
        report_path = row.get("analysis_json")
        if manifest.get("session_only") and manifest.get("artifacts_cleaned_up") and report_path and not os.path.isfile(report_path):
            report_path = None
        record = row.get("record") or {}
        clip_id = record.get("clip_id")
        if clip_id and str(clip_id) in reports_by_clip_id:
            existing_report, _ = reports_by_clip_id[str(clip_id)]
            reports_by_clip_id[str(clip_id)] = (existing_report, report_path)
            continue
        if clip_id and report_path and os.path.isfile(report_path):
            try:
                with open(report_path, "r", encoding="utf-8") as handle:
                    reports_by_clip_id[str(clip_id)] = (json.load(handle), report_path)
            except (OSError, json.JSONDecodeError):
                pass

    detection = None
    slate_detection = dict(p.get("slate_detection") or p.get("slateDetection") or {})
    if "vision" not in slate_detection and isinstance(p.get("vision"), dict):
        slate_detection["vision"] = p.get("vision")
    if _media_analysis_bool(slate_detection.get("enabled"), False):
        detection_params = dict(p)
        detection_params.update(slate_detection)
        detection_params["target"] = normalized_target
        detection_params.setdefault("prefer_event_type", "slate_clap")
        detection = detect_media_sync_events(records, detection_params)

    fields = p.get("fields") or list(_MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
    if not isinstance(fields, list):
        return _err("fields must be a list of Resolve metadata field names")
    fields = [str(field) for field in fields if str(field).strip()]
    include_provenance = _media_analysis_bool(p.get("include_provenance", p.get("includeProvenance")), True)
    marker_writeback_enabled = bool(marker_decision.get("enabled"))
    root = mp.GetRootFolder()
    results = []
    write_failures = []

    for record in records:
        clip_id = str(record.get("clip_id") or "")
        clip = _find_clip(root, clip_id)
        if not clip:
            results.append({"clip_id": clip_id, "success": False, "error": "Clip not found for metadata write"})
            write_failures.append(clip_id)
            continue
        report, report_path = reports_by_clip_id.get(clip_id, ({}, None))
        if not report:
            results.append({"clip_id": clip_id, "success": False, "error": "Analysis report not available"})
            write_failures.append(clip_id)
            continue

        metadata, metadata_error = _safe_clip_call(clip, "GetMetadata", "")
        metadata = metadata if isinstance(metadata, dict) else {}
        third_party, third_party_error = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
        third_party = third_party if isinstance(third_party, dict) else {}

        sync_event = _media_analysis_best_sync_event(detection, clip_id)
        slate_review = None
        if sync_event and _media_analysis_bool(slate_detection.get("enabled"), False):
            slate_review = await _media_analysis_chat_context_slate_review(record, sync_event, slate_detection, ctx)

        candidate_payload = _media_analysis_report_metadata_candidates(
            report,
            detection=detection,
            slate_review=slate_review,
            fields=fields,
            require_visual_description=_media_analysis_bool(p.get("require_visual_description", p.get("requireVisualDescription")), False),
            require_visual_slate=True,
        )
        proposed_fields = candidate_payload["fields"]
        field_results = []
        writes: Dict[str, str] = {}
        for field in fields:
            write_field = _metadata_write_field_for_field(field)
            existing_value = metadata.get(write_field, metadata.get(field, ""))
            merged = _media_analysis_merge_metadata_field(field, existing_value, proposed_fields.get(field), p)
            if write_field != field:
                merged["write_field"] = write_field
            field_results.append(merged)
            if merged.get("changed"):
                writes[write_field] = str(merged["value"])

        provenance = _media_analysis_provenance_metadata(report, report_path, sorted(writes.keys())) if include_provenance else {}
        marker_writeback = _media_analysis_marker_candidates_from_report(
            report,
            record,
            sync_event,
            report_path,
            p,
            slate_review=slate_review,
        )
        # V2 P10: row.success starts False — only becomes True if writes actually
        # happen and succeed. Previously defaulted to True, so dry_run cases
        # silently returned success=true with no writes.
        row = {
            "clip_id": clip_id,
            "clip_name": record.get("clip_name"),
            "success": False,
            "status": "dry_run" if dry_run else "writes_pending",
            "dry_run": dry_run,
            "auto_dry_run_flip": auto_dry_run_flip,
            "auto_dry_run_flip_reason": auto_dry_run_flip_reason,
            "timed_marker_decision": marker_decision,
            "marker_writeback_enabled": marker_writeback_enabled,
            "metadata_error": metadata_error,
            "third_party_metadata_error": third_party_error,
            "analysis_report": report_path,
            "fields": field_results,
            "metadata_writes": writes,
            "third_party_metadata_writes": provenance,
            "marker_writes": marker_writeback if marker_writeback_enabled else {"enabled": False},
            "evidence": candidate_payload.get("evidence"),
            "slate_review": slate_review,
        }
        if not dry_run:
            metadata_ok = True
            third_party_ok = True
            markers_ok = True
            for field, value in writes.items():
                try:
                    metadata_ok = bool(clip.SetMetadata(field, value)) and metadata_ok
                except Exception as exc:
                    metadata_ok = False
                    row.setdefault("write_errors", []).append({"field": field, "error": str(exc)})
            for key, value in provenance.items():
                try:
                    third_party_ok = bool(clip.SetThirdPartyMetadata(key, value)) and third_party_ok
                except Exception as exc:
                    third_party_ok = False
                    row.setdefault("write_errors", []).append({"third_party_key": key, "error": str(exc)})
            if marker_writeback_enabled:
                marker_result = _apply_media_analysis_clip_markers(clip, marker_writeback.get("markers") or [], p)
                marker_writeback["result"] = marker_result
                row["marker_writes"] = marker_writeback
                markers_ok = marker_result.get("success") is True
            row["success"] = metadata_ok and third_party_ok and markers_ok
            row["status"] = "wrote" if row["success"] else "write_failed"
            if not row["success"]:
                write_failures.append(clip_id)
        elif auto_dry_run_flip:
            # Caller asked for writes; we silently downgraded. Treat as a failure
            # of intent (caller will surface this to the user).
            row["status"] = f"blocked:{auto_dry_run_flip_reason}"
            write_failures.append(clip_id)
        results.append(row)

    # Top-level success requires: no write failures AND writes weren't auto-blocked.
    # A dry_run requested explicitly by the caller returns success=true (preview ok);
    # a dry_run auto-flipped from a real write request returns success=false.
    top_success = (not write_failures) and (not auto_dry_run_flip)

    return {
        "success": top_success,
        "dry_run": dry_run,
        "caller_dry_run": caller_dry_run,
        "auto_dry_run_flip": auto_dry_run_flip,
        "auto_dry_run_flip_reason": auto_dry_run_flip_reason,
        "setup_defaults_applied": p.get("_setup_defaults_applied", {}),
        "marker_writeback_enabled": marker_writeback_enabled,
        "timed_marker_decision": marker_decision,
        "timed_marker_prompt": _media_analysis_timed_marker_prompt() if marker_decision.get("prompt_required") else None,
        "confirmation_required": confirmation_required,
        "target": normalized_target,
        "clip_count": len(records),
        "changed_clip_count": sum(1 for row in results if row.get("metadata_writes")),
        "results": results,
        "warnings": warnings,
        "analysis_manifest": manifest,
        "sync_detection": detection,
    }


def _media_pool_item_probe(clip):
    metadata, metadata_error = _safe_clip_call(clip, "GetMetadata", "")
    third_party, third_party_error = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    known_properties = {}
    for key in _MEDIA_POOL_KNOWN_CLIP_PROPERTIES:
        value, err = _safe_clip_call(clip, "GetClipProperty", key)
        known_properties[key] = {"value": value, "error": err} if err else {"value": value}

    color, color_error = _safe_clip_call(clip, "GetClipColor")
    markers, markers_error = _safe_clip_call(clip, "GetMarkers")
    flags, flags_error = _safe_clip_call(clip, "GetFlagList")
    audio_mapping, audio_mapping_error = _safe_clip_call(clip, "GetAudioMapping")
    mark, mark_error = _safe_clip_call(clip, "GetMarkInOut")

    return {
        "summary": _media_pool_item_summary(clip),
        "methods": _callable_method_names(clip, _MEDIA_POOL_ITEM_METHODS),
        "metadata": {"value": metadata, "error": metadata_error} if metadata_error else metadata,
        "third_party_metadata": (
            {"value": third_party, "error": third_party_error} if third_party_error else third_party
        ),
        "clip_properties": {"value": properties, "error": properties_error} if properties_error else properties,
        "known_clip_properties": known_properties,
        "clip_color": {"value": color, "error": color_error} if color_error else color,
        "markers": {"value": markers, "error": markers_error} if markers_error else markers,
        "flags": {"value": flags, "error": flags_error} if flags_error else flags,
        "audio_mapping": (
            {"value": audio_mapping, "error": audio_mapping_error} if audio_mapping_error else audio_mapping
        ),
        "mark_in_out": {"value": mark, "error": mark_error} if mark_error else mark,
    }


def _folder_probe(folder, depth: int = 1):
    if not folder:
        return None
    clips = []
    for clip in (folder.GetClipList() or []):
        clips.append(_media_pool_item_summary(clip))
    subfolders = []
    if depth > 0:
        for sub in (folder.GetSubFolderList() or []):
            subfolders.append(_folder_probe(sub, depth - 1))
    stale = None
    try:
        stale = bool(folder.GetIsFolderStale())
    except Exception:
        pass
    return {
        "name": folder.GetName(),
        "id": folder.GetUniqueId(),
        "stale": stale,
        "clip_count": len(clips),
        "clips": clips,
        "subfolder_count": len(subfolders),
        "subfolders": subfolders,
    }


