def _media_pool_probe(mp, p: Dict[str, Any]):
    depth = p.get("depth", 1)
    try:
        depth = max(0, min(int(depth), 4))
    except (TypeError, ValueError):
        return _err("depth must be an integer")
    root = mp.GetRootFolder()
    current = mp.GetCurrentFolder()
    selected = []
    try:
        selected = [_media_pool_item_summary(clip) for clip in (mp.GetSelectedClips() or [])]
    except Exception as exc:
        selected = [{"error": str(exc)}]
    return {
        "media_pool_id": mp.GetUniqueId(),
        "methods": _callable_method_names(mp, _MEDIA_POOL_METHODS),
        "root": _folder_probe(root, depth),
        "current_folder": _folder_probe(current, 0) if current else None,
        "selected_clips": selected,
    }


def _media_pool_probe_ingest_items(mp, p: Dict[str, Any]):
    root = mp.GetRootFolder()
    ids = p.get("clip_ids") or p.get("ids")
    selected = bool(p.get("selected", False))
    clips = []
    warnings = []
    if ids:
        if not isinstance(ids, list):
            return _err("probe_ingest_item requires clip_ids as a list")
        for clip_id in ids:
            clip = _find_clip(root, str(clip_id))
            if clip:
                clips.append(clip)
            else:
                warnings.append(f"Clip not found: {clip_id}")
    if selected:
        try:
            clips.extend(mp.GetSelectedClips() or [])
        except Exception as exc:
            warnings.append(f"GetSelectedClips failed: {exc}")
    if not clips:
        return _err("probe_ingest_item requires clip_ids or selected=True")
    out = {"items": [_media_pool_item_probe(clip) for clip in clips], "count": len(clips)}
    if warnings:
        out["warnings"] = warnings
    return out


def _path_error(path: str, *, must_be_dir: bool = False, must_be_file: bool = False):
    if not path or not isinstance(path, str):
        return "path must be a non-empty string"
    if not os.path.exists(path):
        return f"path does not exist: {path}"
    if must_be_dir and not os.path.isdir(path):
        return f"path is not a directory: {path}"
    if must_be_file and not os.path.isfile(path):
        return f"path is not a file: {path}"
    return None


def _string_list_param(p: Dict[str, Any], key: str):
    value = p.get(key)
    if not isinstance(value, list) or not value:
        return None, _err(f"{key} must be a non-empty list")
    cleaned = []
    for index, item in enumerate(value):
        if not isinstance(item, str) or not item:
            return None, _err(f"{key}[{index}] must be a non-empty string")
        cleaned.append(item)
    return cleaned, None


def _clips_from_params(root, mp, p: Dict[str, Any], *, key: str = "clip_ids"):
    ids = p.get(key) or p.get("ids")
    selected = bool(p.get("selected", False))
    clips = []
    missing = []
    if ids:
        if not isinstance(ids, list):
            return None, _err(f"{key} must be a list")
        for clip_id in ids:
            clip = _find_clip(root, str(clip_id))
            if clip:
                clips.append(clip)
            else:
                missing.append(str(clip_id))
    if selected:
        clips.extend(mp.GetSelectedClips() or [])
    deduped = []
    seen = set()
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip) or id(clip)
        if clip_id in seen:
            continue
        seen.add(clip_id)
        deduped.append(clip)
    if not deduped:
        return None, _err(f"Provide {key} or selected=True")
    return (deduped, missing), None


def _clip_summaries(clips):
    return [_media_pool_item_summary(clip) for clip in clips]


def _imported_clip_summaries(items):
    return {
        "imported": len(items) if items else 0,
        "clips": _clip_summaries(items or []),
    }


def _format_sequence_path(pattern: str, index: int):
    try:
        return pattern % index
    except (TypeError, ValueError):
        return None


def _missing_sequence_frames(pattern: str, start: int, end: int):
    missing = []
    unformattable = False
    for index in range(start, end + 1):
        path = _format_sequence_path(pattern, index)
        if not path:
            unformattable = True
            break
        if not os.path.exists(path):
            missing.append(path)
    return missing, unformattable


def _set_current_folder_temporarily(mp, target_path: Optional[str]):
    if not target_path:
        return None, None
    target = _navigate_folder(mp, target_path)
    if not target:
        return None, _err(f"Target folder not found: {target_path}")
    previous = mp.GetCurrentFolder()
    if not mp.SetCurrentFolder(target):
        return None, _err(f"Failed to set current folder: {target_path}")
    return previous, None


def _restore_current_folder(mp, previous):
    if previous:
        try:
            mp.SetCurrentFolder(previous)
        except Exception:
            pass


def _ensure_folder_path(mp, path: str):
    if not path or path in ("Master", "/", ""):
        return mp.GetRootFolder(), None
    existing = _navigate_folder(mp, path)
    if existing:
        return existing, None
    parts = path.strip("/").split("/")
    if parts and parts[0] == "Master":
        parts = parts[1:]
    current = mp.GetRootFolder()
    built = ["Master"]
    for part in parts:
        built.append(part)
        found = None
        for sub in (current.GetSubFolderList() or []):
            if sub.GetName() == part:
                found = sub
                break
        if not found:
            found = mp.AddSubFolder(current, part)
            if not found:
                return None, _err(f"Failed to create folder: {'/'.join(built)}")
        current = found
    return current, None


def _safe_import_media(mp, p: Dict[str, Any]):
    paths, err = _string_list_param(p, "paths")
    if err:
        return err
    errors = []
    for path in paths:
        path_err = _path_error(path)
        if path_err:
            errors.append(path_err)
    if errors:
        return _err("; ".join(errors))
    if p.get("dry_run"):
        return _ok(would_import=paths, target_folder=p.get("target_folder"))
    previous, folder_err = _set_current_folder_temporarily(mp, p.get("target_folder"))
    if folder_err:
        return folder_err
    try:
        return _ok(**_imported_clip_summaries(mp.ImportMedia(paths) or []))
    finally:
        _restore_current_folder(mp, previous)


def _safe_import_sequence(mp, p: Dict[str, Any]):
    pattern = p.get("FilePath") or p.get("file_path") or p.get("pattern")
    if not pattern:
        return _err("Provide FilePath, file_path, or pattern")
    try:
        start = int(p.get("StartIndex", p.get("start_index", 1)))
        end = int(p.get("EndIndex", p.get("end_index", start)))
    except (TypeError, ValueError):
        return _err("StartIndex/EndIndex must be integers")
    if end < start:
        return _err("EndIndex must be greater than or equal to StartIndex")
    missing, unformattable = _missing_sequence_frames(pattern, start, end)
    if unformattable:
        return _err("Sequence pattern must be printf-style, e.g. frame_%03d.png")
    if missing:
        sample = missing[:5]
        suffix = "" if len(missing) <= 5 else f" (+{len(missing) - 5} more)"
        return _err(f"Missing sequence frames: {sample}{suffix}")
    info = {"FilePath": pattern, "StartIndex": start, "EndIndex": end}
    if p.get("dry_run"):
        return _ok(would_import=[info], target_folder=p.get("target_folder"))
    previous, folder_err = _set_current_folder_temporarily(mp, p.get("target_folder"))
    if folder_err:
        return folder_err
    try:
        return _ok(**_imported_clip_summaries(mp.ImportMedia([info]) or []))
    finally:
        _restore_current_folder(mp, previous)


def _safe_import_folder(mp, p: Dict[str, Any]):
    path = p.get("path")
    path_err = _path_error(path, must_be_dir=True)
    if path_err:
        return _err(path_err)
    if p.get("dry_run"):
        return _ok(would_import_folder=path, source_clips_path=p.get("source_clips_path", ""))
    return {"success": bool(mp.ImportFolderFromFile(path, p.get("source_clips_path", "")))}


def _organize_clips(mp, root, p: Dict[str, Any]):
    target_path = p.get("target_path")
    if not target_path:
        return _err("target_path is required")
    if p.get("create_missing"):
        target, target_err = _ensure_folder_path(mp, target_path)
    else:
        target = _navigate_folder(mp, target_path)
        target_err = None if target else _err(f"Target folder not found: {target_path}")
    if target_err:
        return target_err
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(target_path=target_path, clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.MoveClips(clips, target)), "moved": len(clips), "missing": missing}


def _copy_metadata(root, p: Dict[str, Any]):
    source = _find_clip(root, p.get("source_clip_id", ""))
    if not source:
        return _err(f"Source clip not found: {p.get('source_clip_id')}")
    target_ids = p.get("target_clip_ids")
    if not isinstance(target_ids, list) or not target_ids:
        return _err("target_clip_ids must be a non-empty list")
    metadata = source.GetMetadata("") or {}
    if p.get("keys"):
        keys = set(p["keys"])
        metadata = {key: value for key, value in metadata.items() if key in keys}
    third_party = {}
    if p.get("include_third_party", True):
        third_party = source.GetThirdPartyMetadata("") or {}
    results = []
    for target_id in target_ids:
        target = _find_clip(root, str(target_id))
        if not target:
            results.append({"clip_id": target_id, "success": False, "error": "Clip not found"})
            continue
        if p.get("dry_run"):
            results.append({"clip_id": target_id, "success": True, "metadata_keys": sorted(metadata.keys()), "third_party_keys": sorted(third_party.keys())})
            continue
        ok = bool(target.SetMetadata(metadata)) if metadata else True
        third_party_ok = True
        for key, value in third_party.items():
            third_party_ok = bool(target.SetThirdPartyMetadata(key, value)) and third_party_ok
        results.append({"clip_id": target_id, "success": ok and third_party_ok})
    return {"success": all(row.get("success") for row in results), "results": results}


def _normalize_metadata(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    metadata = p.get("metadata") or {}
    third_party = p.get("third_party_metadata") or p.get("thirdPartyMetadata") or {}
    if not isinstance(metadata, dict) or not isinstance(third_party, dict):
        return _err("metadata and third_party_metadata must be objects")
    if not metadata and not third_party:
        return _err("Provide metadata or third_party_metadata")
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True, "metadata_keys": sorted(metadata.keys()), "third_party_keys": sorted(third_party.keys())})
            continue
        ok = bool(clip.SetMetadata(metadata)) if metadata else True
        third_party_ok = True
        for key, value in third_party.items():
            third_party_ok = bool(clip.SetThirdPartyMetadata(key, value)) and third_party_ok
        row = {"clip_id": clip_id, "success": ok and third_party_ok}
        if ok and metadata:
            silent = _verify_writeback(clip, metadata)
            if silent:
                row["success"] = False
                row["verified"] = False
                row["unpersisted"] = {silent["key"]: silent["actual"]}
                row["error"] = silent["error"]
                if silent.get("hint"):
                    row["hint"] = silent["hint"]
        results.append(row)
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}


def _probe_clip_properties(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    return {
        "count": len(clips),
        "missing": missing,
        "items": [
            {
                "summary": _media_pool_item_summary(clip),
                "properties": _safe_clip_call(clip, "GetClipProperty", "")[0],
                "known_clip_properties": _media_pool_item_probe(clip)["known_clip_properties"],
            }
            for clip in clips
        ],
    }


def _metadata_field_inventory(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    include_values = _media_analysis_bool(p.get("include_values", p.get("includeValues")), False)
    analysis_fields = list(p.get("analysis_fields") or p.get("analysisFields") or _MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
    slate_fields = ["Scene", "Shot", "Take", "Camera #", "Roll/Card"]
    optional_fields = list(p.get("optional_fields") or p.get("optionalFields") or slate_fields)

    items = []
    for clip in clips:
        metadata, metadata_error = _safe_clip_call(clip, "GetMetadata", "")
        third_party, third_party_error = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
        properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
        metadata = metadata if isinstance(metadata, dict) else {}
        third_party = third_party if isinstance(third_party, dict) else {}
        properties = properties if isinstance(properties, dict) else {}
        property_fields = list(properties.keys())
        metadata_fields = list(metadata.keys())

        def field_status(field: str) -> Dict[str, Any]:
            clip_property_key = _metadata_clip_property_key_for_field(field, properties)
            metadata_write_key = _metadata_write_field_for_field(field)
            row = {
                "field": field,
                "in_get_metadata": field in metadata,
                "in_clip_properties": clip_property_key is not None,
                "inferred_ui_group": _metadata_panel_group_for_field(field),
            }
            if metadata_write_key != field:
                row["metadata_write_key"] = metadata_write_key
            if clip_property_key:
                row["clip_property_key"] = clip_property_key
            if include_values:
                if field in metadata:
                    row["metadata_value"] = metadata.get(field)
                if clip_property_key:
                    row["clip_property_value"] = properties.get(clip_property_key)
            return row

        item = {
            "summary": _media_pool_item_summary(clip),
            "metadata": {
                "field_count": len(metadata_fields),
                "fields": metadata_fields,
            },
            "third_party_metadata": {
                "field_count": len(third_party),
                "fields": list(third_party.keys()),
            },
            "clip_properties": {
                "field_count": len(property_fields),
                "fields": property_fields,
            },
            "metadata_panel_groups": _metadata_panel_group_inventory(property_fields),
            "analysis_writeback_fields": {
                "default": [field_status(str(field)) for field in analysis_fields],
                "optional_slate": [field_status(str(field)) for field in optional_fields],
            },
        }
        if metadata_error:
            item["metadata"]["error"] = metadata_error
        if third_party_error:
            item["third_party_metadata"]["error"] = third_party_error
        if properties_error:
            item["clip_properties"]["error"] = properties_error
        if include_values:
            item["metadata"]["values"] = metadata
            item["third_party_metadata"]["values"] = third_party
            item["clip_properties"]["values"] = properties
        items.append(item)

    return {
        "success": True,
        "count": len(items),
        "missing": missing,
        "group_source": "best_effort_from_GetClipProperty_keys_and_Resolve_20_metadata_panel_labels",
        "ui_group_names": list(_METADATA_PANEL_GROUP_ORDER),
        "notes": [
            "Read-only probe: no SetMetadata or SetClipProperty calls were made.",
            "Resolve does not expose a guaranteed UI metadata-group schema through the public scripting API.",
            "Unfilled clips may return an empty GetMetadata() dict while GetClipProperty('') still exposes metadata-panel-style fields.",
            "metadata_panel_groups is an inferred grouping of the observed clip-property keys, not a Resolve-authored schema.",
        ],
        "items": items,
    }


def _safe_relink(mp, root, p: Dict[str, Any]):
    folder_path = p.get("folder_path")
    path_err = _path_error(folder_path, must_be_dir=True)
    if path_err:
        return _err(path_err)
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(folder_path=folder_path, clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.RelinkClips(clips, folder_path)), "count": len(clips), "missing": missing}


def _safe_unlink(mp, root, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.UnlinkClips(clips)), "count": len(clips), "missing": missing}


def _parse_rate(value):
    if value in (None, "", "0/0", "N/A"):
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip()
    if not text:
        return None
    if "/" in text:
        left, right = text.split("/", 1)
        try:
            numerator = float(left.strip())
            denominator = float(right.strip())
            return numerator / denominator if denominator else None
        except (TypeError, ValueError):
            return None
    match = re.search(r"\d+(?:\.\d+)?", text.replace(",", "."))
    return float(match.group(0)) if match else None


def _parse_int_text(value):
    if value in (None, "", "N/A"):
        return None
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return value
    if isinstance(value, float):
        return int(value)
    match = re.search(r"\d+", str(value).replace(",", ""))
    return int(match.group(0)) if match else None


def _parse_resolution(value):
    if value in (None, "", "N/A"):
        return None
    if isinstance(value, (list, tuple)) and len(value) >= 2:
        width = _parse_int_text(value[0])
        height = _parse_int_text(value[1])
        return (width, height) if width and height else None
    match = re.search(r"(\d+)\s*[xX]\s*(\d+)", str(value))
    if not match:
        return None
    return int(match.group(1)), int(match.group(2))


def _normalize_media_token(value):
    return re.sub(r"[^a-z0-9]+", "", str(value or "").lower())


def _media_token_matches(actual, expected):
    expected_token = _normalize_media_token(expected)
    if not expected_token:
        return True
    actual_token = _normalize_media_token(actual)
    return bool(actual_token) and (
        actual_token == expected_token
        or expected_token in actual_token
        or actual_token in expected_token
    )


def _clip_media_signature(clip):
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    properties = properties if isinstance(properties, dict) else {}
    resolution = _parse_resolution(
        properties.get("Resolution")
        or properties.get("Video Resolution")
        or properties.get("Image Size")
    )
    signature = {
        "name": _safe_media_pool_item_name(clip),
        "id": _safe_media_pool_item_id(clip),
        "file_path": properties.get("File Path") or properties.get("FilePath"),
        "resolution": {"width": resolution[0], "height": resolution[1]} if resolution else None,
        "fps": _parse_rate(
            properties.get("FPS")
            or properties.get("Frame Rate")
            or properties.get("Video Frame Rate")
        ),
        "frames": _parse_int_text(
            properties.get("Frames")
            or properties.get("Frame Count")
            or properties.get("Duration Frames")
        ),
        "sample_rate": _parse_int_text(
            properties.get("Sample Rate")
            or properties.get("Audio Sample Rate")
        ),
    }
    if properties_error:
        signature["properties_error"] = properties_error
    return signature


def _probe_media_file(path: str):
    ffprobe = shutil.which("ffprobe")
    if not ffprobe:
        return {
            "success": False,
            "code": "FFPROBE_MISSING",
            "error": "ffprobe is not installed or not on PATH",
            "path": path,
        }
    try:
        proc = subprocess.run(
            [
                ffprobe,
                "-v",
                "error",
                "-show_streams",
                "-of",
                "json",
                path,
            ],
            capture_output=True,
            encoding="utf-8",
            errors="replace",
            timeout=20,
            stdin=subprocess.DEVNULL,
        )
    except subprocess.TimeoutExpired:
        return {"success": False, "code": "FFPROBE_TIMEOUT", "error": "ffprobe timed out", "path": path}
    except Exception as exc:
        return {"success": False, "code": "FFPROBE_FAILED", "error": str(exc), "path": path}
    if proc.returncode != 0:
        return {
            "success": False,
            "code": "FFPROBE_FAILED",
            "returncode": proc.returncode,
            "error": (proc.stderr or proc.stdout or "").strip(),
            "path": path,
        }
    try:
        payload = json.loads(proc.stdout or "{}")
    except json.JSONDecodeError as exc:
        return {"success": False, "code": "FFPROBE_JSON_ERROR", "error": str(exc), "path": path}
    streams = payload.get("streams") if isinstance(payload, dict) else []
    streams = streams if isinstance(streams, list) else []
    video = next((stream for stream in streams if stream.get("codec_type") == "video"), {})
    audio = next((stream for stream in streams if stream.get("codec_type") == "audio"), {})
    return {"success": True, "path": path, "video": video, "audio": audio, "stream_count": len(streams)}


def _proxy_media_signature(probe: Dict[str, Any]):
    video = probe.get("video") if isinstance(probe.get("video"), dict) else {}
    audio = probe.get("audio") if isinstance(probe.get("audio"), dict) else {}
    width = _parse_int_text(video.get("width"))
    height = _parse_int_text(video.get("height"))
    return {
        "path": probe.get("path"),
        "codec": video.get("codec_name"),
        "codec_long_name": video.get("codec_long_name"),
        "profile": video.get("profile"),
        "resolution": {"width": width, "height": height} if width and height else None,
        "fps": _parse_rate(video.get("avg_frame_rate") or video.get("r_frame_rate")),
        "frames": _parse_int_text(video.get("nb_frames") or (video.get("tags") or {}).get("NUMBER_OF_FRAMES")),
        "sample_rate": _parse_int_text(audio.get("sample_rate")),
        "channels": _parse_int_text(audio.get("channels")),
    }


def _add_proxy_resolution_mismatch(result: Dict[str, Any], source, proxy):
    """Flag resolution only when the aspect ratio differs.

    Proxies are routinely lower resolution than the source — Resolve links a
    half/quarter-res proxy happily (that is the point of proxies; verified live
    on Resolve Studio 21). Only a different aspect ratio means the file cannot
    be a proxy of this source.
    """
    if not source or not proxy:
        return
    src_w, src_h = source.get("width"), source.get("height")
    pxy_w, pxy_h = proxy.get("width"), proxy.get("height")
    if not (src_w and src_h and pxy_w and pxy_h):
        return
    if (src_w, src_h) == (pxy_w, pxy_h):
        return
    src_aspect = src_w / src_h
    pxy_aspect = pxy_w / pxy_h
    if abs(src_aspect - pxy_aspect) / src_aspect <= 0.02:
        result["warnings"].append(
            f"Proxy is a same-aspect downscale ({src_w}x{src_h} -> {pxy_w}x{pxy_h})"
        )
        return
    result["mismatches"].append({"field": "resolution", "source": source, "proxy": proxy})


def _add_proxy_mismatch(mismatches: List[Dict[str, Any]], field: str, source, proxy, *, tolerance: float = 0.0):
    if source is None or proxy is None:
        return
    if isinstance(source, (int, float)) and isinstance(proxy, (int, float)):
        if abs(float(source) - float(proxy)) <= tolerance:
            return
    elif source == proxy:
        return
    mismatches.append({"field": field, "source": source, "proxy": proxy})


def _check_proxy_media_compatibility(
    clip,
    proxy_path: str,
    *,
    expected_codec: Optional[str] = None,
    expected_profile: Optional[str] = None,
):
    source = _clip_media_signature(clip)
    probe = _probe_media_file(proxy_path)
    proxy = _proxy_media_signature(probe) if probe.get("success") else {"path": proxy_path}
    result = {
        "success": bool(probe.get("success")),
        "compatible": False,
        "source": source,
        "proxy": proxy,
        "mismatches": [],
        "warnings": [],
    }
    if not probe.get("success"):
        result["error"] = probe.get("error", "Unable to probe proxy media")
        result["code"] = probe.get("code", "FFPROBE_FAILED")
        return result

    _add_proxy_resolution_mismatch(result, source.get("resolution"), proxy.get("resolution"))
    _add_proxy_mismatch(result["mismatches"], "fps", source.get("fps"), proxy.get("fps"), tolerance=0.01)
    _add_proxy_mismatch(result["mismatches"], "frames", source.get("frames"), proxy.get("frames"), tolerance=1)
    _add_proxy_mismatch(result["mismatches"], "sample_rate", source.get("sample_rate"), proxy.get("sample_rate"))

    if expected_codec and not (
        _media_token_matches(proxy.get("codec"), expected_codec)
        or _media_token_matches(proxy.get("codec_long_name"), expected_codec)
    ):
        result["mismatches"].append({
            "field": "expected_codec",
            "expected": expected_codec,
            "proxy": proxy.get("codec") or proxy.get("codec_long_name"),
        })
    if expected_profile and not _media_token_matches(proxy.get("profile"), expected_profile):
        result["mismatches"].append({
            "field": "expected_profile",
            "expected": expected_profile,
            "proxy": proxy.get("profile"),
        })

    result["compatible"] = not result["mismatches"]
    if source.get("resolution") is None:
        result["warnings"].append("Source clip resolution was not available from GetClipProperty")
    if source.get("fps") is None:
        result["warnings"].append("Source clip FPS was not available from GetClipProperty")
    if proxy.get("frames") is None:
        result["warnings"].append("Proxy frame count was not available from ffprobe")
    return result


def _proxy_link_readback(clip):
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    properties = properties if isinstance(properties, dict) else {}
    readback = {"clip_properties": properties}
    if properties_error:
        readback["properties_error"] = properties_error
    proxy_keys = [
        "Proxy",
        "Proxy Media",
        "Proxy Media Path",
        "Proxy Path",
        "Proxy Status",
        "ProxyMediaPath",
    ]
    observed = {key: properties.get(key) for key in proxy_keys if key in properties}
    if observed:
        readback["proxy_fields"] = observed
    return readback


def _normalized_path_for_compare(path):
    if not path or not isinstance(path, str):
        return None
    return os.path.normcase(os.path.abspath(os.path.expanduser(path)))


def _proxy_readback_matches_path(readback: Dict[str, Any], proxy_path: str):
    expected = _normalized_path_for_compare(proxy_path)
    if not expected:
        return False
    proxy_fields = readback.get("proxy_fields") if isinstance(readback, dict) else {}
    proxy_fields = proxy_fields if isinstance(proxy_fields, dict) else {}
    for value in proxy_fields.values():
        if _normalized_path_for_compare(value) == expected:
            return True
    return False


def _proxy_link_journal_event(event_type: str, clip, proxy_path: str, *, success=None, verified=False, compatibility=None):
    event = {
        "type": event_type,
        "clip_id": _safe_media_pool_item_id(clip),
        "clip_name": _safe_media_pool_item_name(clip),
        "proxy_path": proxy_path,
        "success": success,
        "verified": bool(verified),
    }
    if compatibility is not None:
        event["compatible"] = bool(compatibility.get("compatible"))
        if compatibility.get("mismatches"):
            event["mismatch_fields"] = [row.get("field") for row in compatibility.get("mismatches", [])]
    return event


def _verified_operation(
    name: str,
    *,
    requested: Dict[str, Any],
    preflight: Dict[str, Any],
    execution: Dict[str, Any],
    verification_status: str,
    readback=None,
    journal_event=None,
):
    return {
        "name": name,
        "preflight": preflight,
        "requested": requested,
        "execution": execution,
        "readback": readback,
        "verified": verification_status == "readback_verified",
        "verification_status": verification_status,
        "journal_event": journal_event,
    }


def _check_proxy_media_compatibility_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    proxy_path = p.get("proxy_path") or p.get("path")
    path_err = _path_error(proxy_path, must_be_file=True)
    if path_err:
        return _err(path_err)
    return _check_proxy_media_compatibility(
        clip,
        proxy_path,
        expected_codec=p.get("expected_codec") or p.get("codec"),
        expected_profile=p.get("expected_profile") or p.get("profile"),
    )


def _timeline_append_readback_snapshot(proj):
    try:
        tl = proj.GetCurrentTimeline() if proj else None
    except Exception as exc:
        return {"available": False, "error": f"GetCurrentTimeline failed: {exc}"}
    if not tl:
        return {"available": False, "error": "No current timeline"}

    timeline = {}
    try:
        timeline["name"] = tl.GetName()
    except Exception:
        timeline["name"] = None
    try:
        timeline["id"] = tl.GetUniqueId()
    except Exception:
        timeline["id"] = None

    tracks = {}
    item_count = 0
    warnings = []
    for track_type in ("video", "audio", "subtitle"):
        track_count = _timeline_track_count(tl, track_type)
        rows = []
        for track_index in range(1, track_count + 1):
            try:
                items = tl.GetItemListInTrack(track_type, track_index) or []
            except Exception as exc:
                warnings.append(f"GetItemListInTrack({track_type}, {track_index}) failed: {exc}")
                items = []
            item_count += len(items)
            rows.append({
                "track_index": track_index,
                "item_count": len(items),
                "item_ids": _timeline_item_ids(items),
            })
        tracks[track_type] = {"track_count": track_count, "tracks": rows}
    return {
        "available": True,
        "timeline": timeline,
        "item_count": item_count,
        "tracks": tracks,
        "warnings": warnings,
    }


def _compare_timeline_append_readback(before, observed, expected_count: int):
    before_count = before.get("item_count") if isinstance(before, dict) and before.get("available") else None
    after_count = observed.get("item_count") if isinstance(observed, dict) and observed.get("available") else None
    delta = after_count - before_count if before_count is not None and after_count is not None else None
    return {
        "verified": delta is not None and delta >= expected_count and expected_count > 0,
        "before_item_count": before_count,
        "after_item_count": after_count,
        "item_count_delta": delta,
        "expected_item_count_delta": expected_count,
    }


def _append_to_timeline_with_verification(proj, mp, append_payload, requested: Dict[str, Any], expected_count: int):
    raw_result = {"value": None}
    before = _timeline_append_readback_snapshot(proj)

    def mutate():
        raw_result["value"] = mp.AppendToTimeline(append_payload)
        return bool(raw_result["value"])

    verification = verify_by_readback(
        mutate=mutate,
        observe=lambda: _timeline_append_readback_snapshot(proj),
        snapshot=lambda: before,
        compare=lambda before_snapshot, observed: _compare_timeline_append_readback(
            before_snapshot,
            observed,
            expected_count,
        ),
        intent=requested,
        label="media_pool.append_to_timeline",
    )
    return raw_result["value"], verification, before


def _append_to_timeline_verified_operation(requested: Dict[str, Any], verification: Dict[str, Any], before):
    success = bool(verification.get("success_raw"))
    verified = bool(verification.get("verified"))
    verification_status = "readback_verified" if verified else ("api_failed" if not success else "api_success_unverified")
    readback = {
        "before": before,
        "after": verification.get("observed"),
        "before_item_count": verification.get("before_item_count"),
        "after_item_count": verification.get("after_item_count"),
        "item_count_delta": verification.get("item_count_delta"),
        "expected_item_count_delta": verification.get("expected_item_count_delta"),
    }
    return _verified_operation(
        "media_pool.append_to_timeline",
        requested=requested,
        preflight={
            "ok": True,
            "current_timeline_available": bool(isinstance(before, dict) and before.get("available")),
            "expected_item_count_delta": requested.get("expected_count"),
        },
        execution={"api": "MediaPool.AppendToTimeline", "attempted": True, "success": success},
        readback=readback,
        verification_status=verification_status,
        journal_event={
            "type": "timeline.appended" if verified else ("timeline.append.failed" if not success else "timeline.append.unverified"),
            "success": success,
            "verified": verified,
            "expected_count": requested.get("expected_count"),
            "item_count_delta": verification.get("item_count_delta"),
        },
    )


def _link_proxy_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    proxy_path = p.get("proxy_path") or p.get("path")
    path_err = _path_error(proxy_path, must_be_file=True)
    if path_err:
        return _err(path_err)
    missing = _requires_method(clip, "LinkProxyMedia", "17.0")
    if missing:
        return missing
    check_compatibility = bool(
        p.get("check_compatibility")
        or p.get("require_compatible")
        or p.get("expected_codec")
        or p.get("expected_profile")
        or p.get("codec")
        or p.get("profile")
    )
    compatibility = None
    if check_compatibility:
        compatibility = _check_proxy_media_compatibility(
            clip,
            proxy_path,
            expected_codec=p.get("expected_codec") or p.get("codec"),
            expected_profile=p.get("expected_profile") or p.get("profile"),
        )
    requested = {
        "clip_id": p.get("clip_id"),
        "proxy_path": proxy_path,
        "dry_run": bool(p.get("dry_run")),
        "check_compatibility": check_compatibility,
        "require_compatible": bool(p.get("require_compatible")),
        "expected_codec": p.get("expected_codec") or p.get("codec"),
        "expected_profile": p.get("expected_profile") or p.get("profile"),
    }
    preflight = {
        "ok": True,
        "clip_found": True,
        "proxy_path_valid": True,
        "method_available": True,
        "compatibility_checked": compatibility is not None,
    }
    if compatibility is not None:
        preflight["compatible"] = bool(compatibility.get("compatible"))
    if p.get("dry_run"):
        out = _ok(clip=_media_pool_item_summary(clip), proxy_path=proxy_path)
        if compatibility is not None:
            out["compatibility"] = compatibility
        out["verified_operation"] = _verified_operation(
            "media_pool.link_proxy_checked",
            requested=requested,
            preflight=preflight,
            execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": False, "success": None},
            readback=None,
            verification_status="dry_run",
            journal_event=_proxy_link_journal_event(
                "proxy.link.preview",
                clip,
                proxy_path,
                success=None,
                verified=False,
                compatibility=compatibility,
            ),
        )
        return out
    if p.get("require_compatible") and compatibility is not None and not compatibility.get("compatible"):
        out = _err(
            "Proxy media is not compatible with the source clip; refusing LinkProxyMedia",
            code="PROXY_INCOMPATIBLE",
            category="invalid_input",
            remediation="Use a proxy with matching resolution, FPS, frame count, sample rate, and requested codec/profile.",
        )
        out["compatibility"] = compatibility
        out["verified_operation"] = _verified_operation(
            "media_pool.link_proxy_checked",
            requested=requested,
            preflight={**preflight, "ok": False},
            execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": False, "success": None},
            readback=None,
            verification_status="blocked",
            journal_event=_proxy_link_journal_event(
                "proxy.link.blocked",
                clip,
                proxy_path,
                success=False,
                verified=False,
                compatibility=compatibility,
            ),
        )
        return out
    verification = verify_by_readback(
        mutate=lambda: clip.LinkProxyMedia(proxy_path),
        observe=lambda: _proxy_link_readback(clip),
        compare=lambda _before, observed: {
            "verified": _proxy_readback_matches_path(observed, proxy_path),
        },
        intent={"clip_id": p.get("clip_id"), "proxy_path": proxy_path},
        label="media_pool.link_proxy_checked",
    )
    success = bool(verification.get("success_raw"))
    readback = verification.get("observed")
    verified = bool(verification.get("verified"))
    verification_status = "readback_verified" if verified else ("api_failed" if not success else "api_success_unverified")
    event_type = "proxy.linked" if success else "proxy.link.failed"
    out = {"success": success, "readback": readback}
    if compatibility is not None:
        out["compatibility"] = compatibility
    out["verified_operation"] = _verified_operation(
        "media_pool.link_proxy_checked",
        requested=requested,
        preflight=preflight,
        execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": True, "success": success},
        readback=readback,
        verification_status=verification_status,
        journal_event=_proxy_link_journal_event(
            event_type,
            clip,
            proxy_path,
            success=success,
            verified=verified,
            compatibility=compatibility,
        ),
    )
    return out


def _link_full_resolution_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    missing = _requires_method(clip, "LinkFullResolutionMedia", "20.0")
    if missing:
        return missing
    path = p.get("path") or p.get("full_res_media_path") or p.get("fullResMediaPath")
    path_err = _path_error(path, must_be_file=True)
    if path_err:
        return _err(path_err)
    if p.get("dry_run"):
        return _ok(clip=_media_pool_item_summary(clip), path=path)
    return {"success": bool(clip.LinkFullResolutionMedia(path))}


def _set_clip_marks(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    try:
        mark_in = int(p["mark_in"])
        mark_out = int(p["mark_out"])
    except (KeyError, TypeError, ValueError):
        return _err("mark_in and mark_out must be integers")
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True, "mark_in": mark_in, "mark_out": mark_out})
            continue
        results.append({"clip_id": clip_id, "success": bool(clip.SetMarkInOut(mark_in, mark_out, p.get("type", "all")))})
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}


def _clear_clip_marks(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True})
            continue
        results.append({"clip_id": clip_id, "success": bool(clip.ClearMarkInOut(p.get("type", "all")))})
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}


def _copy_clip_annotations(root, p: Dict[str, Any]):
    source = _find_clip(root, p.get("source_clip_id", ""))
    if not source:
        return _err(f"Source clip not found: {p.get('source_clip_id')}")
    target_ids = p.get("target_clip_ids")
    if not isinstance(target_ids, list) or not target_ids:
        return _err("target_clip_ids must be a non-empty list")
    markers = source.GetMarkers() or {}
    flags = source.GetFlagList() or []
    color = source.GetClipColor()
    include_markers = p.get("include_markers", True)
    include_flags = p.get("include_flags", True)
    include_color = p.get("include_clip_color", True)
    results = []
    for target_id in target_ids:
        target = _find_clip(root, str(target_id))
        if not target:
            results.append({"clip_id": target_id, "success": False, "error": "Clip not found"})
            continue
        if p.get("dry_run"):
            results.append({"clip_id": target_id, "success": True, "markers": len(markers), "flags": len(flags), "clip_color": color})
            continue
        ok = True
        if include_color and color:
            ok = bool(target.SetClipColor(color)) and ok
        if include_flags:
            for flag in flags:
                ok = bool(target.AddFlag(flag)) and ok
        if include_markers:
            for frame, marker in markers.items():
                custom = marker.get("customData") or marker.get("custom_data") or ""
                ok = bool(
                    target.AddMarker(
                        int(frame),
                        marker.get("color", "Blue"),
                        marker.get("name", ""),
                        marker.get("note", ""),
                        marker.get("duration", 1),
                        custom,
                    )
                ) and ok
        results.append({"clip_id": target_id, "success": ok})
    return {"success": all(row.get("success") for row in results), "results": results}


def _media_pool_boundary_report(mp, p: Dict[str, Any]):
    report = {
        "capabilities": _media_pool_ingest_capabilities(),
        "media_pool": _media_pool_probe(mp, {"depth": p.get("depth", 1)}),
    }
    if p.get("clip_ids") or p.get("selected"):
        report["items"] = _media_pool_probe_ingest_items(mp, p)
    return report


def _ser(obj):
    """Serialize Resolve API objects to JSON-safe values."""
    if obj is None:
        return None
    if isinstance(obj, (str, int, float, bool)):
        return obj
    if isinstance(obj, dict):
        return {k: _ser(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return [_ser(v) for v in obj]
    # Resolve API object — return repr
    return str(obj)

def _png_chunk(chunk_type: bytes, chunk_data: bytes) -> bytes:
    payload = chunk_type + chunk_data
    crc = struct.pack(">I", zlib.crc32(payload) & 0xFFFFFFFF)
    return struct.pack(">I", len(chunk_data)) + payload + crc

def _thumbnail_data_to_png_bytes(thumbnail_data: Dict[str, Any]) -> bytes:
    """Convert Resolve's raw thumbnail dict into PNG bytes."""
    if not isinstance(thumbnail_data, dict):
        raise ValueError("thumbnail_data must be a dict")

    width = int(thumbnail_data.get("width") or 0)
    height = int(thumbnail_data.get("height") or 0)
    components = int(
        thumbnail_data.get("noOfComponents")
        or thumbnail_data.get("components")
        or thumbnail_data.get("channels")
        or 3
    )
    depth = int(thumbnail_data.get("depth") or 8)
    data = thumbnail_data.get("data")

    if width <= 0 or height <= 0:
        raise ValueError(f"Invalid thumbnail dimensions: {width}x{height}")
    if components not in (3, 4):
        raise ValueError(f"Unsupported thumbnail component count: {components}")
    if depth != 8:
        raise ValueError(f"Unsupported thumbnail bit depth: {depth}")
    if not data:
        raise ValueError("Thumbnail data is empty")

    if isinstance(data, str):
        raw = base64.b64decode(data)
    elif isinstance(data, bytes):
        raw = data
    elif isinstance(data, bytearray):
        raw = bytes(data)
    elif isinstance(data, list):
        raw = bytes(data)
    else:
        raise ValueError(f"Unsupported thumbnail data type: {type(data).__name__}")

    row_size = width * components
    expected_size = row_size * height
    if len(raw) < expected_size:
        raise ValueError(
            f"Thumbnail data too short: got {len(raw)} bytes, expected "
            f"{expected_size} for {width}x{height}x{components}"
        )
    raw = raw[:expected_size]

    filtered_rows = bytearray()
    for y in range(height):
        filtered_rows.append(0)
        start = y * row_size
        filtered_rows.extend(raw[start:start + row_size])

    color_type = 2 if components == 3 else 6
    ihdr = struct.pack(">IIBBBBB", width, height, 8, color_type, 0, 0, 0)
    return (
        b"\x89PNG\r\n\x1a\n"
        + _png_chunk(b"IHDR", ihdr)
        + _png_chunk(b"IDAT", zlib.compress(bytes(filtered_rows)))
        + _png_chunk(b"IEND", b"")
    )

def _unknown(action, valid):
    return _err(f"Unknown action '{action}'. Valid actions: {', '.join(valid)}")


def _normalize_cdl(cdl):
    """Normalize CDL payloads to the string format Resolve's SetCDL expects."""
    return normalize_cdl_payload(cdl)


