def _find_project_timeline(project, name: str):
    """Return the timeline named `name` in `project`, or None."""
    try:
        count = int(project.GetTimelineCount() or 0)
    except Exception:
        return None
    for i in range(1, count + 1):
        tl = project.GetTimelineByIndex(i)
        try:
            if tl and tl.GetName() == name:
                return tl
        except Exception:
            continue
    return None


class _SpecLiveExecutor:
    """Live executor for project_spec.apply_spec — adapts a Resolve project to
    the duck-typed executor contract. Spec-aware so live_state() only reads the
    setting keys the spec cares about."""

    def __init__(self, r, pm, spec):
        self._r = r
        self._pm = pm
        self._spec = spec
        self._proj = pm.GetCurrentProject()

    def _media_pool_bin_paths(self) -> List[str]:
        if not self._proj or not getattr(self._spec, "bins", None):
            return []
        try:
            mp = self._proj.GetMediaPool()
            root = mp.GetRootFolder() if mp else None
        except Exception:
            return []
        if root is None:
            return []
        paths: List[str] = []

        def walk(folder, prefix: str) -> None:
            paths.append(prefix)
            try:
                subfolders = folder.GetSubFolderList() or []
            except Exception:
                subfolders = []
            for subfolder in subfolders:
                try:
                    name = subfolder.GetName()
                except Exception:
                    name = ""
                if name:
                    walk(subfolder, f"{prefix}/{name}")

        walk(root, "Master")
        return paths

    def live_state(self) -> Dict[str, Any]:
        proj = self._proj
        projects = list(self._pm.GetProjectListInCurrentFolder() or [])
        settings: Dict[str, Any] = {}
        if proj:
            for k in _project_spec.effective_settings(self._spec):
                try:
                    v = proj.GetSetting(k)
                except Exception:
                    v = None
                if v is not None:
                    settings[k] = v
        spec_names = {t.name for t in self._spec.timelines}
        timelines: List[Dict[str, Any]] = []
        if proj:
            count = int(proj.GetTimelineCount() or 0)
            for i in range(1, count + 1):
                tl = proj.GetTimelineByIndex(i)
                if not tl:
                    continue
                name = tl.GetName()
                if name not in spec_names:
                    timelines.append({"name": name})
                    continue
                tspec = next((t for t in self._spec.timelines if t.name == name), None)
                keys = set((tspec.settings if tspec else {})) | {"timelineFrameRate"}
                tl_settings: Dict[str, Any] = {}
                for k in keys:
                    try:
                        v = tl.GetSetting(k)
                    except Exception:
                        v = None
                    if v is not None:
                        tl_settings[k] = v
                markers: List[Dict[str, Any]] = []
                try:
                    for frame, m in (tl.GetMarkers() or {}).items():
                        entry = {"frame": int(frame)}
                        if isinstance(m, dict):
                            entry.update({kk: m.get(kk) for kk in
                                          ("color", "name", "note", "duration", "customData")})
                        markers.append(entry)
                except Exception:
                    pass
                timelines.append({"name": name, "settings": tl_settings, "markers": markers})
        return {
            "project": proj.GetName() if proj else None,
            "projects": projects,
            "settings": settings,
            "bins": self._media_pool_bin_paths(),
            "timelines": timelines,
        }

    def ensure_project(self, name: str) -> bool:
        if self._proj and self._proj.GetName() == name:
            return True
        projects = list(self._pm.GetProjectListInCurrentFolder() or [])
        proj = self._pm.LoadProject(name) if name in projects else self._pm.CreateProject(name)
        if proj:
            self._proj = proj
            return True
        return False

    def set_project_setting(self, key: str, value: Any) -> bool:
        if not self._proj:
            return False
        try:
            return bool(self._proj.SetSetting(key, str(value)))
        except Exception:
            return False

    def ensure_bin(self, path: str) -> bool:
        if not self._proj:
            return False
        try:
            mp = self._proj.GetMediaPool()
        except Exception:
            return False
        if mp is None:
            return False
        _, err = _ensure_folder_path(mp, path)
        return err is None

    def ensure_timeline(self, name: str, fps: Optional[float]) -> bool:
        if not self._proj:
            return False
        tl = _find_project_timeline(self._proj, name)
        if tl is None:
            mp = self._proj.GetMediaPool()
            if mp is None:
                return False
            tl = mp.CreateEmptyTimeline(name)
            if tl is None:
                return False
        if fps is not None:
            try:
                tl.SetSetting("timelineFrameRate", str(fps))
            except Exception:
                pass
        return True

    def set_timeline_setting(self, tl_name: str, key: str, value: Any) -> bool:
        tl = _find_project_timeline(self._proj, tl_name) if self._proj else None
        if tl is None:
            return False
        try:
            return bool(tl.SetSetting(key, str(value)))
        except Exception:
            return False

    def add_marker(self, tl_name: str, marker: Dict[str, Any]) -> bool:
        tl = _find_project_timeline(self._proj, tl_name) if self._proj else None
        if tl is None:
            return False
        try:
            return bool(tl.AddMarker(
                int(marker.get("frame", 0)),
                marker.get("color", "Blue"),
                marker.get("name", ""),
                marker.get("note", ""),
                int(marker.get("duration", 1)),
                marker.get("customData", marker.get("custom_data", "")),
            ))
        except Exception:
            return False


def _make_spec_hook_runner(timeout: float = 120.0):
    """Return a callable that runs a Hook's command (opt-in only).

    The command is split with shlex and run WITHOUT a shell, so a spec's hook
    string cannot inject arbitrary shell (`; rm -rf …`, pipes, expansion). A
    hook that needs shell features must invoke an explicit interpreter
    (e.g. ``bash -c "…"``) as its own argv, making the intent visible (EX1).
    """
    import shlex
    import subprocess

    def _run(hook) -> bool:
        try:
            argv = shlex.split(hook.command or "")
        except ValueError as exc:
            logger.warning("spec hook '%s' has an unparseable command: %s", hook.name or hook.command, exc)
            return False
        if not argv:
            logger.warning("spec hook '%s' has an empty command", hook.name or "")
            return False
        try:
            proc = subprocess.run(
                argv,
                shell=False,
                timeout=timeout,
                stdin=subprocess.DEVNULL,
                capture_output=True,
                text=True,
            )
            return proc.returncode == 0
        except Exception as exc:
            logger.warning("spec hook '%s' failed: %s", hook.name or hook.command, exc)
            return False

    return _run


def _spec_action(r, pm, action: str, p: Dict[str, Any]) -> Dict[str, Any]:
    """plan_spec / apply_spec / diff_to_spec — declarative project reconcile."""
    spec_path = p.get("spec_path") or p.get("path")
    try:
        if spec_path:
            spec = _project_spec.load_spec(str(spec_path))
        elif isinstance(p.get("spec"), dict):
            spec = _project_spec.spec_from_dict(p["spec"])
        else:
            return _err("Provide spec_path (file) or an inline spec dict.",
                        code="NO_SPEC", category="invalid_input")
    except _project_spec.SpecError as exc:
        return _err(str(exc), code="SPEC_INVALID", category="invalid_input", state=exc.state)

    executor = _SpecLiveExecutor(r, pm, spec)
    if action == "diff_to_spec":
        return _ok(project=spec.project, **_project_spec.plan_spec(spec, executor.live_state()))
    if action == "plan_spec":
        return _ok(project=spec.project,
                   **_project_spec.apply_spec(spec, executor, dry_run=True))
    # apply_spec
    run_hooks = bool(p.get("run_hooks", False))
    try:
        result = _project_spec.apply_spec(
            spec, executor,
            dry_run=bool(p.get("dry_run", False)),
            run_hooks=run_hooks,
            continue_on_error=bool(p.get("continue_on_error", False)),
            run_hook=_make_spec_hook_runner() if run_hooks else None,
        )
    except _project_spec.SpecError as exc:
        return _err(str(exc), code="SPEC_APPLY_FAILED",
                    category="batch_partial", state=exc.state)
    return _ok(**result) if result.get("success") else {"success": False, **result}


def _project_lint_live(r, pm) -> Dict[str, Any]:
    """Gather live project state and run the lint health-check."""
    proj = pm.GetCurrentProject()
    if not proj:
        return _ok(**_project_lint.lint_report({"project": None}))
    state: Dict[str, Any] = {"project": proj.GetName()}
    try:
        cur = proj.GetCurrentTimeline()
        state["current_timeline"] = cur.GetName() if cur else None
    except Exception:
        state["current_timeline"] = None
    timelines: List[Dict[str, Any]] = []
    try:
        count = int(proj.GetTimelineCount() or 0)
    except Exception:
        count = 0
    for i in range(1, count + 1):
        tl = proj.GetTimelineByIndex(i)
        if not tl:
            continue
        fps = None
        try:
            fps = float(tl.GetSetting("timelineFrameRate"))
        except Exception:
            pass
        item_count = 0
        video_item_count = 0
        audio_item_count = 0
        subtitle_item_count = 0
        try:
            for track_type, key in (
                ("video", "video_item_count"),
                ("audio", "audio_item_count"),
                ("subtitle", "subtitle_item_count"),
            ):
                track_total = 0
                track_count = int(tl.GetTrackCount(track_type) or 0)
                for ti in range(1, track_count + 1):
                    track_total += len(tl.GetItemListInTrack(track_type, ti) or [])
                if key == "video_item_count":
                    video_item_count = track_total
                elif key == "audio_item_count":
                    audio_item_count = track_total
                elif key == "subtitle_item_count":
                    subtitle_item_count = track_total
                item_count += track_total
        except Exception:
            pass
        timelines.append({
            "name": tl.GetName(),
            "fps": fps,
            "item_count": item_count,
            "video_item_count": video_item_count,
            "audio_item_count": audio_item_count,
            "subtitle_item_count": subtitle_item_count,
        })
    state["timelines"] = timelines
    settings: Dict[str, Any] = {}
    try:
        csm = proj.GetSetting("colorScienceMode")
        if csm is not None:
            settings["colorScienceMode"] = csm
    except Exception:
        pass
    state["settings"] = settings
    render: Dict[str, Any] = {}
    try:
        rf = proj.GetCurrentRenderFormatAndCodec() or {}
        if rf.get("format"):
            render["format"] = rf.get("format")
        render["codec"] = rf.get("codec")
    except Exception:
        pass
    state["render"] = render
    return _ok(**_project_lint.lint_report(state))


@mcp.tool()
def project_manager(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Manage DaVinci Resolve projects.

    Actions:
      list() -> {projects}
      get_current() -> {name, id}
      create(name, media_location_path?) -> {success, name}
      load(name) -> {success}
      save() -> {success}
      close() -> {success}
      delete(name) -> {success}
      import_project(path, name?) -> {success}
      export_project(name, path, with_stills_and_luts?) -> {success}
      archive(name, path, src_media?, render_cache?, proxy_media?) -> {success}
      restore(path, name?) -> {success}
      project_capabilities() -> {capabilities}
      probe_project_lifecycle() -> {project_manager, ...}
      probe_project_settings(keys?, try_write?) -> {snapshot, candidate_settings}
      safe_project_create(name, media_location_path?, dry_run?) -> {success}
      safe_project_export(name, path, with_stills_and_luts?, dry_run?) -> {success}
      safe_project_import(path, name, dry_run?) -> {success}
      safe_project_archive(name, path, src_media=false, render_cache=false, proxy_media=false, dry_run?) -> {success}
      safe_project_restore(path, name, dry_run?) -> {success}
      safe_project_delete(name, close_current?, dry_run?) -> {success}
      safe_set_project_settings(settings, restore?, dry_run?) -> {success}
      project_settings_snapshot(name?) -> {project, settings, presets, ...}
      database_capabilities() -> {methods, current, databases}
      safe_set_current_database(db_info, dry_run?, allow_switch?) -> {success}
      preset_lifecycle_probe() -> {project_presets, render_presets, layout_presets, ...}
      project_boundary_report() -> {capabilities, project_manager, settings, database, presets, cloud}
      lint() -> {ok, counts, issues} — graded project health pre-flight (no project, no
        current timeline, mixed fps, empty timeline, render/color-science unset, offline media).
      diff_to_spec(spec_path|spec) -> {actions, diff, change_count} — preview drift vs a
        declarative spec WITHOUT mutating. Spec is YAML/JSON: {project, color_preset?, settings?,
        timelines:[{name,fps?,settings?,markers?}], hooks?}.
      plan_spec(spec_path|spec) -> {dry_run, actions, diff, change_count} — same as apply with dry_run.
      apply_spec(spec_path|spec, dry_run?, run_hooks?, continue_on_error?) -> {success, applied, failures}
        Reconcile the project toward the spec (idempotent: re-runs are no-ops). Color/HDR
        settings are applied in dependency order; markers only added if absent. Hooks run only
        when run_hooks=true (executes shell from the spec — opt-in).
    """
    p = params or {}
    r = get_resolve()
    if r is None:
        return _err("Could not connect to DaVinci Resolve. It was not running and auto-launch failed. Check that Resolve Studio is installed.")
    pm = r.GetProjectManager()

    if action == "lint":
        return _project_lint_live(r, pm)
    if action in {"diff_to_spec", "plan_spec", "apply_spec"}:
        return _spec_action(r, pm, action, p)
    if action == "project_capabilities":
        return _project_capabilities(pm, pm.GetCurrentProject(), r)
    elif action == "probe_project_lifecycle":
        return _project_manager_snapshot(pm)
    elif action == "database_capabilities":
        return _database_capabilities(pm)
    elif action == "safe_set_current_database":
        return _safe_set_current_database(pm, p)
    elif action == "safe_project_create":
        return _safe_project_create(pm, r, p)
    elif action == "safe_project_export":
        return _safe_project_export(pm, p)
    elif action == "safe_project_import":
        return _safe_project_import(pm, p)
    elif action == "safe_project_archive":
        return _safe_project_archive(pm, p)
    elif action == "safe_project_restore":
        return _safe_project_restore(pm, p)
    elif action == "safe_project_delete":
        return _safe_project_delete(pm, p)
    elif action in {"probe_project_settings", "safe_set_project_settings", "project_settings_snapshot", "preset_lifecycle_probe", "project_boundary_report"}:
        proj = pm.GetCurrentProject()
        if not proj:
            return _err("No project open")
        if action == "probe_project_settings":
            return _probe_project_settings(proj, p)
        if action == "safe_set_project_settings":
            return _safe_set_project_settings(proj, p)
        if action == "project_settings_snapshot":
            return _project_settings_snapshot(proj, p)
        if action == "preset_lifecycle_probe":
            return _preset_lifecycle_probe(r, proj, p)
        return _project_boundary_report(r, pm, proj, p)
    elif action == "list":
        return {"projects": pm.GetProjectListInCurrentFolder()}
    elif action == "get_current":
        proj = pm.GetCurrentProject()
        return {"name": proj.GetName(), "id": proj.GetUniqueId()} if proj else _err("No project open")
    elif action == "create":
        if not p.get("name"):
            return _err("create requires name")
        media_location_path = p.get("media_location_path") or p.get("mediaLocationPath")
        if media_location_path:
            version = r.GetVersion() or [0]
            if version[0] < 20 or (version[0] == 20 and len(version) > 2 and (version[1], version[2]) < (2, 2)):
                return _err("ProjectManager.CreateProject media_location_path requires DaVinci Resolve 20.2.2+")
        proj = pm.CreateProject(p["name"], media_location_path) if media_location_path else pm.CreateProject(p["name"])
        return _ok(name=proj.GetName()) if proj else _err(f"Failed to create '{p['name']}'")
    elif action == "load":
        if not p.get("name"):
            return _err("load requires name")
        proj = pm.LoadProject(p["name"])
        return _ok() if proj else _err(f"Failed to load '{p['name']}'")
    elif action == "save":
        return {"success": bool(pm.SaveProject())}
    elif action == "close":
        proj = pm.GetCurrentProject()
        return {"success": bool(pm.CloseProject(proj))} if proj else _err("No project open")
    elif action == "delete":
        if not p.get("name"):
            return _err("delete requires name")
        from src.utils.project_cleanup import delete_project_safely
        deleted = delete_project_safely(pm, p["name"])
        return {"success": bool(deleted.get("success")), "delete_detail": deleted}
    elif action == "import_project":
        if not p.get("path"):
            return _err("import_project requires path")
        return {"success": bool(pm.ImportProject(p["path"], p.get("name")))}
    elif action == "export_project":
        err, _clean = _validate_params(p, {
            "name": {"type": str, "required": True, "non_empty": True},
            "path": {"type": str, "required": True, "non_empty": True},
        })
        if err:
            return _err(err)
        return {"success": bool(pm.ExportProject(p["name"], p["path"], p.get("with_stills_and_luts", True)))}
    elif action == "archive":
        err, _clean = _validate_params(p, {
            "name": {"type": str, "required": True, "non_empty": True},
            "path": {"type": str, "required": True, "non_empty": True},
        })
        if err:
            return _err(err)
        return {"success": bool(pm.ArchiveProject(p["name"], p["path"],
            p.get("src_media", True), p.get("render_cache", True), p.get("proxy_media", False)))}
    elif action == "restore":
        if not p.get("path"):
            return _err("restore requires path")
        return {"success": bool(pm.RestoreProject(p["path"], p.get("name")))}
    return _unknown(action, ["list","get_current","create","load","save","close","delete","import_project","export_project","archive","restore","lint","diff_to_spec","plan_spec","apply_spec", *_PROJECT_KERNEL_ACTIONS])


