@mcp.tool()
def project_settings(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Project metadata, settings, and color groups.

    Actions:
      get_name() -> {name}
      set_name(name) -> {success}
      get_setting(name?) -> {settings}  — omit name for all settings
      set_setting(name, value) -> {success}
      get_unique_id() -> {id}
      get_presets() -> {presets}
      set_preset(name) -> {success}
      refresh_luts() -> {success}
      get_gallery() -> {available}
      export_frame_as_still(path) -> {success}
      project_summary(include_clips?, clip_limit?) -> {project, current_page, timeline_count, current_timeline, media_pool}
        Live structural readout — what's in this project right now (no analysis needed).
      load_burnin_preset(name) -> {success}
      insert_audio(media_path, start_offset?, duration?) -> {success}
      get_color_groups() -> {groups}
      add_color_group(name) -> {success, name}
      delete_color_group(name) -> {success}
      apply_fairlight_preset(preset_name) -> {success}
      generate_speech(speech_generation_settings, timecode?) -> {success, new, new_id}  — Resolve 21+, AI Speech Generator; creates new audio media (confirm-gated)
    """
    p = params or {}
    _, proj, err = _check()
    if err:
        return err

    if action == "get_name":
        return {"name": proj.GetName()}
    elif action == "set_name":
        if not p.get("name"):
            return _err("set_name requires name")
        return {"success": bool(proj.SetName(p["name"]))}
    elif action == "get_setting":
        return {"settings": _ser(proj.GetSetting(p.get("name", "")))}
    elif action == "set_setting":
        if not p.get("name"):
            return _err("set_setting requires name")
        if "value" not in p:
            return _err("set_setting requires value")
        return {"success": bool(proj.SetSetting(p["name"], p["value"]))}
    elif action == "get_unique_id":
        return {"id": proj.GetUniqueId()}
    elif action == "get_presets":
        return {"presets": _ser(proj.GetPresetList())}
    elif action == "set_preset":
        return {"success": bool(proj.SetPreset(p["name"]))}
    elif action == "refresh_luts":
        return {"success": bool(proj.RefreshLUTList())}
    elif action == "get_gallery":
        g = proj.GetGallery()
        return {"available": g is not None}
    elif action == "export_frame_as_still":
        err, clean = _validate_params(p, {
            "path": {"type": str, "required": True, "non_empty": True, "parent_dir_exists": True},
        })
        if err:
            return _err(err)
        return {"success": bool(proj.ExportCurrentFrameAsStill(clean["path"]))}
    elif action == "project_summary":
        return _project_summary(
            proj,
            include_clips=bool(p.get("include_clips")),
            clip_limit=int(p.get("clip_limit", 50)),
        )
    elif action == "load_burnin_preset":
        return {"success": bool(proj.LoadBurnInPreset(p["name"]))}
    elif action == "insert_audio":
        return {"success": bool(proj.InsertAudioToCurrentTrackAtPlayhead(
            p["media_path"], p.get("start_offset", 0), p.get("duration", 0)))}
    elif action == "get_color_groups":
        groups = proj.GetColorGroupsList()
        return {"groups": [{"name": g.GetName()} for g in (groups or [])]}
    elif action == "add_color_group":
        g = proj.AddColorGroup(p["name"])
        return _ok(name=g.GetName()) if g else _err("Failed to add color group")
    elif action == "delete_color_group":
        groups = proj.GetColorGroupsList() or []
        for g in groups:
            if g.GetName() == p["name"]:
                return {"success": bool(proj.DeleteColorGroup(g))}
        return _err(f"Color group '{p['name']}' not found")
    elif action == "apply_fairlight_preset":
        missing = _requires_method(proj, "ApplyFairlightPresetToCurrentTimeline", "20.2.2")
        if missing:
            return missing
        return {"success": bool(proj.ApplyFairlightPresetToCurrentTimeline(p["preset_name"]))}
    elif action == "generate_speech":
        missing = _requires_method(proj, "GenerateSpeech", "21.0")
        if missing:
            return missing
        settings = _first_param(p, "speech_generation_settings", "speechGenerationSettings", "settings", default=None) or {}
        if not isinstance(settings, dict) or not settings.get("TextInput"):
            return _err("generate_speech requires speech_generation_settings with a 'TextInput' string. "
                        "Optional keys: VoiceModel, CustomVoiceFile, Speed, Variation, Pitch, GenerationID, Filename, AddToTimeline, AudioTrack.")
        timecode = _first_param(p, "timecode", default="") or ""
        gate = _ai_governance_gate("generate_speech", p)
        if gate:
            return gate
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="project_settings.generate_speech",
                params=p,
                preview={
                    "operation": "project_settings.generate_speech",
                    "warning": "Generates a NEW AI text-to-speech audio item"
                               + (" and adds it to the timeline." if settings.get("AddToTimeline") else "."),
                    "text_input": settings.get("TextInput"),
                    "voice_model": settings.get("VoiceModel"),
                    "add_to_timeline": bool(settings.get("AddToTimeline")),
                    "timecode": timecode,
                    "governance": _ai_governance_check("generate_speech"),
                },
            )
        blocked = _consume_confirm_token(action="project_settings.generate_speech", params=p)
        if blocked:
            return blocked
        with _ai_ledger_timed("generate_speech") as _rec:
            new_item = proj.GenerateSpeech(settings, timecode)
            _rec.success = bool(new_item)
            if new_item:
                path, nbytes = _clip_file_size(new_item)
                _rec.output_path = path
                _rec.output_bytes = nbytes
        if not new_item:
            return {"success": False}
        return {"success": True, "new": new_item.GetName(), "new_id": new_item.GetUniqueId(),
                "output_path": _rec.output_path, "output_bytes": _rec.output_bytes}
    return _unknown(action, ["get_name","set_name","get_setting","set_setting","get_unique_id","get_presets","set_preset","refresh_luts","get_gallery","export_frame_as_still","project_summary","load_burnin_preset","insert_audio","get_color_groups","add_color_group","delete_color_group","apply_fairlight_preset","generate_speech"])


