def _render_temp_path_ok(path: str) -> bool:
    if not path:
        return False
    try:
        target = os.path.abspath(path)
        temp_roots = [
            os.path.abspath(tempfile.gettempdir()),
            os.path.abspath("/private/tmp"),
            os.path.abspath("/tmp"),
        ]
        return any(os.path.commonpath([target, root]) == root for root in temp_roots)
    except ValueError:
        return False


def _render_formats(proj):
    formats = proj.GetRenderFormats() or {}
    return _ser(formats)


def _render_format_id_from_formats(formats: Any, fmt: str) -> str:
    if not isinstance(fmt, str) or not fmt or not isinstance(formats, dict):
        return fmt
    if fmt in formats:
        return formats.get(fmt) or fmt
    if fmt in formats.values():
        return fmt
    needle = fmt.lower()
    for label, format_id in formats.items():
        label_text = str(label)
        id_text = str(format_id)
        if label_text.lower() == needle:
            return id_text or fmt
        if id_text.lower() == needle:
            return id_text
    return fmt


def _render_format_id(proj, fmt: str, formats: Optional[Dict[str, Any]] = None) -> str:
    if formats is None:
        formats = _render_formats(proj)
    return _render_format_id_from_formats(formats, fmt)


def _render_format_requested(requested: Optional[List[Any]], label: str, extension: Any, format_id: str, formats: Dict[str, Any]) -> bool:
    if not requested:
        return True
    extension_text = str(extension)
    for item in requested:
        if item == label or item == extension or item == format_id:
            return True
        if isinstance(item, str) and _render_format_id_from_formats(formats, item) == format_id:
            return True
        if isinstance(item, str) and item.lower() in {label.lower(), extension_text.lower(), format_id.lower()}:
            return True
    return False


def _render_codecs(proj, fmt: str, formats: Optional[Dict[str, Any]] = None):
    try:
        return _ser(proj.GetRenderCodecs(_render_format_id(proj, fmt, formats)) or {})
    except Exception as exc:
        return {"error": str(exc)}


def _render_capabilities(proj):
    formats = _render_formats(proj)
    presets = _ser(proj.GetRenderPresetList() or [])
    quick_presets = []
    if _has_method(proj, "GetQuickExportRenderPresets"):
        try:
            quick_presets = _ser(proj.GetQuickExportRenderPresets() or [])
        except Exception:
            quick_presets = []
    return {
        "methods": _callable_method_names(proj, _RENDER_METHODS),
        "formats": formats,
        "format_count": len(formats) if isinstance(formats, dict) else 0,
        "presets": presets,
        "quick_export_presets": quick_presets,
        "supported_settings": list(_RENDER_SETTING_KEYS),
        "guards": {
            "safe_quick_export_requires_allow_render": True,
            "temp_target_required_for_lifecycle_probe": True,
            "upload_disabled_for_safe_quick_export": True,
        },
    }


def _probe_render_matrix(proj, p: Dict[str, Any]):
    formats = _render_formats(proj)
    if not isinstance(formats, dict):
        return _err("GetRenderFormats did not return a format dictionary")
    requested = p.get("formats")
    if requested is not None and not isinstance(requested, list):
        return _err("formats must be a list when provided")
    max_pairs = p.get("max_pairs")
    try:
        max_pairs = int(max_pairs) if max_pairs is not None else None
    except (TypeError, ValueError):
        return _err("max_pairs must be an integer")
    matrix = []
    pair_count = 0
    errors = []
    for fmt, extension in formats.items():
        format_id = _render_format_id_from_formats(formats, fmt)
        if not _render_format_requested(requested, fmt, extension, format_id, formats):
            continue
        codecs = _render_codecs(proj, format_id, formats)
        format_row = {"format": fmt, "extension": extension, "format_id": format_id, "codecs": [], "codec_count": 0}
        if isinstance(codecs, dict) and codecs.get("error"):
            format_row["error"] = codecs["error"]
            errors.append({"format": fmt, "error": codecs["error"]})
            matrix.append(format_row)
            continue
        if isinstance(codecs, dict):
            format_row["codec_count"] = len(codecs)
            for label, codec in codecs.items():
                if max_pairs is not None and pair_count >= max_pairs:
                    break
                row = {"label": label, "codec": codec}
                try:
                    row["resolutions"] = _ser(proj.GetRenderResolutions(format_id, codec) or [])
                    row["resolution_count"] = len(row["resolutions"])
                except Exception as exc:
                    row["error"] = str(exc)
                    errors.append({"format": fmt, "format_id": format_id, "codec": codec, "error": str(exc)})
                format_row["codecs"].append(row)
                pair_count += 1
        matrix.append(format_row)
        if max_pairs is not None and pair_count >= max_pairs:
            break
    return {
        "formats": len(matrix),
        "format_total": len(formats),
        "pairs_probed": pair_count,
        "errors": errors,
        "matrix": matrix,
    }


def _render_settings_snapshot(proj):
    if _has_method(proj, "GetRenderSettings"):
        settings = _ser(proj.GetRenderSettings())
    else:
        settings = {"error": "GetRenderSettings unavailable"}
    return {
        "format_and_codec": _ser(proj.GetCurrentRenderFormatAndCodec()),
        "mode": _ser(proj.GetCurrentRenderMode()),
        "settings": settings,
        "jobs": _ser(proj.GetRenderJobList() or []),
        "is_rendering": bool(proj.IsRenderingInProgress()),
    }


def _validate_render_settings_payload(settings: Dict[str, Any], *, require_temp_target: bool = False):
    if not isinstance(settings, dict) or not settings:
        return None, _err("settings must be a non-empty object")
    unknown = sorted(key for key in settings if key not in _RENDER_SETTING_KEYS)
    errors = []
    target_dir = settings.get("TargetDir")
    if target_dir is not None:
        if not isinstance(target_dir, str) or not target_dir:
            errors.append("TargetDir must be a non-empty string")
        elif not os.path.isdir(target_dir):
            errors.append(f"TargetDir does not exist: {target_dir}")
        elif require_temp_target and not _render_temp_path_ok(target_dir):
            errors.append("TargetDir must be under the system temp directory for this safe operation")
    elif require_temp_target:
        errors.append("TargetDir is required for this safe operation")
    for key in ("FormatWidth", "FormatHeight", "MarkIn", "MarkOut", "AudioBitDepth", "AudioSampleRate"):
        if key in settings and not isinstance(settings[key], int):
            errors.append(f"{key} must be an integer")
    for key in ("SelectAllFrames", "ExportVideo", "ExportAudio", "ExportAlpha", "MultiPassEncode", "NetworkOptimization", "ReplaceExistingFilesInPlace", "ExportSubtitle"):
        if key in settings and not isinstance(settings[key], bool):
            errors.append(f"{key} must be a boolean")
    if "MarkIn" in settings and "MarkOut" in settings and settings["MarkOut"] < settings["MarkIn"]:
        errors.append("MarkOut must be greater than or equal to MarkIn")
    result = {"valid": not errors, "unknown_keys": unknown, "errors": errors, "settings": dict(settings)}
    return result, None


def _validate_render_settings_action(p: Dict[str, Any]):
    validation, err = _validate_render_settings_payload(
        p.get("settings"),
        require_temp_target=bool(p.get("require_temp_target", False)),
    )
    if err:
        return err
    return validation


def _settings_diff(requested: Dict[str, Any], applied: Dict[str, Any]):
    if not isinstance(applied, dict):
        return {"matched": [], "coerced_or_missing": sorted(requested.keys())}
    matched = []
    coerced = {}
    for key, value in requested.items():
        if applied.get(key) == value:
            matched.append(key)
        else:
            coerced[key] = {"requested": value, "applied": applied.get(key)}
    return {"matched": sorted(matched), "coerced_or_missing": coerced}


def _safe_set_render_settings(proj, p: Dict[str, Any]):
    settings = p.get("settings")
    validation, err = _validate_render_settings_payload(
        settings,
        require_temp_target=bool(p.get("require_temp_target", False)),
    )
    if err:
        return err
    if not validation["valid"]:
        return {"success": False, "validation": validation}
    if p.get("dry_run"):
        return _ok(validation=validation)
    before = _render_settings_snapshot(proj)
    success = bool(proj.SetRenderSettings(settings))
    after_settings = _ser(proj.GetRenderSettings()) if _has_method(proj, "GetRenderSettings") else {}
    result = {
        "success": success,
        "validation": validation,
        "before": before,
        "after": after_settings,
        "diff": _settings_diff(settings, after_settings),
    }
    if p.get("restore") and isinstance(before.get("settings"), dict):
        result["restore_success"] = bool(proj.SetRenderSettings(before["settings"]))
    return result


def _prepare_render_job(proj, p: Dict[str, Any]):
    target_dir = p.get("target_dir") or (p.get("settings") or {}).get("TargetDir")
    if not target_dir:
        return _err("target_dir or settings.TargetDir is required")
    if not os.path.isdir(target_dir):
        return _err(f"target_dir does not exist: {target_dir}")
    if p.get("require_temp_target", True) and not _render_temp_path_ok(target_dir):
        return _err("target_dir must be under the system temp directory unless require_temp_target=False")
    settings = dict(p.get("settings") or {})
    settings.setdefault("TargetDir", target_dir)
    if p.get("custom_name"):
        settings["CustomName"] = p["custom_name"]
    validation, err = _validate_render_settings_payload(settings, require_temp_target=p.get("require_temp_target", True))
    if err:
        return err
    if not validation["valid"]:
        return {"success": False, "validation": validation}
    if p.get("dry_run"):
        return _ok(validation=validation, format=p.get("format"), codec=p.get("codec"))
    before = _render_settings_snapshot(proj)
    format_success = None
    if p.get("format") and p.get("codec"):
        format_success = bool(proj.SetCurrentRenderFormatAndCodec(_render_format_id(proj, p["format"]), p["codec"]))
    settings_success = bool(proj.SetRenderSettings(settings))
    job_id = proj.AddRenderJob() if settings_success else None
    return {
        "success": bool(job_id),
        "job_id": job_id,
        "format_success": format_success,
        "settings_success": settings_success,
        "before": before,
        "settings": settings,
    }


def _render_job_lifecycle_probe(proj, p: Dict[str, Any]):
    prepared = _prepare_render_job(proj, {**p, "dry_run": False, "require_temp_target": True})
    if prepared.get("error") or not prepared.get("success"):
        return prepared
    job_id = prepared["job_id"]
    status_before = _ser(proj.GetRenderJobStatus(job_id))
    delete_success = bool(proj.DeleteRenderJob(job_id))
    return {
        "success": delete_success,
        "job_id": job_id,
        "status_before_delete": status_before,
        "delete_success": delete_success,
        "prepared": prepared,
    }


def _quick_export_capabilities(proj):
    presets = []
    if _has_method(proj, "GetQuickExportRenderPresets"):
        presets = _ser(proj.GetQuickExportRenderPresets() or [])
    return {
        "presets": presets,
        "preset_count": len(presets) if isinstance(presets, list) else 0,
        "safe_params": ["TargetDir", "CustomName", "VideoQuality", "EnableUpload"],
        "guards": {
            "EnableUpload_forced_false": True,
            "allow_render_required": True,
            "temp_target_required": True,
        },
    }


def _safe_quick_export(proj, p: Dict[str, Any]):
    preset = p.get("preset")
    if not preset:
        return _err("preset is required")
    params = dict(p.get("params") or {})
    target_dir = params.get("TargetDir") or p.get("target_dir")
    if target_dir:
        params["TargetDir"] = target_dir
    if p.get("custom_name"):
        params["CustomName"] = p["custom_name"]
    params["EnableUpload"] = False
    validation, err = _validate_render_settings_payload(
        {key: value for key, value in params.items() if key in _RENDER_SETTING_KEYS},
        require_temp_target=bool(p.get("require_temp_target", True)),
    )
    if err:
        return err
    if not validation["valid"]:
        return {"success": False, "validation": validation}
    if p.get("dry_run") or not p.get("allow_render", False):
        return _ok(would_render=False, preset=preset, params=params, validation=validation)
    status = _ser(proj.RenderWithQuickExport(preset, params))
    return {"success": not (isinstance(status, dict) and status.get("error")), "status": status, "params": params}


def _export_render_boundary_report(proj, p: Dict[str, Any]):
    report = {
        "capabilities": _render_capabilities(proj),
        "settings": _render_settings_snapshot(proj),
    }
    if p.get("include_matrix", True):
        report["matrix"] = _probe_render_matrix(proj, {"max_pairs": p.get("max_pairs")})
    if p.get("include_quick_export", True):
        report["quick_export"] = _quick_export_capabilities(proj)
    return report


@mcp.tool()
def render(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Render pipeline: jobs, presets, formats, codecs, and rendering.

    Actions:
      add_job() -> {job_id}
      delete_job(job_id) -> {success}
      delete_all_jobs() -> {success}
      list_jobs() -> {jobs}
      get_job_status(job_id) -> {status}
      start(job_ids?, interactive?) -> {success}
      stop() -> {success}
      is_rendering() -> {rendering}
      get_formats() -> {formats}
      get_codecs(format) -> {codecs}
      get_format_and_codec() -> {format, codec}
      set_format_and_codec(format, codec) -> {success}
      get_mode() -> {mode}
      set_mode(mode) -> {success}
      get_resolutions(format, codec) -> {resolutions}
      get_settings() -> {settings}  (alias for set_render_settings with get)
      set_settings(settings) -> {success}
      list_presets() -> {presets}
      load_preset(name) -> {success}
      save_preset(name) -> {success}
      delete_preset(name) -> {success}
      quick_export_presets() -> {presets}
      quick_export(preset, params?) -> {status}
      render_capabilities() -> {methods, formats, presets, quick_export_presets}
      probe_render_matrix(formats?, max_pairs?) -> {matrix, errors}
      probe_render_settings() -> {format_and_codec, mode, settings, jobs, is_rendering}
      validate_render_settings(settings, require_temp_target?) -> {valid, errors, unknown_keys}
      safe_set_render_settings(settings, dry_run?, restore?, require_temp_target?) -> {success, diff}
      prepare_render_job(target_dir, settings?, format?, codec?, custom_name?, dry_run?) -> {success, job_id}
      render_job_lifecycle_probe(target_dir, settings?, format?, codec?, custom_name?) -> {success, job_id, status_before_delete}
      quick_export_capabilities() -> {presets, safe_params, guards}
      safe_quick_export(preset, target_dir?|params?, custom_name?, dry_run?, allow_render?) -> {success, status}
      export_render_boundary_report(include_matrix?, max_pairs?, include_quick_export?) -> {capabilities, settings, matrix?}
    """
    p = params or {}
    _, proj, err = _check()
    if err:
        return err

    if action == "add_job":
        jid = proj.AddRenderJob()
        return {"job_id": jid} if jid else _err("Failed to add render job")
    elif action == "delete_job":
        return {"success": bool(proj.DeleteRenderJob(p["job_id"]))}
    elif action == "delete_all_jobs":
        return {"success": bool(proj.DeleteAllRenderJobs())}
    elif action == "list_jobs":
        return {"jobs": _ser(proj.GetRenderJobList())}
    elif action == "get_job_status":
        return _ser(proj.GetRenderJobStatus(p["job_id"]))
    elif action == "start":
        job_ids = p.get("job_ids")
        interactive = p.get("interactive", False)
        if job_ids:
            return {"success": bool(proj.StartRendering(job_ids, interactive))}
        return {"success": bool(proj.StartRendering(interactive))}
    elif action == "stop":
        proj.StopRendering()
        return _ok()
    elif action == "is_rendering":
        return {"rendering": bool(proj.IsRenderingInProgress())}
    elif action == "get_formats":
        return {"formats": _ser(proj.GetRenderFormats())}
    elif action == "get_codecs":
        return {"codecs": _render_codecs(proj, p["format"])}
    elif action == "get_format_and_codec":
        return _ser(proj.GetCurrentRenderFormatAndCodec())
    elif action == "set_format_and_codec":
        return {"success": bool(proj.SetCurrentRenderFormatAndCodec(_render_format_id(proj, p["format"]), p["codec"]))}
    elif action == "get_mode":
        return {"mode": proj.GetCurrentRenderMode()}
    elif action == "set_mode":
        return {"success": bool(proj.SetCurrentRenderMode(p["mode"]))}
    elif action == "get_resolutions":
        return {"resolutions": _ser(proj.GetRenderResolutions(_render_format_id(proj, p["format"]), p["codec"]))}
    elif action == "get_settings":
        missing = _requires_method(proj, "GetRenderSettings", "unknown")
        if missing:
            return missing
        return {"settings": _ser(proj.GetRenderSettings())}
    elif action == "set_settings":
        if "settings" not in p or not isinstance(p["settings"], dict):
            return _err("set_settings requires a settings object")
        # Whitelist to documented keys; SetRenderSettings silently ignores unknown
        # keys, so a typo'd setting would be dropped with no signal (P1 #6).
        settings, ignored_settings = _filter_to_keys(p["settings"], _RENDER_SETTING_KEYS)
        result = {"success": bool(proj.SetRenderSettings(settings))}
        if ignored_settings:
            result["ignored_settings"] = ignored_settings
        return result
    elif action == "list_presets":
        return {"presets": proj.GetRenderPresetList()}
    elif action == "load_preset":
        return {"success": bool(proj.LoadRenderPreset(p["name"]))}
    elif action == "save_preset":
        return {"success": bool(proj.SaveAsNewRenderPreset(p["name"]))}
    elif action == "delete_preset":
        return {"success": bool(proj.DeleteRenderPreset(p["name"]))}
    elif action == "quick_export_presets":
        return {"presets": proj.GetQuickExportRenderPresets()}
    elif action == "quick_export":
        if "preset" not in p:
            return _err("quick_export requires a preset")
        # Whitelist the documented quick-export params (unknown keys silently
        # ignored by Resolve) (P1 #23).
        qe_params, ignored_params = _filter_to_keys(
            p.get("params", {}), {"TargetDir", "CustomName", "VideoQuality", "EnableUpload"}
        )
        out = _ser(proj.RenderWithQuickExport(p["preset"], qe_params))
        if ignored_params and isinstance(out, dict):
            out["ignored_params"] = ignored_params
        return out
    elif action == "render_capabilities":
        return _render_capabilities(proj)
    elif action == "probe_render_matrix":
        return _probe_render_matrix(proj, p)
    elif action == "probe_render_settings":
        return _render_settings_snapshot(proj)
    elif action == "validate_render_settings":
        return _validate_render_settings_action(p)
    elif action == "safe_set_render_settings":
        return _safe_set_render_settings(proj, p)
    elif action == "prepare_render_job":
        return _prepare_render_job(proj, p)
    elif action == "render_job_lifecycle_probe":
        return _render_job_lifecycle_probe(proj, p)
    elif action == "quick_export_capabilities":
        return _quick_export_capabilities(proj)
    elif action == "safe_quick_export":
        return _safe_quick_export(proj, p)
    elif action == "export_render_boundary_report":
        return _export_render_boundary_report(proj, p)
    return _unknown(action, ["add_job","delete_job","delete_all_jobs","list_jobs","get_job_status","start","stop","is_rendering","get_formats","get_codecs","get_format_and_codec","set_format_and_codec","get_mode","set_mode","get_resolutions","get_settings","set_settings","list_presets","load_preset","save_preset","delete_preset","quick_export_presets","quick_export",*_RENDER_KERNEL_ACTIONS])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 10: media_storage
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
def media_storage(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Browse storage volumes and import media into the Media Pool.

    Actions:
      get_volumes() -> {volumes}
      get_subfolders(path) -> {subfolders}
      get_files(path) -> {files}
      reveal(path) -> {success}
      import_to_pool(items) -> {imported}
        — simple: params.items is a list of absolute file/folder paths
      import_to_pool(item_infos) -> {imported}
        — positioned: params.item_infos is a list of {media, startFrame, endFrame}
          dicts per docs line 210. Mirrors MediaStorage.AddItemListToMediaPool([{itemInfo}, ...]).
      add_clip_mattes(clip_id, paths, stereo_eye?) -> {success}
      add_timeline_mattes(paths) -> {items}
    """
    p = params or {}
    r = get_resolve()
    if r is None:
        return _err("Could not connect to DaVinci Resolve. It was not running and auto-launch failed. Check that Resolve Studio is installed.")
    ms = r.GetMediaStorage()

    if action == "get_volumes":
        return {"volumes": ms.GetMountedVolumeList()}
    elif action == "get_subfolders":
        return {"subfolders": ms.GetSubFolderList(p["path"])}
    elif action == "get_files":
        return {"files": ms.GetFileList(p["path"])}
    elif action == "reveal":
        return {"success": bool(ms.RevealInStorage(p["path"]))}
    elif action == "import_to_pool":
        if p.get("item_infos") is not None:
            raw = p["item_infos"]
            if not isinstance(raw, list) or not raw:
                return _err("item_infos must be a non-empty list")
            for i, info in enumerate(raw):
                if not isinstance(info, dict):
                    return _err(f"item_infos[{i}] must be an object")
                if not info.get("media"):
                    return _err(f"item_infos[{i}] requires media (file path)")
            result = ms.AddItemListToMediaPool(raw)
        else:
            items = p.get("items")
            if not items:
                return _err("Provide items (simple) or item_infos (positioned)")
            result = ms.AddItemListToMediaPool(items)
        return {"imported": len(result) if result else 0}
    elif action == "add_clip_mattes":
        _, proj, mp, err = _get_mp()
        if err:
            return err
        clip = _find_clip(mp.GetRootFolder(), p["clip_id"])
        if not clip:
            return _err(f"Clip not found: {p['clip_id']}")
        eye = p.get("stereo_eye", "")
        return {"success": bool(ms.AddClipMattesToMediaPool(clip, p["paths"], eye))}
    elif action == "add_timeline_mattes":
        result = ms.AddTimelineMattesToMediaPool(p["paths"])
        return {"items": len(result) if result else 0}
    return _unknown(action, ["get_volumes","get_subfolders","get_files","reveal","import_to_pool","add_clip_mattes","add_timeline_mattes"])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 11: media_pool
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
@_destructive_op("media_pool")
def media_pool(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Manage the Media Pool: folders, clips, timelines, import/export.

    PREFER safe_* / probe_* / *_capabilities / *_boundary_report / *_checked variants where they
    exist. Raw mutators below do not validate paths, support dry_run, or normalize errors.

    Actions:
      get_root_folder() -> {name, id}
      get_current_folder() -> {name, id}
      set_current_folder(path) -> {success}  — path like "Master/SubFolder"
      add_subfolder(name, parent_path?) -> {success, name, id}
      delete_folders(folder_ids) -> {success}
        DESTRUCTIVE. Deletes folders + every clip they contain.
      move_folders(folder_ids, target_path) -> {success}
      refresh() -> {success}
      create_timeline(name, if_exists?) -> {success, name, id}
        — if_exists: version (default), reuse, or fail
      create_timeline_from_clips(name, clip_ids, if_exists?) -> {success, name, id}
        — simple: params.clip_ids appends clips end-to-end into a new timeline
      create_timeline_from_clips(name, clip_infos, if_exists?) -> {success, name, id}
        — positioned: params.clip_infos is a list of {clip_id or media_pool_item_id,
          start_frame & end_frame (or startFrame/endFrame), record_frame/recordFrame}.
          record_frame is relative to the created timeline start frame by default;
          pass record_frame_mode="absolute" for raw Resolve recordFrame values.
      setup_multicam_timeline(name, clip_ids|angles, sync_mode?, include_audio?, dry_run?) -> {success}
        — creates a stacked multicam prep timeline: one angle per video track, optional
          matching audio tracks. Native multicam clip conversion remains a Resolve UI step.
      import_timeline(path, options?) -> {success, name}
        UNSAFE. No path sandboxing. Prefer timeline.import_timeline_checked.
      delete_timelines(timeline_ids) -> {success}
        CATASTROPHIC. Deletes timelines outright.
      append_to_timeline(clip_ids) -> {success, count}
        — legacy: params.clip_ids only (appends at end / default placement)
      append_to_timeline(clip_infos) -> {success, count, items}
        — positioned: params.clip_infos is a list of {clip_id or media_pool_item_id,
          start_frame & end_frame (or startFrame/endFrame), record_frame/recordFrame,
          track_index/trackIndex (1-based), optional media_type/mediaType (1=video, 2=audio)}.
          record_frame is relative to the current timeline start frame by default;
          pass record_frame_mode="absolute" for raw Resolve recordFrame values.
          Returns timeline_item_id per item.
      import_media(paths) -> {imported}
        UNSAFE. No dry_run. Prefer safe_import_media.
        — simple: params.paths is a list of file/folder paths
      import_media(clip_infos) -> {imported}
        UNSAFE. No dry_run. Prefer safe_import_sequence.
        — image sequences: params.clip_infos is a list of
          {FilePath, StartIndex, EndIndex} dicts (PascalCase keys per Resolve docs).
          Example: [{"FilePath": "frame_%03d.dpx", "StartIndex": 1, "EndIndex": 100}]
      delete_clips(clip_ids) -> {success}
        DESTRUCTIVE. Removes clips from the Media Pool (does not touch source files).
      move_clips(clip_ids, target_path) -> {success}
      relink(clip_ids, folder_path) -> {success}
        UNSAFE. No dry_run. Prefer safe_relink.
      unlink(clip_ids) -> {success}
        UNSAFE. No dry_run. Prefer safe_unlink.
      export_metadata(path, clip_ids?) -> {success}
      get_unique_id() -> {id}
      create_stereo_clip(left_id, right_id) -> {success, name}
      auto_sync_audio(clip_ids, settings?) -> {success}
      get_selected() -> {clips}
      set_selected(clip_id) -> {success}
      get_clip_mattes(clip_id) -> {mattes}
      get_timeline_mattes(folder_path?) -> {mattes}
      delete_clip_mattes(clip_id, paths) -> {success}
      import_folder(path, source_clips_path?) -> {success}
      ingest_capabilities() -> {supported, partially_supported, unsupported}
      probe_media_pool(depth?) -> {media_pool_id, methods, root, current_folder, selected_clips}
      probe_ingest_item(clip_ids? selected?) -> {items, count}
      safe_import_media(paths, target_folder?, dry_run?) -> {success, imported, clips}
      safe_import_sequence(FilePath|file_path|pattern, StartIndex?, EndIndex?, target_folder?, dry_run?) -> {success, imported, clips}
      safe_import_folder(path, source_clips_path?, dry_run?) -> {success}
      organize_clips(clip_ids|selected, target_path, create_missing?, dry_run?) -> {success}
      copy_metadata(source_clip_id, target_clip_ids, keys?, include_third_party?, dry_run?) -> {success, results}
      normalize_metadata(clip_ids|selected, metadata?, third_party_metadata?, dry_run?) -> {success, results}
      probe_clip_properties(clip_ids|selected) -> {items, count}
      metadata_field_inventory(clip_ids|selected, include_values?) -> {items, ui_group_names}
      safe_relink(clip_ids|selected, folder_path, dry_run?) -> {success}
      safe_unlink(clip_ids|selected, dry_run?) -> {success}
      check_proxy_media_compatibility(clip_id, proxy_path|path, expected_codec?, expected_profile?) -> {compatible, mismatches}
      link_proxy_checked(clip_id, proxy_path|path, dry_run?, check_compatibility?, require_compatible?, expected_codec?, expected_profile?) -> {success}
      link_full_resolution_checked(clip_id, path|full_res_media_path, dry_run?) -> {success}
      set_clip_marks(clip_ids|selected, mark_in, mark_out, type?, dry_run?) -> {success, results}
      clear_clip_marks(clip_ids|selected, type?, dry_run?) -> {success, results}
      copy_clip_annotations(source_clip_id, target_clip_ids, include_markers?, include_flags?, include_clip_color?, dry_run?) -> {success, results}
      media_pool_boundary_report(depth?, clip_ids?, selected?) -> {capabilities, media_pool, items?}
    """
    p = params or {}
    _, proj, mp, err = _get_mp()
    if err:
        return err
    root = mp.GetRootFolder()

    if action == "get_root_folder":
        return {"name": root.GetName(), "id": root.GetUniqueId()}
    elif action == "get_current_folder":
        f = mp.GetCurrentFolder()
        return {"name": f.GetName(), "id": f.GetUniqueId()} if f else _err("No current folder")
    elif action == "set_current_folder":
        f = _navigate_folder(mp, p.get("path", ""))
        if not f:
            return _err(f"Folder not found: {p.get('path')}")
        return {"success": bool(mp.SetCurrentFolder(f))}
    elif action == "add_subfolder":
        parent = _navigate_folder(mp, p.get("parent_path", "")) or mp.GetCurrentFolder()
        f = mp.AddSubFolder(parent, p["name"])
        return _ok(name=f.GetName(), id=f.GetUniqueId()) if f else _err("Failed to create subfolder")
    elif action == "delete_folders":
        folders = []
        for fid in p["folder_ids"]:
            # Search for folder by ID (simplified - searches root subfolders)
            for sub in (root.GetSubFolderList() or []):
                if sub.GetUniqueId() == fid:
                    folders.append(sub)
        if not folders:
            return _err("No folders found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_folders", params=p,
                preview={"operation": "media_pool.delete_folders",
                         "warning": "Permanently deletes folders AND every clip they contain.",
                         "folders_lost": len(folders),
                         "names": [_clip_name(f) for f in folders][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_folders", params=p)
        if blocked:
            return blocked
        return {"success": bool(mp.DeleteFolders(folders))}
    elif action == "move_folders":
        target = _navigate_folder(mp, p["target_path"])
        if not target:
            return _err(f"Target folder not found: {p['target_path']}")
        folders = []
        for fid in p["folder_ids"]:
            for sub in (root.GetSubFolderList() or []):
                if sub.GetUniqueId() == fid:
                    folders.append(sub)
        return {"success": bool(mp.MoveFolders(folders, target))}
    elif action == "refresh":
        return {"success": bool(mp.RefreshFolders())}
    elif action == "create_timeline":
        create_name, existing, policy_result = _resolve_timeline_create_policy(proj, p)
        if policy_result:
            return policy_result
        tl = mp.CreateEmptyTimeline(create_name)
        return _ok(
            name=tl.GetName(),
            id=tl.GetUniqueId(),
            requested_name=p.get("name"),
            created_new=True,
            versioned_name=bool(existing and create_name != p.get("name")),
        ) if tl else _err("Failed to create timeline")
    elif action == "create_timeline_from_clips":
        create_name, existing, policy_result = _resolve_timeline_create_policy(proj, p)
        if policy_result:
            return policy_result
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list):
                return _err("clip_infos must be a list")
            if not raw:
                return _err("clip_infos must be a non-empty list")
            for i, ci in enumerate(raw):
                _, row_err = _build_create_clip_info_dict(root, ci, i)
                if row_err:
                    return row_err
            tl = mp.CreateEmptyTimeline(create_name)
            if not tl:
                return _err("Failed to create timeline from clip_infos")
            try:
                proj.SetCurrentTimeline(tl)
            except Exception:
                pass
            timeline_start = _timeline_start_frame(tl)
            built = []
            for i, ci in enumerate(raw):
                append_ci = dict(ci)
                append_ci.setdefault("track_index", append_ci.get("trackIndex", 1))
                row, row_err = _build_append_clip_info_dict(root, append_ci, i, timeline_start)
                if row_err:
                    return row_err
                built.append(row)
            appended = mp.AppendToTimeline(built)
            if not appended:
                return _err("Failed to append clip_infos to created timeline")
            return _ok(
                name=tl.GetName(),
                id=tl.GetUniqueId(),
                requested_name=p.get("name"),
                created_new=True,
                versioned_name=bool(existing and create_name != p.get("name")),
            )
        clip_ids = p.get("clip_ids")
        if not clip_ids:
            return _err("Provide clip_ids (simple) or clip_infos (positioned)")
        clips = [_find_clip(root, cid) for cid in clip_ids]
        clips = [c for c in clips if c]
        if not clips:
            return _err("No valid clips found")
        tl = mp.CreateTimelineFromClips(create_name, clips)
        return _ok(
            name=tl.GetName(),
            id=tl.GetUniqueId(),
            requested_name=p.get("name"),
            created_new=True,
            versioned_name=bool(existing and create_name != p.get("name")),
        ) if tl else _err("Failed to create timeline")
    elif action == "setup_multicam_timeline":
        return _setup_multicam_timeline(proj, mp, p)
    elif action == "import_timeline":
        # Whitelist options to the documented keys; Resolve silently ignores
        # unknown keys, so a typo would be dropped with no signal (P1 #4).
        options, ignored_opts = _filter_to_keys(p.get("options", {}), _IMPORT_TIMELINE_OPTION_KEYS)
        with long_resolve_op("media_pool.import_timeline"):
            tl = mp.ImportTimelineFromFile(p["path"], options)
        if not tl:
            return _err("Failed to import timeline")
        result = _ok(name=tl.GetName())
        if ignored_opts:
            result["ignored_options"] = ignored_opts
        return result
    elif action == "delete_timelines":
        count = proj.GetTimelineCount()
        timelines = []
        for i in range(1, count + 1):
            tl = proj.GetTimelineByIndex(i)
            if tl and tl.GetUniqueId() in p["timeline_ids"]:
                timelines.append(tl)
        if not timelines:
            return _err("No timelines found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_timelines", params=p,
                preview={"operation": "media_pool.delete_timelines",
                         "warning": "Permanently deletes timelines.",
                         "timelines_lost": len(timelines),
                         "names": [t.GetName() for t in timelines][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_timelines", params=p)
        if blocked:
            return blocked
        # Read-back: DeleteTimelines' bool is unreliable; verify by the project's
        # timeline count dropping (P2).
        before_n = proj.GetTimelineCount()
        raw = bool(mp.DeleteTimelines(timelines))
        after_n = proj.GetTimelineCount()
        return {"success": raw, "verified": after_n < before_n,
                "timelines_before": before_n, "timelines_after": after_n}
    elif action == "append_to_timeline":
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list):
                return _err("clip_infos must be a list")
            if not raw:
                return _err("clip_infos must be a non-empty list")
            timeline_start = _timeline_start_frame(proj.GetCurrentTimeline())
            built = []
            for i, ci in enumerate(raw):
                row, row_err = _build_append_clip_info_dict(root, ci, i, timeline_start)
                if row_err:
                    return row_err
                built.append(row)
            requested = {
                "mode": "clip_infos",
                "clip_info_count": len(raw),
                "expected_count": len(built),
            }
            result, verification, before = _append_to_timeline_with_verification(
                proj,
                mp,
                built,
                requested,
                len(built),
            )
            if not result:
                return _err("Failed to append clip_infos to timeline")
            items_out = []
            for i, item in enumerate(result):
                item_out, item_err = _serialize_appended_timeline_item(item, i)
                if item_err:
                    return item_err
                items_out.append(item_out)
            out = _ok(count=len(result), items=items_out)
            out["verified_operation"] = _append_to_timeline_verified_operation(
                requested,
                verification,
                before,
            )
            return out
        clip_ids = p.get("clip_ids")
        if not clip_ids:
            return _err("Provide clip_ids (simple append) or clip_infos (positioned append)")
        clips = [_find_clip(root, cid) for cid in clip_ids]
        clips = [c for c in clips if c]
        requested = {
            "mode": "clip_ids",
            "clip_ids": list(clip_ids),
            "resolved_clip_count": len(clips),
            "expected_count": len(clips),
        }
        result, verification, before = _append_to_timeline_with_verification(
            proj,
            mp,
            clips,
            requested,
            len(clips),
        )
        out = _ok(count=len(result) if result else 0)
        out["verified_operation"] = _append_to_timeline_verified_operation(
            requested,
            verification,
            before,
        )
        return out
    elif action == "import_media":
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list) or not raw:
                return _err("clip_infos must be a non-empty list")
            for i, ci in enumerate(raw):
                if not isinstance(ci, dict):
                    return _err(f"clip_infos[{i}] must be an object")
                if not ci.get("FilePath"):
                    return _err(f"clip_infos[{i}] requires FilePath")
            result = mp.ImportMedia(raw)
        else:
            paths = p.get("paths")
            if not paths:
                return _err("Provide paths (simple) or clip_infos (image sequences)")
            result = mp.ImportMedia(paths)
        return {"imported": len(result) if result else 0}
    elif action == "delete_clips":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        if not clips:
            return _err("No clips found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_clips", params=p,
                preview={"operation": "media_pool.delete_clips",
                         "warning": "Permanently deletes Media Pool clips.",
                         "clips_lost": len(clips),
                         "names": [_clip_name(c) for c in clips][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_clips", params=p)
        if blocked:
            return blocked
        return {"success": bool(mp.DeleteClips(clips))}
    elif action == "move_clips":
        target = _navigate_folder(mp, p["target_path"])
        if not target:
            return _err(f"Target folder not found: {p['target_path']}")
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.MoveClips(clips, target))}
    elif action == "relink":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.RelinkClips(clips, p["folder_path"]))}
    elif action == "unlink":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.UnlinkClips(clips))}
    elif action == "export_metadata":
        clip_ids = p.get("clip_ids")
        if clip_ids:
            clips = [_find_clip(root, cid) for cid in clip_ids]
            clips = [c for c in clips if c]
            return {"success": bool(mp.ExportMetadata(p["path"], clips))}
        return {"success": bool(mp.ExportMetadata(p["path"]))}
    elif action == "get_unique_id":
        return {"id": mp.GetUniqueId()}
    elif action == "create_stereo_clip":
        left = _find_clip(root, p["left_id"])
        right = _find_clip(root, p["right_id"])
        if not left or not right:
            return _err("Left or right clip not found")
        result = mp.CreateStereoClip(left, right)
        return _ok(name=result.GetName()) if result else _err("Failed to create stereo clip")
    elif action == "auto_sync_audio":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        # Normalize string settings into live AUDIO_SYNC_* enum keys; passing raw
        # human-readable keys makes AutoSyncAudio silently reject the call.
        settings, ignored = _normalize_auto_sync_settings(dict(p.get("settings") or {}), get_resolve())
        result = {"success": bool(mp.AutoSyncAudio(clips, settings))}
        if ignored:
            result["ignored_settings"] = ignored
        return result
    elif action == "get_selected":
        sel = mp.GetSelectedClips()
        if not sel:
            return {"clips": []}
        return {"clips": [{"name": c.GetName(), "id": c.GetUniqueId()} for c in sel]}
    elif action == "set_selected":
        clip = _find_clip(root, p["clip_id"])
        return {"success": bool(mp.SetSelectedClip(clip))} if clip else _err("Clip not found")
    elif action == "get_clip_mattes":
        clip = _find_clip(root, p["clip_id"])
        return {"mattes": mp.GetClipMatteList(clip)} if clip else _err("Clip not found")
    elif action == "get_timeline_mattes":
        folder = _navigate_folder(mp, p.get("folder_path", "")) or mp.GetCurrentFolder()
        result = mp.GetTimelineMatteList(folder)
        return {"mattes": len(result) if result else 0}
    elif action == "delete_clip_mattes":
        clip = _find_clip(root, p["clip_id"])
        if not clip:
            return _err("Clip not found")
        return {"success": bool(mp.DeleteClipMattes(clip, p["paths"]))}
    elif action == "import_folder":
        if not p.get("path"):
            return _err("import_folder requires path")
        return {"success": bool(mp.ImportFolderFromFile(p["path"], p.get("source_clips_path", "")))}
    elif action == "ingest_capabilities":
        return _media_pool_ingest_capabilities()
    elif action == "probe_media_pool":
        return _media_pool_probe(mp, p)
    elif action == "probe_ingest_item":
        return _media_pool_probe_ingest_items(mp, p)
    elif action == "safe_import_media":
        return _safe_import_media(mp, p)
    elif action == "safe_import_sequence":
        return _safe_import_sequence(mp, p)
    elif action == "safe_import_folder":
        return _safe_import_folder(mp, p)
    elif action == "organize_clips":
        return _organize_clips(mp, root, p)
    elif action == "copy_metadata":
        return _copy_metadata(root, p)
    elif action == "normalize_metadata":
        return _normalize_metadata(root, mp, p)
    elif action == "probe_clip_properties":
        return _probe_clip_properties(root, mp, p)
    elif action == "metadata_field_inventory":
        return _metadata_field_inventory(root, mp, p)
    elif action == "safe_relink":
        return _safe_relink(mp, root, p)
    elif action == "safe_unlink":
        return _safe_unlink(mp, root, p)
    elif action == "check_proxy_media_compatibility":
        return _check_proxy_media_compatibility_checked(root, p)
    elif action == "link_proxy_checked":
        return _link_proxy_checked(root, p)
    elif action == "link_full_resolution_checked":
        return _link_full_resolution_checked(root, p)
    elif action == "set_clip_marks":
        return _set_clip_marks(root, mp, p)
    elif action == "clear_clip_marks":
        return _clear_clip_marks(root, mp, p)
    elif action == "copy_clip_annotations":
        return _copy_clip_annotations(root, p)
    elif action == "media_pool_boundary_report":
        return _media_pool_boundary_report(mp, p)
    return _unknown(action, ["get_root_folder","get_current_folder","set_current_folder","add_subfolder","delete_folders","move_folders","refresh","create_timeline","create_timeline_from_clips","import_timeline","delete_timelines","append_to_timeline","import_media","delete_clips","move_clips","relink","unlink","export_metadata","get_unique_id","create_stereo_clip","auto_sync_audio","get_selected","set_selected","get_clip_mattes","get_timeline_mattes","delete_clip_mattes","import_folder",*_MEDIA_POOL_KERNEL_ACTIONS])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 12: folder
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
def folder(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Operations on Media Pool folders.

    Actions:
      get_clips(path?) -> {clips}  — path like "Master/SubFolder", omit for current
      get_name(path?) -> {name}
      get_subfolders(path?) -> {subfolders}
      is_stale(path?) -> {stale}
      get_unique_id(path?) -> {id}
      export(path?, export_path) -> {success}
      transcribe_audio(path?, use_speaker_detection?) -> {success}  — use_speaker_detection is Resolve 21+
      clear_transcription(path?) -> {success}
      perform_audio_classification(path?) -> {success}  — Resolve 21+
      clear_audio_classification(path?) -> {success}  — Resolve 21+
      analyze_for_intellisearch(path?, identify_faces?, is_better_mode?) -> {success}  — Resolve 21+, AI IntelliSearch Extra
      analyze_for_slate(path?, marker_color?) -> {success}  — Resolve 21+, AI Slate ID Extra
      remove_motion_blur(path?, deblur_option?) -> {success, created}  — Resolve 21+; renders NEW media (confirm-gated)
    """
    p = params or {}
    _, _, mp, err = _get_mp()
    if err:
        return err

    folder_path = p.get("path", "")
    f = _navigate_folder(mp, folder_path) if folder_path else mp.GetCurrentFolder()
    if not f:
        return _err(f"Folder not found: {folder_path}")

    if action == "get_clips":
        clips = f.GetClipList() or []
        return {"clips": [{"name": c.GetName(), "id": c.GetUniqueId()} for c in clips]}
    elif action == "get_name":
        return {"name": f.GetName()}
    elif action == "get_subfolders":
        subs = f.GetSubFolderList() or []
        return {"subfolders": [{"name": s.GetName(), "id": s.GetUniqueId()} for s in subs]}
    elif action == "is_stale":
        return {"stale": bool(f.GetIsFolderStale())}
    elif action == "get_unique_id":
        return {"id": f.GetUniqueId()}
    elif action == "export":
        return {"success": bool(f.Export(p["export_path"]))}
    elif action == "transcribe_audio":
        usd = _first_param(p, "use_speaker_detection", "useSpeakerDetection")
        if usd is None:
            with long_resolve_op("folder.transcribe_audio"):
                return {"success": bool(f.TranscribeAudio())}
        with long_resolve_op("folder.transcribe_audio"):
            return {"success": bool(f.TranscribeAudio(bool(usd)))}
    elif action == "clear_transcription":
        return {"success": bool(f.ClearTranscription())}
    elif action == "perform_audio_classification":
        missing = _requires_method(f, "PerformAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("perform_audio_classification") as _rec:
            ok = bool(f.PerformAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "clear_audio_classification":
        missing = _requires_method(f, "ClearAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("clear_audio_classification") as _rec:
            ok = bool(f.ClearAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_intellisearch":
        missing = _requires_method(f, "AnalyzeForIntellisearch", "21.0")
        if missing:
            return missing
        identify_faces = bool(_first_param(p, "identify_faces", "identifyFaces", default=False))
        is_better_mode = bool(_first_param(p, "is_better_mode", "isBetterMode", default=False))
        with _ai_ledger_timed("analyze_for_intellisearch") as _rec:
            ok = bool(f.AnalyzeForIntellisearch(identify_faces, is_better_mode))
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_slate":
        missing = _requires_method(f, "AnalyzeForSlate", "21.0")
        if missing:
            return missing
        marker_color = _first_param(p, "marker_color", "markerColor", default="Blue")
        if marker_color not in _MARKER_COLORS:
            return _err(f"Invalid marker_color {marker_color!r}. Valid colors: {', '.join(_MARKER_COLORS)}")
        with _ai_ledger_timed("analyze_for_slate") as _rec:
            ok = bool(f.AnalyzeForSlate(marker_color))
            _rec.success = ok
        return {"success": ok}
    elif action == "remove_motion_blur":
        missing = _requires_method(f, "RemoveMotionBlur", "21.0")
        if missing:
            return missing
        deblur = _first_param(p, "deblur_option", "deblurOption", default=None) or {}
        gate = _ai_governance_gate("remove_motion_blur", p)
        if gate:
            return gate
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="folder.remove_motion_blur",
                params=p,
                preview={
                    "operation": "folder.remove_motion_blur",
                    "warning": "Renders NEW deblurred media files for clips in the folder; source media is not modified.",
                    "folder": f.GetName(),
                    "deblur_option": deblur,
                    "governance": _ai_governance_check("remove_motion_blur"),
                },
            )
        blocked = _consume_confirm_token(action="folder.remove_motion_blur", params=p)
        if blocked:
            return blocked
        with _ai_ledger_timed("remove_motion_blur") as _rec:
            result = f.RemoveMotionBlur(deblur)
            _rec.success = bool(result)
            created = []
            total_bytes = 0
            for pair in (result or []):
                try:
                    orig, new = pair
                    path, nbytes = _clip_file_size(new)
                    if nbytes:
                        total_bytes += nbytes
                    created.append({"original": orig.GetName(), "new": new.GetName(),
                                    "new_id": new.GetUniqueId(), "output_path": path, "output_bytes": nbytes})
                except Exception:
                    continue
            # Folder deblur creates many files; record the first path + summed bytes.
            if created:
                _rec.output_path = created[0].get("output_path")
                _rec.output_bytes = total_bytes or None
        return {"success": bool(result), "created": created}
    return _unknown(action, ["get_clips","get_name","get_subfolders","is_stale","get_unique_id","export","transcribe_audio","clear_transcription","perform_audio_classification","clear_audio_classification","analyze_for_intellisearch","analyze_for_slate","remove_motion_blur"])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 13: media_pool_item
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
def media_pool_item(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Operations on a media pool clip. Identify clip by clip_id.

    Actions:
      get_name(clip_id) -> {name}
      get_metadata(clip_id, key?) -> {metadata}
      set_metadata(clip_id, key, value) OR set_metadata(clip_id, metadata) -> {success}
      get_third_party_metadata(clip_id, key?) -> {metadata}
      set_third_party_metadata(clip_id, key, value) -> {success}
      get_media_id(clip_id) -> {media_id}
      get_clip_property(clip_id, key?) -> {properties}
      set_clip_property(clip_id, key, value) -> {success}
      get_clip_color(clip_id) -> {color}
      set_clip_color(clip_id, color) -> {success}
      clear_clip_color(clip_id) -> {success}
      link_proxy(clip_id, proxy_path) -> {success}
      unlink_proxy(clip_id) -> {success}
      replace_clip(clip_id, path) -> {success}
      set_name(clip_id, name) -> {success}
      link_full_resolution_media(clip_id, path) -> {success}
      monitor_growing_file(clip_id) -> {success}
      replace_clip_preserve_sub_clip(clip_id, path) -> {success}
      get_unique_id(clip_id) -> {id}
      transcribe_audio(clip_id, use_speaker_detection?) -> {success}  — use_speaker_detection is Resolve 21+
      clear_transcription(clip_id) -> {success}
      get_transcription(clip_id) -> {text, truncated, status, has_transcription}
        Read a clip's transcription. `truncated` flags when Resolve's preview
        property cut the text off (the full transcript is longer).
      extract_frames(clip_id, timestamps, output_dir?) -> {frame_paths, output_dir, count, errors}
        Extract still JPEGs from the clip's source at the given timestamps (seconds)
        via ffmpeg. Source-safe: reads source, writes only to a scratch dir.
      perform_audio_classification(clip_id) -> {success}  — Resolve 21+
      clear_audio_classification(clip_id) -> {success}  — Resolve 21+
      analyze_for_intellisearch(clip_id, identify_faces?, is_better_mode?) -> {success}  — Resolve 21+, AI IntelliSearch Extra
      analyze_for_slate(clip_id, marker_color?) -> {success}  — Resolve 21+, AI Slate ID Extra
      remove_motion_blur(clip_id, deblur_option?) -> {success, new, new_id}  — Resolve 21+; renders NEW media (confirm-gated)
      get_audio_mapping(clip_id) -> {mapping}
      get_mark_in_out(clip_id) -> {mark}
      set_mark_in_out(clip_id, mark_in, mark_out, type?) -> {success}
      clear_mark_in_out(clip_id, type?) -> {success}
      open_in_viewer(clip_id, page?, mark_in_seconds?, mark_out_seconds?, clear_marks?) -> {success, clip_id, clip_name, folder_name, page, mark_set}
        — Switches to Media page (default) and selects the clip in the bin.
          Resolve auto-loads the selected clip into the source viewer on Media page.
          Optional: pre-set Mark In/Out on the clip so a shot's time range is
          highlighted when it loads.
          NOTE: Source-viewer auto-load is undocumented in the Scripting API;
          verified empirically on Resolve Studio 20.3.2.9. If BMD changes the
          behavior the clip will still be selected — editor double-clicks to load.
    """
    p = params or {}
    _, _, mp, err = _get_mp()
    if err:
        return err

    # open_in_viewer needs (clip, parent_folder) to set the bin to the right folder.
    # Other actions just need the clip.
    if action == "open_in_viewer":
        clip, parent = _find_clip_with_parent(mp.GetRootFolder(), p.get("clip_id", ""))
        if not clip:
            return _err(f"Clip not found: {p.get('clip_id')}")
        page = (p.get("page") or "media").strip().lower()
        if page not in ("media", "cut", "edit"):
            return _err(f"Unsupported page for open_in_viewer: {page!r}. Use 'media' (recommended), 'cut', or 'edit'.")
        resolve_obj = get_resolve()
        if resolve_obj is None:
            return _err("Not connected to DaVinci Resolve. Is Resolve running?")
        if not resolve_obj.OpenPage(page):
            return _err(f"Failed to switch to {page} page")

        # V2 P14+B4: Optional mark in/out so a shot's time range is pre-highlighted
        # when the clip loads in source viewer. Caller passes seconds; we convert
        # to frames using the clip's fps from properties.
        mark_set: Optional[Dict[str, Any]] = None
        if p.get("clear_marks") or p.get("clearMarks"):
            try:
                clip.ClearMarkInOut(p.get("mark_type") or "all")
                mark_set = {"cleared": True}
            except Exception as exc:
                mark_set = {"cleared": False, "error": str(exc)}
        else:
            mark_in_s = p.get("mark_in_seconds") if p.get("mark_in_seconds") is not None else p.get("markInSeconds")
            mark_out_s = p.get("mark_out_seconds") if p.get("mark_out_seconds") is not None else p.get("markOutSeconds")
            if mark_in_s is not None or mark_out_s is not None:
                # Resolve fps from clip properties; fall back to 24 if not readable.
                try:
                    fps_str = clip.GetClipProperty("FPS") or clip.GetClipProperty("Frame Rate") or "24"
                    fps = float(str(fps_str).split()[0])
                    if fps <= 0:
                        fps = 24.0
                except Exception:
                    fps = 24.0
                in_frame = int(round(float(mark_in_s) * fps)) if mark_in_s is not None else 0
                out_frame = int(round(float(mark_out_s) * fps)) if mark_out_s is not None else None
                if out_frame is None:
                    # No out → caller wants only an "in" mark; use clip end.
                    try:
                        existing = clip.GetMarkInOut() or {}
                        video = existing.get("video") or {}
                        out_frame = int(video.get("out") or (in_frame + 1))
                    except Exception:
                        out_frame = in_frame + 1
                if out_frame <= in_frame:
                    out_frame = in_frame + 1
                try:
                    mark_ok = bool(clip.SetMarkInOut(in_frame, out_frame, p.get("mark_type") or "all"))
                    mark_set = {
                        "applied": mark_ok,
                        "in_frame": in_frame,
                        "out_frame": out_frame,
                        "fps_used": fps,
                        "mark_in_seconds": mark_in_s,
                        "mark_out_seconds": mark_out_s,
                    }
                except Exception as exc:
                    mark_set = {"applied": False, "error": str(exc)}

        # Navigate the bin to the clip's folder so the clip is visible to select.
        if parent is not None:
            try:
                mp.SetCurrentFolder(parent)
            except Exception:
                pass  # not fatal; SetSelectedClip below may still work
        select_ok = bool(mp.SetSelectedClip(clip))

        # Bring Resolve to the foreground so the editor doesn't have to
        # alt-tab. Default on; pass focus_app=false to suppress.
        focus_app = p.get("focus_app", p.get("focusApp", True))
        focus_result: Optional[Dict[str, Any]] = None
        if focus_app:
            focus_result = _activate_resolve_window()

        # Jump the source viewer playhead to Mark In via Shift+I keystroke.
        # Resolve's scripting API has no direct "set source viewer playhead"
        # call, so we send the keyboard equivalent of "Go to In" once the
        # app is in the foreground. Default on when a mark was set.
        jump_result: Optional[Dict[str, Any]] = None
        wants_jump = p.get("jump_to_mark_in", p.get("jumpToMarkIn", True))
        applied_mark = bool(mark_set and mark_set.get("applied"))
        if wants_jump and applied_mark and focus_result and focus_result.get("activated"):
            jump_result = _send_resolve_keystroke_go_to_mark_in()

        return {
            "success": select_ok,
            "clip_id": clip.GetUniqueId(),
            "clip_name": clip.GetName(),
            "folder_name": parent.GetName() if parent else None,
            "page": page,
            "mark_set": mark_set,
            "focus": focus_result,
            "playhead_jump": jump_result,
            "note": (
                "Clip selected in bin. On Media page the source viewer auto-loads "
                "the selection. On Cut/Edit pages the clip is selected but the "
                "source viewer may not auto-load — call again with page='media' or "
                "double-click in Resolve."
            ) if page != "media" else (
                "Clip selected and auto-loaded in Media page source viewer."
                + (" Mark In/Out set." if mark_set and mark_set.get("applied") else "")
                + (" Resolve activated." if focus_result and focus_result.get("activated") else "")
                + (" Playhead jumped to Mark In." if jump_result and jump_result.get("sent") else "")
            ),
        }

    clip = _find_clip(mp.GetRootFolder(), p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")

    if action == "get_name":
        return {"name": clip.GetName()}
    elif action == "get_metadata":
        return {"metadata": _ser(clip.GetMetadata(p.get("key", "")))}
    elif action == "set_metadata":
        if "metadata" in p:
            ok = bool(clip.SetMetadata(p["metadata"]))
            if ok:
                silent = _verify_writeback(clip, p["metadata"])
                if silent:
                    return silent
            return {"success": ok}
        ok = bool(clip.SetMetadata(p["key"], p["value"]))
        if ok:
            silent = _verify_clip_property_writeback(clip, p["key"], p["value"])
            if silent:
                return silent
        return {"success": ok}
    elif action == "get_third_party_metadata":
        return {"metadata": _ser(clip.GetThirdPartyMetadata(p.get("key", "")))}
    elif action == "set_third_party_metadata":
        return {"success": bool(clip.SetThirdPartyMetadata(p["key"], p["value"]))}
    elif action == "get_media_id":
        return {"media_id": clip.GetMediaId()}
    elif action == "get_clip_property":
        return {"properties": _ser(clip.GetClipProperty(p.get("key", "")))}
    elif action == "set_clip_property":
        ok = bool(clip.SetClipProperty(p["key"], p["value"]))
        if ok:
            silent = _verify_clip_property_writeback(clip, p["key"], p["value"])
            if silent:
                return silent
        return {"success": ok}
    elif action == "get_clip_color":
        return {"color": clip.GetClipColor()}
    elif action == "set_clip_color":
        return {"success": bool(clip.SetClipColor(p["color"]))}
    elif action == "clear_clip_color":
        return {"success": bool(clip.ClearClipColor())}
    elif action == "link_proxy":
        return {"success": bool(clip.LinkProxyMedia(p["proxy_path"]))}
    elif action == "unlink_proxy":
        return {"success": bool(clip.UnlinkProxyMedia())}
    elif action == "replace_clip":
        return {"success": bool(clip.ReplaceClip(p["path"]))}
    elif action == "set_name":
        missing = _requires_method(clip, "SetName", "20.2")
        if missing:
            return missing
        return {"success": bool(clip.SetName(p["name"]))}
    elif action == "link_full_resolution_media":
        missing = _requires_method(clip, "LinkFullResolutionMedia", "20.0")
        if missing:
            return missing
        full_res_path = p.get("path") or p.get("full_res_media_path") or p.get("fullResMediaPath")
        if not full_res_path:
            return _err("Provide path or full_res_media_path")
        return {"success": bool(clip.LinkFullResolutionMedia(full_res_path))}
    elif action == "monitor_growing_file":
        missing = _requires_method(clip, "MonitorGrowingFile", "20.0")
        if missing:
            return missing
        return {"success": bool(clip.MonitorGrowingFile())}
    elif action == "replace_clip_preserve_sub_clip":
        missing = _requires_method(clip, "ReplaceClipPreserveSubClip", "20.0")
        if missing:
            return missing
        replacement_path = p.get("path") or p.get("file_path") or p.get("filePath")
        if not replacement_path:
            return _err("Provide path or file_path")
        return {"success": bool(clip.ReplaceClipPreserveSubClip(replacement_path))}
    elif action == "get_unique_id":
        return {"id": clip.GetUniqueId()}
    elif action == "transcribe_audio":
        usd = _first_param(p, "use_speaker_detection", "useSpeakerDetection")
        if usd is None:
            with long_resolve_op("media_pool_item.transcribe_audio"):
                return {"success": bool(clip.TranscribeAudio())}
        with long_resolve_op("media_pool_item.transcribe_audio"):
            return {"success": bool(clip.TranscribeAudio(bool(usd)))}
    elif action == "clear_transcription":
        return {"success": bool(clip.ClearTranscription())}
    elif action == "get_transcription":
        raw = clip.GetClipProperty("Transcription")
        text = raw if isinstance(raw, str) else ("" if raw is None else str(raw))
        try:
            status = clip.GetClipProperty("Transcription Status")
        except Exception:
            status = None
        return {
            "clip_id": p.get("clip_id"),
            "text": text,
            "truncated": _is_truncated(text),
            "status": status or None,
            "has_transcription": bool(text.strip()),
        }
    elif action == "extract_frames":
        return _extract_clip_frames(clip, p)
    elif action == "perform_audio_classification":
        missing = _requires_method(clip, "PerformAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("perform_audio_classification", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.PerformAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "clear_audio_classification":
        missing = _requires_method(clip, "ClearAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("clear_audio_classification", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.ClearAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_intellisearch":
        missing = _requires_method(clip, "AnalyzeForIntellisearch", "21.0")
        if missing:
            return missing
        identify_faces = bool(_first_param(p, "identify_faces", "identifyFaces", default=False))
        is_better_mode = bool(_first_param(p, "is_better_mode", "isBetterMode", default=False))
        with _ai_ledger_timed("analyze_for_intellisearch", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.AnalyzeForIntellisearch(identify_faces, is_better_mode))
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_slate":
        missing = _requires_method(clip, "AnalyzeForSlate", "21.0")
        if missing:
            return missing
        marker_color = _first_param(p, "marker_color", "markerColor", default="Blue")
        if marker_color not in _MARKER_COLORS:
            return _err(f"Invalid marker_color {marker_color!r}. Valid colors: {', '.join(_MARKER_COLORS)}")
        with _ai_ledger_timed("analyze_for_slate", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.AnalyzeForSlate(marker_color))
            _rec.success = ok
        return {"success": ok}
    elif action == "remove_motion_blur":
        missing = _requires_method(clip, "RemoveMotionBlur", "21.0")
        if missing:
            return missing
        deblur = _first_param(p, "deblur_option", "deblurOption", default=None) or {}
        gate = _ai_governance_gate("remove_motion_blur", p)
        if gate:
            return gate
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool_item.remove_motion_blur",
                params=p,
                preview={
                    "operation": "media_pool_item.remove_motion_blur",
                    "warning": "Renders a NEW deblurred media file; the source clip is not modified.",
                    "clip": clip.GetName(),
                    "deblur_option": deblur,
                    "governance": _ai_governance_check("remove_motion_blur"),
                },
            )
        blocked = _consume_confirm_token(action="media_pool_item.remove_motion_blur", params=p)
        if blocked:
            return blocked
        with _ai_ledger_timed("remove_motion_blur", clip_id=p.get("clip_id")) as _rec:
            new_clip = clip.RemoveMotionBlur(deblur)
            _rec.success = bool(new_clip)
            if new_clip:
                path, nbytes = _clip_file_size(new_clip)
                _rec.output_path = path
                _rec.output_bytes = nbytes
        if not new_clip:
            return {"success": False}
        return {"success": True, "new": new_clip.GetName(), "new_id": new_clip.GetUniqueId(),
                "output_path": _rec.output_path, "output_bytes": _rec.output_bytes}
    elif action == "get_audio_mapping":
        return {"mapping": clip.GetAudioMapping()}
    elif action == "get_mark_in_out":
        return _ser(clip.GetMarkInOut())
    elif action == "set_mark_in_out":
        err, clean = _validate_params(
            p,
            {"mark_in": {"type": int, "required": True}, "mark_out": {"type": int, "required": True}},
            invariants=[lambda c: f"mark_in ({c['mark_in']}) must be <= mark_out ({c['mark_out']})"
                        if c["mark_in"] > c["mark_out"] else None],
        )
        if err:
            return _err(err)
        return {"success": bool(clip.SetMarkInOut(clean["mark_in"], clean["mark_out"], p.get("type", "all")))}
    elif action == "clear_mark_in_out":
        return {"success": bool(clip.ClearMarkInOut(p.get("type", "all")))}
    return _unknown(action, ["get_name","get_metadata","set_metadata","get_third_party_metadata","set_third_party_metadata","get_media_id","get_clip_property","set_clip_property","get_clip_color","set_clip_color","clear_clip_color","link_proxy","unlink_proxy","replace_clip","set_name","link_full_resolution_media","monitor_growing_file","replace_clip_preserve_sub_clip","get_unique_id","transcribe_audio","clear_transcription","get_transcription","extract_frames","perform_audio_classification","clear_audio_classification","analyze_for_intellisearch","analyze_for_slate","remove_motion_blur","get_audio_mapping","get_mark_in_out","set_mark_in_out","clear_mark_in_out","open_in_viewer"])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 14: media_pool_item_markers
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
def media_pool_item_markers(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Markers and flags on media pool clips. Identify clip by clip_id.

    Actions:
      add(clip_id, frame|frame_id|frameId, color?, name?, note?, duration?, custom_data?) -> {success, frame}
      get_all(clip_id) -> {markers}
      get_by_custom_data(clip_id, custom_data) -> {markers}
      update_custom_data(clip_id, frame|frame_id|frameId, custom_data) -> {success}
      get_custom_data(clip_id, frame|frame_id|frameId) -> {data}
      delete_by_color(clip_id, color) -> {success}
      delete_at_frame(clip_id, frame|frame_id|frameId) -> {success}
      delete_by_custom_data(clip_id, custom_data) -> {success}
      add_flag(clip_id, color) -> {success}
      get_flags(clip_id) -> {flags}
      clear_flags(clip_id, color) -> {success}
      set_name(clip_id, name) -> {success}
      link_full_resolution_media(clip_id, path) -> {success}
      monitor_growing_file(clip_id) -> {success}
      replace_clip_preserve_sub_clip(clip_id, path) -> {success}
    """
    p = params or {}
    _, _, mp, err = _get_mp()
    if err:
        return err
    clip = _find_clip(mp.GetRootFolder(), p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")

    if action == "add":
        marker, marker_err = _marker_add_payload(p)
        if marker_err:
            return marker_err
        return _add_marker(clip, marker)
    elif action == "get_all":
        return {"markers": _ser(clip.GetMarkers())}
    elif action == "get_by_custom_data":
        return {"markers": _ser(clip.GetMarkerByCustomData(_first_param(p, "custom_data", "customData", default="")))}
    elif action == "update_custom_data":
        frame, frame_err = _marker_frame_from_params(p)
        if frame_err:
            return frame_err
        return {"success": bool(clip.UpdateMarkerCustomData(frame, _first_param(p, "custom_data", "customData", default="")))}
    elif action == "get_custom_data":
        frame, frame_err = _marker_frame_from_params(p)
        if frame_err:
            return frame_err
        return {"data": clip.GetMarkerCustomData(frame)}
    elif action == "delete_by_color":
        if not p.get("color"):
            return _err("delete_by_color requires color")
        return {"success": bool(clip.DeleteMarkersByColor(p["color"]))}
    elif action == "delete_at_frame":
        frame, frame_err = _marker_frame_from_params(p)
        if frame_err:
            return frame_err
        return {"success": bool(clip.DeleteMarkerAtFrame(frame))}
    elif action == "delete_by_custom_data":
        return {"success": bool(clip.DeleteMarkerByCustomData(_first_param(p, "custom_data", "customData", default="")))}
    elif action == "add_flag":
        return {"success": bool(clip.AddFlag(p["color"]))}
    elif action == "get_flags":
        return {"flags": clip.GetFlagList()}
    elif action == "clear_flags":
        return {"success": bool(clip.ClearFlags(p["color"]))}
    elif action == "set_name":
        missing = _requires_method(clip, "SetName", "20.2")
        if missing:
            return missing
        return {"success": bool(clip.SetName(p["name"]))}
    elif action == "link_full_resolution_media":
        missing = _requires_method(clip, "LinkFullResolutionMedia", "20.0")
        if missing:
            return missing
        full_res_path = p.get("path") or p.get("full_res_media_path") or p.get("fullResMediaPath")
        if not full_res_path:
            return _err("Provide path or full_res_media_path")
        return {"success": bool(clip.LinkFullResolutionMedia(full_res_path))}
    elif action == "monitor_growing_file":
        missing = _requires_method(clip, "MonitorGrowingFile", "20.0")
        if missing:
            return missing
        return {"success": bool(clip.MonitorGrowingFile())}
    elif action == "replace_clip_preserve_sub_clip":
        missing = _requires_method(clip, "ReplaceClipPreserveSubClip", "20.0")
        if missing:
            return missing
        replacement_path = p.get("path") or p.get("file_path") or p.get("filePath")
        if not replacement_path:
            return _err("Provide path or file_path")
        return {"success": bool(clip.ReplaceClipPreserveSubClip(replacement_path))}
    return _unknown(action, ["add","get_all","get_by_custom_data","update_custom_data","get_custom_data","delete_by_color","delete_at_frame","delete_by_custom_data","add_flag","get_flags","clear_flags","set_name","link_full_resolution_media","monitor_growing_file","replace_clip_preserve_sub_clip"])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 15: media_analysis
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
async def media_analysis(action: str, params: Optional[Dict[str, Any]] = None, ctx: Optional[Context] = None) -> Dict[str, Any]:
    """Project-scoped media analysis and guarded metadata publishing.

    <when_to_use>
    - Lead any analysis flow with capabilities() + get_caps() to know what's available
      and what the current budget looks like.
    - For per-clip work: analyze_clip(clip_id=...). For bins/projects/timelines: analyze_bin,
      analyze_project, analyze_sequence (return job_id for long runs).
    - Vision uses host_chat_paths: analyze returns frame_paths + JSON schema; the host reads
      frames, produces JSON, then calls commit_vision to merge.
    - For caps refusal recovery: set_caps_preset (preset=generous|unlimited) or wait for day rollover.
    </when_to_use>

    <returns>
    capabilities         -> {tools, transcription, vision}
    get_caps             -> {preset, caps, presets_available, usage?}
    set_caps_preset      -> {success, preset, overrides}
    plan                 -> {clips, artifacts, estimated_seconds}
    analyze_clip|file    -> {clips, manifest: {success, clip_count, successful_clip_count, failed_clip_count, partial_success?, caps_refusal_clip_count?, clips: [...], error?}}
    analyze_bin|project|sequence -> {job_id, status, clips, manifest, ...}
    commit_vision        -> {analysis_json, marker_plan_json, metadata_publish}
    summarize            -> {clips_summarized, summary, provenance: {source_reports, missing_reports}}
    review_timeline_markers -> {path, samples, vision_review?}
    start_batch_job      -> {job_id, status}
    batch_job_status     -> {job_id, status, progress, recent_events, clip_states}
    All actions may return {"error": {code, category, retryable, message, remediation, reason?}}.
    Errors with code=CAPS_REFUSAL also carry a `caps_refusal` block at the clip level and a
    `caps_refusal_clip_count` aggregate at the manifest level.
    </returns>

    Actions:
      capabilities() -> {tools, transcription, vision}
      install_guidance() -> {missing}  — guidance only; never installs anything
      get_caps(clip_id?, job_id?) -> {preset, caps, presets_available, usage?} — effective caps + usage rollup (vision tokens consumed per scope, percent of budget).
      set_caps_preset(preset, overrides?) -> {success, preset, overrides} — preset is minimal | standard | generous | unlimited. Overrides is a dict of {field: int|"unlimited"} that wins over the preset.
      get_usage(scope?, scope_key?, clip_id?, job_id?) -> {scope, usage} — raw usage rollup for one scope (clip | job | day).
      get_resolve_ai_usage(session_only?, op?, limit?) -> {summary, recent} — ledger of Resolve 21 local AI ops (audio classification, IntelliSearch, slate, motion-deblur, speech). Tracks invocations, wall-clock, and files/bytes created by the two media-creating ops. Separate from get_caps/get_usage (those meter Claude-side tokens; these ops don't spend them).
      get_ai_governance() -> {tier, mode, thresholds, usage, tiers_available} — governance tier (off|lenient|standard|strict) for the media-creating AI ops vs this session's render usage. mode is advisory (default; preview warnings only) or enforce (over-tier runs are blocked).
      set_ai_governance(preset?, mode?, overrides?) -> {success, tier, mode, overrides} — set the tier, the mode (advisory|enforce), and/or overrides (deblur_runs, speech_runs, render_bytes, render_wall_clock_ms; int or "unlimited"). In enforce mode a blocked run returns GOVERNANCE_BLOCKED; pass override_governance=true on the op to consciously exceed the tier once.
      resolve_output_root(analysis_root?, source_paths?) -> {project_root}
      plan(target, depth?, analysis_root?, transcription?, vision?, dry_run?) -> {clips, artifacts}
      analyze_file(path|file_path, dry_run?, session_only?, persist?) -> {clips, manifest}
      analyze_clip(clip_id|selected, dry_run?, session_only?, persist?) -> {clips, manifest}
      analyze_bin(path|bin_path, recursive?, dry_run?, session_only?, persist?) -> {clips, manifest}
      analyze_project(recursive?, dry_run?, session_only?, persist?) -> {clips, manifest}
      analyze_sequence(timeline_index?, track_types?, dry_run?, session_only?, persist?) -> {clips, manifest}
      analyze_timeline(...) -> alias for analyze_sequence on the current timeline
      detect_sync_events(paths?|target?, event_types?, windows?) -> {files, alignment}
      add_sync_event_markers(target?|paths?|detections?, confirm?) -> {added, skipped}
      publish_clip_metadata(target?, fields?, slate_detection?, timed_markers?|write_markers?, dry_run?, confirm?) -> {results}
      commit_vision(clip_id|file_path|clip_dir, visual, vision_token?, analysis_root?, publish_metadata?, dry_run?, confirm?) -> {analysis_json, marker_plan_json, metadata_publish}
      review_timeline_markers(max_samples?, analysis_root?, vision?) -> {path, samples, vision_review?}
      summarize(analysis_root?) -> project summary from existing clip reports
      get_report(report_path?) -> load manifest or a report under the analysis root
      build_index(analysis_root?) -> rebuild the single-user SQLite index from existing reports
      index_status(analysis_root?) -> summarize index path, size, and row counts
      query_index(query, limit?, result_types?) -> search clips, markers, and transcripts
      start_batch_job(target, depth?, ...) -> create a durable slice-runnable analysis job; target may be selected, bin, project, sequence, file, or {type:"clips", clip_ids:[...]}
      run_batch_job_slice(job_id, max_clips?, max_seconds?) -> process a bounded job slice and refresh the index after successful clips
      batch_job_status(job_id) -> progress, recent events, and clip states
      list_batch_jobs() -> recent durable analysis jobs
      cancel_batch_job(job_id) -> stop future slices
      resume_batch_job(job_id) -> requeue a canceled or interrupted job
      cleanup_artifacts(frames_only=true) -> remove generated frame artifacts only

    Analysis outputs stay under a davinci-resolve-mcp-analysis project root
    and are validated so they are never written beside source media. Executed
    Resolve-target analysis defaults to execution, persisted inspectable
    artifacts, metadata writeback, and Media Pool clip markers unless disabled.
    The SQLite index is a single-user derived cache stored beside the JSON
    reports; it stores text/metadata only, never sampled image bytes.
    Batch jobs are single-user operational state stored beside the analysis
    root; each slice exits cleanly so agents can poll progress without spending
    tokens on long media processing.
    Executed Resolve-target analysis writes metadata and Media Pool clip markers
    by default; pass dry_run=true, publish_metadata=false, or timed_markers=no
    to disable writeback. If ask_before_metadata_publish is enabled,
    publish_clip_metadata returns a confirmation prompt until confirm=true.
    Vision uses host_chat_paths by default: analyze actions return a deferred
    payload with absolute frame_paths and a JSON schema. The host chat reads
    each frame as a local image, produces JSON per the schema, and calls
    media_analysis(action="commit_vision", params={clip_id, visual, vision_token})
    to merge the result, rebuild Media Pool clip markers, and publish
    vision-dependent metadata to Resolve. Works with any MCP client whose chat
    model is vision-capable; no sampling/createMessage support required.
    """
    p = _media_analysis_apply_setup_defaults(action, dict(params or {}))

    # First-run frame-sampling prompt: if the user has never chosen a sampling
    # mode (and didn't pass one this call), ask before spending any vision
    # tokens. Re-running with sampling_mode=<choice> saves it as the default;
    # passing sampling_mode explicitly any time is a one-off that skips this.
    _sampling_decision = p.get("_sampling_mode_decision") if isinstance(p, dict) else None
    if (
        isinstance(_sampling_decision, dict)
        and _sampling_decision.get("prompt_required")
        and action in {"analyze_clip", "analyze_file", "analyze_bin", "analyze_project", "analyze_sequence", "analyze_timeline", "start_batch_job"}
    ):
        return {
            "success": True,
            "status": "confirmation_required",
            "confirmation_required": True,
            "sampling_mode_prompt": _media_analysis_sampling_mode_prompt(),
            "recommended_sampling_mode": _media_analysis_module.RECOMMENDED_SAMPLING_MODE,
            "message": (
                "Choose a frame-sampling mode for visual analysis. Re-run with "
                "sampling_mode set to one of fixed/per_minute/adaptive_capped/adaptive "
                "(the chosen value is saved as your default), or set it in the control "
                "panel under Analysis Modes. Pass sampling_mode per-call any time for a one-off."
            ),
            "preferences_path": _media_analysis_preferences_path(),
        }

    # E2 — capture original action + scope before the dispatch may rewrite
    # `action` (e.g. analyze_clip → plan). Used by _e2_wrap below to attach
    # an `escalation` block when a (scope, action) pair fails repeatedly.
    _e2_track_action = action if action in {
        "analyze_clip", "analyze_file", "analyze_bin",
        "analyze_project", "analyze_sequence", "analyze_timeline",
        "commit_vision",
    } else None
    _e2_track_scope: Optional[str] = None
    if _e2_track_action == "analyze_clip":
        _e2_track_scope = p.get("clip_id") or (p.get("target") or {}).get("clip_id")
    elif _e2_track_action == "analyze_file":
        _e2_track_scope = p.get("path") or p.get("file_path") or (p.get("target") or {}).get("path")
    elif _e2_track_action == "analyze_bin":
        bin_path = p.get("bin_path") or p.get("path") or (p.get("target") or {}).get("path")
        _e2_track_scope = ("bin:" + bin_path) if bin_path else "bin:Master"
    elif _e2_track_action == "analyze_project":
        _e2_track_scope = "project"
    elif _e2_track_action in {"analyze_sequence", "analyze_timeline"}:
        _e2_track_scope = "sequence"
    elif _e2_track_action == "commit_vision":
        _e2_track_scope = p.get("clip_id")

    def _e2_wrap(resp: Any) -> Any:
        """Attach failure_tracker escalation when (scope, action) has failed N times in window."""
        if not _e2_track_action or not isinstance(resp, dict):
            return resp
        return _record_action_outcome(_e2_track_scope, _e2_track_action, resp)

    if action == "capabilities":
        return _media_analysis_capabilities_for_request(ctx)
    if action == "recheck_capabilities":
        # Re-runs detection (shutil.which / importlib.util.find_spec) so a tool
        # an agent just installed flips from missing → available without the
        # user reloading the dashboard. Optional `previous` param compares against
        # a prior snapshot and returns a `changed` diff for "before/after" reporting.
        fresh = _media_analysis_capabilities_for_request(ctx)
        previous = (p.get("previous") or {}) if isinstance(p, dict) else {}
        prev_tools = (previous.get("tools") or {}) if isinstance(previous, dict) else {}
        new_tools = fresh.get("tools") or {}
        changed: Dict[str, Dict[str, Any]] = {}
        for name, new_entry in new_tools.items():
            prev_avail = bool((prev_tools.get(name) or {}).get("available")) if isinstance(prev_tools.get(name), dict) else None
            new_avail = bool(new_entry.get("available"))
            if prev_avail is None:
                continue
            if prev_avail != new_avail:
                changed[name] = {"was": prev_avail, "now": new_avail}
        return {
            "success": True,
            "capabilities": fresh,
            "changed": changed,
        }
    if action == "get_caps":
        # Effective caps + per-scope usage rollup. Cheap, no Resolve required —
        # consults the preference file + the per-project token-usage DB.
        from src.utils import analysis_caps as _ac
        active = _ac.resolve_caps(_caps_preset_provider(), _caps_overrides_provider())
        out: Dict[str, Any] = {
            "success": True,
            "preset": active.preset,
            "caps": active.to_dict(),
            "presets_available": _ac.list_presets(),
        }
        # Usage rollup is per-project; if no project context, skip silently.
        try:
            vctx = _destructive_versioning_provider()
            if vctx is not None:
                _resolve_h, _proj_h, project_root, _name = vctx
                out["usage"] = _ac.get_usage_rollup(
                    project_root=project_root,
                    caps=active,
                    clip_id=p.get("clip_id"),
                    job_id=p.get("job_id"),
                )
        except Exception as exc:
            out["usage_error"] = f"{type(exc).__name__}: {exc}"
        return out
    if action == "get_resolve_ai_usage":
        # Ledger of Resolve-local 21.0 AI ops (audio classification, IntelliSearch,
        # slate, motion-deblur, speech generation). Distinct from get_caps/get_usage,
        # which meter Claude-side analysis tokens — these ops don't spend those.
        try:
            vctx = _destructive_versioning_provider()
            if vctx is None:
                return _err("No project context — open a Resolve project first")
            _r, _proj, project_root, _name = vctx
            session_only = bool(p.get("session_only", False))
            session_id = _AI_LEDGER_SESSION_ID if session_only else None
            limit = _safe_int(p.get("limit"), 50, minimum=1, maximum=1000)
            return {
                "success": True,
                "session_id": _AI_LEDGER_SESSION_ID,
                "scope": "session" if session_only else "project",
                "summary": _resolve_ai_ledger.get_summary(project_root=project_root, session_id=session_id),
                "recent": _resolve_ai_ledger.get_usage(project_root=project_root, session_id=session_id, op=p.get("op"), limit=limit),
            }
        except Exception as exc:
            return _err(f"{type(exc).__name__}: {exc}")
    if action == "get_ai_governance":
        # Soft-tier governance for the media-creating AI ops (deblur / speech).
        # Advisory only — reports this session's render usage vs the active tier.
        try:
            project_root = _ai_ledger_root()
            st = _resolve_ai_governance.status(
                project_root=project_root, session_id=_AI_LEDGER_SESSION_ID,
                preset=_ai_governance_preset(), overrides=_ai_governance_overrides(),
            )
            return {"success": True, "session_id": _AI_LEDGER_SESSION_ID, "mode": _ai_governance_mode(), **st}
        except Exception as exc:
            return _err(f"{type(exc).__name__}: {exc}")
    if action == "set_ai_governance":
        preset = (p.get("preset") or "").strip().lower()
        mode = (p.get("mode") or "").strip().lower()
        if not preset and not mode and not isinstance(p.get("overrides"), dict):
            return _err("set_ai_governance requires at least one of: preset, mode, overrides")
        if preset and preset not in _resolve_ai_governance.VALID_TIERS:
            return _err(f"unknown tier '{preset}'. Valid: {sorted(_resolve_ai_governance.VALID_TIERS)}")
        if mode and mode not in _AI_GOVERNANCE_MODES:
            return _err(f"unknown mode '{mode}'. Valid: {list(_AI_GOVERNANCE_MODES)}")
        try:
            prefs = _read_media_analysis_preferences_strict()
        except ConfigParseError as exc:
            return _err(f"Refusing to save AI governance: {exc}. The preferences file exists but is unparseable; fix or delete it to avoid wiping saved settings.")
        if preset:
            prefs["resolve_ai_governance_preset"] = preset
        if mode:
            prefs["resolve_ai_governance_mode"] = mode
        if isinstance(p.get("overrides"), dict):
            prefs["resolve_ai_governance_overrides"] = p["overrides"]
        _write_media_analysis_preferences(prefs)
        return {
            "success": True,
            "tier": prefs.get("resolve_ai_governance_preset") or _resolve_ai_governance.DEFAULT_TIER,
            "mode": prefs.get("resolve_ai_governance_mode") or "advisory",
            "overrides": prefs.get("resolve_ai_governance_overrides") or {},
        }
    if action == "set_caps_preset":
        preset = (p.get("preset") or "").strip().lower()
        from src.utils import analysis_caps as _ac
        if preset not in _ac.VALID_PRESETS:
            return _err(f"unknown preset '{preset}'. Valid: {sorted(_ac.VALID_PRESETS)}")
        # Update preference file directly (same pattern as set_defaults).
        try:
            prefs = _read_media_analysis_preferences_strict()
        except ConfigParseError as exc:
            return _err(f"Refusing to save caps preset: {exc}. The preferences file exists but is unparseable; fix or delete it to avoid wiping saved settings.")
        prefs["analysis_caps_preset"] = preset
        if isinstance(p.get("overrides"), dict):
            prefs["analysis_caps_overrides"] = p["overrides"]
        _write_media_analysis_preferences(prefs)
        return {"success": True, "preset": preset, "overrides": prefs.get("analysis_caps_overrides") or {}}
    if action == "get_usage":
        from src.utils import analysis_caps as _ac
        try:
            vctx = _destructive_versioning_provider()
            if vctx is None:
                return _err("No project context — open a Resolve project first")
            _r, _proj, project_root, _name = vctx
            scope = (p.get("scope") or "day").strip().lower()
            scope_key = p.get("scope_key") or p.get("clip_id") or p.get("job_id")
            return {
                "success": True,
                "scope": scope,
                "scope_key": scope_key,
                "usage": _ac.get_current_usage(
                    project_root=project_root, scope=scope, scope_key=scope_key,
                ),
            }
        except Exception as exc:
            return _err(f"{type(exc).__name__}: {exc}")

    if action == "install_guidance":
        caps = _media_analysis_capabilities_for_request(ctx)
        guidance = media_analysis_install_guidance(caps)
        if caps.get("vision", {}).get("available"):
            guidance.get("missing", {}).pop("vision", None)
        guidance["host_chat_paths_vision"] = {
            "available": True,
            "requires": "No package install; the host MCP client's chat model must be able to read local image files.",
            "provider": HOST_CHAT_PATHS_PROVIDER,
            "commit_action": {"tool": "media_analysis", "action": "commit_vision"},
            "schema_reference": VISION_SCHEMA_REFERENCE,
        }
        return guidance

    pm, proj, err = _check()
    if err:
        return _e2_wrap(err)
    project_name, project_id = _project_name_and_id(proj)
    if p.get("project_name") or p.get("projectName"):
        project_name = p.get("project_name") or p.get("projectName")
    if p.get("project_id") or p.get("projectId"):
        project_id = p.get("project_id") or p.get("projectId")

    if action == "resolve_output_root":
        return resolve_media_analysis_output_root(
            project_name=project_name,
            project_id=project_id,
            analysis_root=p.get("analysis_root"),
            source_paths=p.get("source_paths") or p.get("sourcePaths") or [],
            create=bool(p.get("create", False)),
        )

    if action in {
        "summarize",
        "get_report",
        "build_index",
        "rebuild_index",
        "index_status",
        "query_index",
        "batch_job_status",
        "list_batch_jobs",
        "run_batch_job_slice",
        "cancel_batch_job",
        "resume_batch_job",
        "cleanup_artifacts",
        # V2 session/panel state + C4 corrections. These checks lived inside
        # this block since v2.24.0 but were missing from the membership set,
        # making them unreachable from MCP dispatch (the panel proxied to the
        # helpers directly, which masked it). Fixed as part of C1 (Phase A).
        "get_panel_state",
        "set_panel_state",
        "session_start_context",
        "update_shot_field",
        "update_clip_field",
        "get_field_history",
        "revert_field",
        "list_corrections",
        # C1 — DB-canonical analysis store.
        "db_status",
        "db_ingest",
        # Phase B — deep shot-level vision tier.
        "deepen",
        "commit_shot_vision",
        "vision_pending_sweep",
        # Phase C — embeddings + similarity.
        "build_embeddings",
        "find_similar",
        # Phase D — cross-clip entities + bin briefing v2.
        "detect_entities",
        "commit_entities",
        "list_entities",
        "prepare_bin_briefing",
        "commit_bin_summary",
        # Cross-shot relationships (spec §4).
        "detect_shot_relationships",
        "commit_shot_relationships",
        "list_shot_relationships",
    }:
        root = resolve_media_analysis_output_root(
            project_name=project_name,
            project_id=project_id,
            analysis_root=p.get("analysis_root"),
            source_paths=[],
            create=bool(p.get("create", False)),
        )
        if not root.get("success"):
            return root
        project_root = root["project_root"]
        if action == "summarize":
            return summarize_media_analysis_reports(project_root)
        if action == "get_report":
            return load_media_analysis_report(
                project_root,
                report_path=p.get("report_path") or p.get("path"),
                clip_dir=p.get("clip_dir"),
            )
        # V2 B6: chat ↔ panel state sharing
        if action == "get_panel_state":
            from src.utils.analysis_memory import read_panel_state, panel_state_path
            state = read_panel_state(project_root)
            return {
                "success": True,
                "project_root": project_root,
                "panel_state_path": panel_state_path(project_root),
                "panel_state": state,
            }
        if action == "set_panel_state":
            from src.utils.analysis_memory import write_panel_state
            updates = p.get("state") or p.get("panel_state") or {}
            if not isinstance(updates, dict):
                return _err("set_panel_state requires `state` to be an object")
            merge = _media_analysis_bool(p.get("merge", True), True)
            written_by = p.get("written_by") or p.get("writtenBy") or "chat"
            return write_panel_state(project_root, updates, written_by=written_by, merge=merge)
        # V2 session-start context (loads soul + memory + heartbeat + panel state)
        if action == "session_start_context":
            from src.utils.analysis_memory import session_start_context
            return session_start_context(project_root)
        # V2 C4: correction tools — per-clip sidecar JSON with provenance + changelog
        if action == "update_shot_field":
            return _v2_update_field(project_root, p, entity_type="shot")
        if action == "update_clip_field":
            return _v2_update_field(project_root, p, entity_type="clip")
        if action == "get_field_history":
            return _v2_get_field_history(project_root, p)
        if action == "revert_field":
            return _v2_revert_field(project_root, p)
        if action == "list_corrections":
            return _v2_list_corrections(project_root, p)
        # C1 — DB-canonical analysis store (Phase A).
        if action == "db_status":
            from src.utils import analysis_store
            return analysis_store.db_status(project_root)
        if action == "db_ingest":
            from src.utils import analysis_store
            return analysis_store.ingest_project(project_root)
        # Phase B — deep shot-level vision tier.
        if action == "deepen":
            from src.utils import deep_vision
            clip_ref = p.get("clip_id") or p.get("clipId") or p.get("clip_dir") or p.get("clipDir") or p.get("file_path") or p.get("filePath")
            if not clip_ref:
                return _err("deepen requires clip_id, clip_dir, or file_path")
            raw_indices = p.get("shot_indices") or p.get("shotIndices")
            if raw_indices is None and p.get("shot_index") is not None:
                raw_indices = [p.get("shot_index")]
            return deep_vision.deepen_clip(
                project_root,
                clip_ref=clip_ref,
                shot_indices=[int(i) for i in raw_indices] if raw_indices else None,
                confirm_token=p.get("confirm_token") or p.get("confirmToken"),
                job_id=p.get("job_id") or p.get("jobId"),
            )
        if action == "commit_shot_vision":
            from src.utils import deep_vision
            clip_ref = p.get("clip_id") or p.get("clipId") or p.get("clip_dir") or p.get("clipDir") or p.get("file_path") or p.get("filePath")
            if not clip_ref:
                return _err("commit_shot_vision requires clip_id, clip_dir, or file_path")
            return deep_vision.commit_shot_vision(
                project_root,
                shots=p.get("shots"),
                vision_token=p.get("vision_token") or p.get("visionToken"),
                clip_ref=clip_ref,
                author=p.get("author") or "host_chat",
            )
        if action == "vision_pending_sweep":
            from src.utils import deep_vision
            return deep_vision.vision_pending_sweep(
                project_root,
                expire=_media_analysis_bool(p.get("expire"), False),
                max_age_days=p.get("max_age_days") or p.get("maxAgeDays"),
                reoffer=_media_analysis_bool(p.get("reoffer"), False),
            )
        # Phase C — embeddings + similarity (local compute; no token caps).
        if action == "build_embeddings":
            from src.utils import embeddings
            kinds = p.get("kinds") or p.get("kind") or ["text"]
            if isinstance(kinds, str):
                kinds = [kinds]
            return embeddings.build_embeddings(
                project_root,
                kinds=[str(k).strip().lower() for k in kinds],
                clip_ref=p.get("clip_id") or p.get("clipId") or p.get("clip_dir") or p.get("clipDir"),
                include_segments=_media_analysis_bool(p.get("include_segments", p.get("includeSegments")), True),
                max_frames_per_clip=int(p.get("max_frames_per_clip") or p.get("maxFramesPerClip") or 16),
            )
        if action == "find_similar":
            from src.utils import embeddings
            entity_types = p.get("entity_types") or p.get("entityTypes")
            if isinstance(entity_types, str):
                entity_types = [entity_types]
            return embeddings.find_similar(
                project_root,
                text=p.get("text") or p.get("query"),
                clip_ref=p.get("clip_id") or p.get("clipId") or p.get("clip_dir") or p.get("clipDir"),
                shot_index=p.get("shot_index") if p.get("shot_index") is not None else p.get("shotIndex"),
                shot_uuid=p.get("shot_uuid") or p.get("shotUuid"),
                kind=p.get("kind") or "text",
                entity_types=entity_types,
                limit=int(p.get("limit") or 10),
            )
        # Phase D — cross-clip entities + bin briefing v2.
        if action == "detect_entities":
            from src.utils import entities
            return entities.detect_entities(
                project_root,
                threshold=float(p.get("threshold") or entities.DEFAULT_CLUSTER_THRESHOLD),
                min_cluster_size=int(p.get("min_cluster_size") or p.get("minClusterSize") or entities.DEFAULT_MIN_CLUSTER_SIZE),
                max_clusters=int(p.get("max_clusters") or p.get("maxClusters") or 24),
                job_id=p.get("job_id") or p.get("jobId"),
            )
        if action == "commit_entities":
            from src.utils import entities
            return entities.commit_entities(
                project_root,
                entities_payload=p.get("entities"),
                vision_token=p.get("vision_token") or p.get("visionToken"),
                author=p.get("author") or "host_chat",
            )
        if action == "list_entities":
            from src.utils import entities
            return entities.list_entities(project_root, kind=p.get("kind"))
        # Cross-shot relationships (spec §4): detect → one bounded vision
        # confirm (frame pairs) → commit; pattern recognition only.
        if action == "detect_shot_relationships":
            from src.utils import shot_relationships
            band = p.get("continues_band") or p.get("continuesBand")
            return shot_relationships.detect_shot_relationships(
                project_root,
                setup_threshold=float(p.get("setup_threshold") or p.get("setupThreshold")
                                      or shot_relationships.DEFAULT_SETUP_THRESHOLD),
                alt_take_threshold=float(p.get("alt_take_threshold") or p.get("altTakeThreshold")
                                         or shot_relationships.DEFAULT_ALT_TAKE_THRESHOLD),
                continues_band=tuple(band) if isinstance(band, (list, tuple)) and len(band) == 2
                else shot_relationships.DEFAULT_CONTINUES_BAND,
                max_candidates=int(p.get("max_candidates") or p.get("maxCandidates")
                                   or shot_relationships.DEFAULT_MAX_CANDIDATES),
                job_id=p.get("job_id") or p.get("jobId"),
            )
        if action == "commit_shot_relationships":
            from src.utils import shot_relationships
            return shot_relationships.commit_shot_relationships(
                project_root,
                relationships_payload=p.get("relationships"),
                vision_token=p.get("vision_token") or p.get("visionToken"),
                author=p.get("author") or "host_chat",
            )
        if action == "list_shot_relationships":
            from src.utils import shot_relationships
            return shot_relationships.list_shot_relationships(
                project_root,
                clip_ref=p.get("clip_id") or p.get("clipId") or p.get("clip_dir") or p.get("clipDir"),
                shot_uuid=p.get("shot_uuid") or p.get("shotUuid"),
                relationship_type=p.get("relationship_type") or p.get("relationshipType"),
                include_superseded=bool(p.get("include_superseded") or p.get("includeSuperseded")),
            )
        if action == "prepare_bin_briefing":
            from src.utils import entities
            return entities.prepare_bin_briefing(project_root)
        if action == "commit_bin_summary":
            from src.utils import entities
            return entities.commit_bin_summary(
                project_root,
                briefing=p.get("briefing") or p.get("summary"),
                briefing_token=p.get("briefing_token") or p.get("briefingToken"),
                author=p.get("author") or "host_chat",
            )
        if action in {"build_index", "rebuild_index"}:
            return build_analysis_index(project_root, index_path=p.get("index_path") or p.get("indexPath"))
        if action == "index_status":
            return analysis_index_status(project_root, index_path=p.get("index_path") or p.get("indexPath"))
        if action == "query_index":
            return query_analysis_index(
                project_root,
                p.get("query", ""),
                limit=p.get("limit", 20),
                result_types=p.get("result_types") or p.get("resultTypes"),
                index_path=p.get("index_path") or p.get("indexPath"),
            )
        if action == "list_batch_jobs":
            return list_media_analysis_batch_jobs(project_root, limit=p.get("limit", 50))
        if action == "batch_job_status":
            job_id = p.get("job_id") or p.get("jobId") or p.get("id")
            if not job_id:
                return _err("batch_job_status requires job_id")
            return media_analysis_batch_job_status(
                project_root,
                str(job_id),
                include_clips=_media_analysis_bool(p.get("include_clips", p.get("includeClips")), True),
                include_events=_media_analysis_bool(p.get("include_events", p.get("includeEvents")), True),
            )
        if action == "run_batch_job_slice":
            job_id = p.get("job_id") or p.get("jobId") or p.get("id")
            if not job_id:
                return _err("run_batch_job_slice requires job_id")
            return run_media_analysis_batch_job_slice(
                project_root,
                str(job_id),
                max_clips=p.get("max_clips", p.get("maxClips", 1)),
                max_seconds=p.get("max_seconds", p.get("maxSeconds")),
                capabilities=detect_media_analysis_capabilities(),
            )
        if action == "cancel_batch_job":
            job_id = p.get("job_id") or p.get("jobId") or p.get("id")
            if not job_id:
                return _err("cancel_batch_job requires job_id")
            return cancel_media_analysis_batch_job(project_root, str(job_id))
        if action == "resume_batch_job":
            job_id = p.get("job_id") or p.get("jobId") or p.get("id")
            if not job_id:
                return _err("resume_batch_job requires job_id")
            return resume_media_analysis_batch_job(project_root, str(job_id))
        return cleanup_media_analysis_artifacts(project_root, frames_only=bool(p.get("frames_only", True)))

    if action == "review_timeline_markers":
        tl = proj.GetCurrentTimeline()
        if not tl:
            return _err("No current timeline")
        review = _timeline_marker_thumbnail_review(proj, tl, p)
        if not review.get("success"):
            return review
        vision = p.get("vision") or {}
        if _media_analysis_bool(vision.get("enabled"), default=False):
            provider = vision.get("provider") or HOST_CHAT_PATHS_PROVIDER
            if provider in HOST_CHAT_VISION_PROVIDERS:
                review["vision_review"] = _media_analysis_host_chat_image_review_payload(
                    review.get("path"),
                    {
                        "timeline": {"name": tl.GetName(), "id": tl.GetUniqueId()},
                        "samples": review.get("samples", []),
                        "review_prompt": review.get("review_prompt"),
                    },
                    vision,
                )
            else:
                review["vision_review"] = {
                    "success": False,
                    "status": "skipped",
                    "provider": provider,
                    "reason": f"Timeline marker image review uses host_chat_paths; unknown provider '{provider}'.",
                }
        return review

    if action == "detect_sync_events":
        records, normalized_target, warnings, target_err = _media_analysis_sync_event_records(proj, p)
        if target_err:
            if warnings:
                target_err["warnings"] = warnings
            return target_err
        result = detect_media_sync_events(records or [], p)
        result["target"] = normalized_target
        if warnings:
            result.setdefault("warnings", [])
            result["warnings"] = warnings + list(result.get("warnings") or [])
        return result

    if action == "add_sync_event_markers":
        detection = p.get("detection") or p.get("detections")
        if not isinstance(detection, dict):
            records, normalized_target, warnings, target_err = _media_analysis_sync_event_records(proj, p)
            if target_err:
                if warnings:
                    target_err["warnings"] = warnings
                return target_err
            detection = detect_media_sync_events(records or [], p)
            detection["target"] = normalized_target
            if warnings:
                detection.setdefault("warnings", [])
                detection["warnings"] = warnings + list(detection.get("warnings") or [])
        return _apply_sync_event_markers(proj, detection, p)

    if action == "publish_clip_metadata":
        return await _publish_clip_metadata_from_analysis(proj, p, ctx)

    if action == "commit_vision":
        visual = p.get("visual") or p.get("visual_analysis") or p.get("visualAnalysis")
        if visual is None:
            return _err("commit_vision requires `visual` (JSON object matching the vision schema)")
        clip_id = p.get("clip_id") or p.get("clipId")
        file_path = p.get("file_path") or p.get("filePath") or p.get("path")
        clip_dir = p.get("clip_dir") or p.get("clipDir")
        vision_token = p.get("vision_token") or p.get("visionToken")

        analysis_root = p.get("analysis_root") or p.get("analysisRoot") or p.get("project_root") or p.get("projectRoot")
        if not analysis_root:
            source_paths = [file_path] if file_path else None
            root_info = resolve_media_analysis_output_root(source_paths=source_paths, project_name=project_name, project_id=project_id)
            if not root_info.get("success"):
                return root_info
            analysis_root = root_info.get("project_root")

        commit = commit_visual_analysis(
            project_root=analysis_root,
            visual=visual,
            clip_id=str(clip_id) if clip_id else None,
            file_path=file_path,
            clip_dir=clip_dir,
            vision_token=str(vision_token) if vision_token else None,
        )
        if not commit.get("success"):
            return commit

        record = commit.get("record") or {}
        committed_clip_id = record.get("clip_id") or clip_id
        if committed_clip_id and _media_analysis_metadata_writeback_enabled(p):
            publish_params = _media_analysis_apply_setup_defaults("publish_clip_metadata", {
                **p,
                "target": {"type": "clip", "clip_id": str(committed_clip_id)},
            })
            publish_params["target"] = {"type": "clip", "clip_id": str(committed_clip_id)}
            if not _has_any_param(publish_params, "dry_run", "dryRun"):
                publish_params["dry_run"] = False
            if not _has_any_param(publish_params, "confirm", "confirmed", "apply"):
                publish_params["confirm"] = True
            committed_report_path = commit.get("analysis_json")
            if committed_report_path and os.path.isfile(committed_report_path):
                publish_params["_pre_resolved_report_paths"] = {
                    str(committed_clip_id): committed_report_path,
                }
            commit["metadata_publish"] = await _publish_clip_metadata_from_analysis(proj, publish_params, ctx)
        else:
            commit["metadata_publish"] = {
                "success": True,
                "status": "skipped",
                "reason": (
                    "Metadata writeback skipped — commit_vision called against a non-Resolve clip "
                    "or with publish_metadata=false. Analysis files were updated on disk."
                ),
            }
        return commit

    if action == "start_batch_job":
        p["dry_run"] = False
        p["persist"] = True
        p["session_only"] = False
        p["cleanup_frames"] = _media_analysis_bool(p.get("cleanup_frames", p.get("cleanupFrames")), True)
        p["target"] = _media_analysis_target_dict(p.get("target"), p)
        if p["target"].get("_invalid_target"):
            return _err(p["target"]["_invalid_target"])
        mp = None
        target_type = str(p["target"].get("type") or p.get("target_type") or "clip").strip().lower()
        if target_type != "file":
            mp = proj.GetMediaPool()
            if not mp:
                return _err("Failed to get MediaPool")
        records, normalized_target, warnings, target_err = _media_analysis_records_from_target(mp, p, project=proj)
        if target_err:
            if warnings:
                target_err["warnings"] = warnings
            return target_err
        created = create_media_analysis_batch_job(
            project_name=project_name,
            project_id=project_id,
            records=records or [],
            target=normalized_target,
            params=p,
            capabilities=detect_media_analysis_capabilities(),
            name=p.get("name") or p.get("job_name") or p.get("jobName"),
        )
        if warnings:
            created.setdefault("warnings", warnings)
        return created

    if action in {"analyze_file", "analyze_clip", "analyze_bin", "analyze_project", "analyze_timeline", "analyze_sequence"}:
        dry_run_default = bool(_media_analysis_effective_preferences().get("dry_run_first_default"))
        p["dry_run"] = _media_analysis_bool(p.get("dry_run"), dry_run_default)
        target = _media_analysis_target_dict(p.get("target"), p)
        if target.get("_invalid_target"):
            return _err(target["_invalid_target"])
        if action == "analyze_file":
            target.update({"type": "file", "path": p.get("path") or p.get("file_path") or p.get("filePath") or target.get("path")})
        elif action == "analyze_clip":
            target.update({"type": "clip", "clip_id": p.get("clip_id") or target.get("clip_id"), "selected": p.get("selected", target.get("selected", False))})
        elif action == "analyze_bin":
            target.update({"type": "bin", "path": p.get("bin_path") or p.get("path") or target.get("path") or "Master", "recursive": p.get("recursive", target.get("recursive", True))})
        elif action == "analyze_project":
            target.update({"type": "project", "recursive": p.get("recursive", target.get("recursive", True))})
        elif action in {"analyze_timeline", "analyze_sequence"}:
            target.update({
                "type": "sequence",
                "timeline_index": p.get("timeline_index") or p.get("timelineIndex") or target.get("timeline_index") or target.get("timelineIndex"),
                "track_types": p.get("track_types") or p.get("trackTypes") or target.get("track_types") or target.get("trackTypes"),
            })
        p["target"] = target
        # E3 — `prefer_handle` opt-in. When true AND this isn't a dry-run,
        # divert to the durable batch-job machinery so the call returns a
        # job_id immediately instead of blocking on vision/transcription.
        # Default false: existing blocking semantics are preserved.
        # The start_batch_job handler lives ABOVE this block in the dispatch
        # chain, so we can't just rewrite `action` and fall through — we
        # re-enter the tool with the rewritten action via await so the
        # handler chain restarts from the top.
        if _media_analysis_bool(p.get("prefer_handle"), False) and not p.get("dry_run"):
            return await media_analysis("start_batch_job", p, ctx)
        action = "plan"

    if action == "coverage_report":
        # Pure-read coverage assessment. Editorial / color / online / producer
        # contexts call this first and lead recommendations with `evidence_base`.
        target = _media_analysis_target_dict(p.get("target"), p)
        if target.get("_invalid_target"):
            return _err(target["_invalid_target"])
        target_type = str(target.get("type") or p.get("target_type") or "clip").strip().lower()
        mp = None
        if target_type != "file":
            mp = proj.GetMediaPool()
            if not mp:
                return _err("Failed to get MediaPool")
        p["target"] = target
        records, normalized_target, warnings, target_err = _media_analysis_records_from_target(mp, p, project=proj)
        if target_err:
            if warnings:
                target_err["warnings"] = warnings
            return target_err
        coverage = build_media_analysis_coverage_report(
            project_name=project_name,
            project_id=project_id,
            records=records or [],
            target=normalized_target,
            params=p,
            capabilities=_media_analysis_capabilities_for_request(ctx),
        )
        if warnings:
            coverage["warnings"] = warnings
        return coverage

    if action == "plan":
        p["dry_run"] = _media_analysis_bool(p.get("dry_run"), True)
        persist = _media_analysis_bool(p.get("persist"), False)
        if "session_only" in p:
            p["session_only"] = _media_analysis_bool(p.get("session_only"), False)
        else:
            p["session_only"] = (not p["dry_run"]) and (not persist)
        if persist:
            p["session_only"] = False
        if p["session_only"] and not p["dry_run"]:
            p["cleanup_frames"] = _media_analysis_bool(p.get("cleanup_frames"), True)
            if not p.get("analysis_root"):
                p["_reuse_default_analysis_root"] = True
                session_root = tempfile.mkdtemp(prefix="davinci-resolve-mcp-analysis-session-")
                p["analysis_root"] = session_root
                p["_session_temp_base_root"] = session_root

        target = _media_analysis_target_dict(p.get("target"), p)
        if target.get("_invalid_target"):
            return _err(target["_invalid_target"])
        target_type = str(target.get("type") or p.get("target_type") or "clip").strip().lower()
        mp = None
        if target_type != "file":
            mp = proj.GetMediaPool()
            if not mp:
                return _e2_wrap(_err("Failed to get MediaPool"))
        records, normalized_target, warnings, target_err = _media_analysis_records_from_target(mp, p, project=proj)
        if target_err:
            if warnings:
                target_err["warnings"] = warnings
            return _e2_wrap(target_err)
        caps = _media_analysis_capabilities_for_request(ctx)
        plan = build_media_analysis_plan(
            project_name=project_name,
            project_id=project_id,
            records=records or [],
            target=normalized_target,
            params=p,
            capabilities=caps,
        )
        if p.get("_setup_defaults_applied"):
            plan["setup_defaults_applied"] = p.get("_setup_defaults_applied")
        if warnings:
            plan["warnings"] = warnings
        if (
            plan.get("capability_gaps")
            and not bool(p.get("dry_run", True))
            and media_analysis_plan_requires_capabilities(plan)
        ):
            return _e2_wrap(_media_analysis_missing_capabilities_response(plan))
        if not bool(p.get("dry_run", True)):
            executed = await execute_media_analysis_plan_async(
                plan,
                params=p,
                capabilities=caps,
            )
            # V2 P9: compact the wire response unless verbose=true. Full payload
            # is always on disk under analysis_json. Saves 100k+ chars per call
            # and avoids forcing consumers to file-shovel via jq.
            verbose = _media_analysis_bool(p.get("verbose", p.get("verboseResponse", p.get("include_full_manifest"))), False)
            result = {
                "success": bool(executed.get("success")),
                "plan": plan,
                "manifest": _compact_manifest_for_response(executed, verbose=verbose),
                "response_format": "verbose" if verbose else "compact",
            }
            if executed.get("status"):
                result["status"] = executed.get("status")
            if executed.get("reuse_summary"):
                result["reuse_summary"] = executed.get("reuse_summary")
            if executed.get("error"):
                result["error"] = executed.get("error")
            if executed.get("status") == "reuse_blocked":
                result["blocked_clip_count"] = executed.get("blocked_clip_count")
                return _e2_wrap(result)
            if executed.get("vision_pending"):
                result["status"] = "pending_host_vision_analysis"
                result["pending_action"] = executed.get("pending_action")
                result["next_step_instructions"] = (
                    "Visual analysis is deferred to the host chat. For each clip in "
                    "manifest.clips with vision_status='pending_host_analysis', open "
                    "analysis_json on disk to retrieve the full visual.prompt, "
                    "schema_reference, frame_paths[] and shot_table[]. Read those frames "
                    "as local images, produce a JSON object matching the schema, and call "
                    "media_analysis(action='commit_vision', params={clip_id, visual, vision_token}). "
                    "Resolve clip-level metadata (Description, Keywords, Comments) is published "
                    "automatically after commit_vision finalizes. Pass verbose=true to inline the "
                    "full visual payload in the response instead of reading from disk."
                )
                return _e2_wrap(result)
            if (
                result["success"]
                and target_type != "file"
                and not _media_analysis_bool(p.get("dry_run"), True)
                and _media_analysis_metadata_writeback_enabled(p)
            ):
                publish_params = _media_analysis_apply_setup_defaults("publish_clip_metadata", {
                    **p,
                    "target": normalized_target,
                })
                publish_params["target"] = normalized_target
                if not _has_any_param(publish_params, "dry_run", "dryRun"):
                    publish_params["dry_run"] = False
                publish_result = await _publish_clip_metadata_from_analysis(proj, publish_params, ctx)
                result["metadata_publish"] = _compact_metadata_publish_for_response(publish_result, verbose=verbose)
                result["success"] = bool(result["success"] and publish_result.get("success"))
            return _e2_wrap(result)
        # D3 — dry-run plan path: seed the partial-success keys with defaults
        # so callers can rely on the schema being uniform between dry-run plans
        # and executed manifests. No clips have run yet, so completed/failed
        # are both empty.
        plan.setdefault("partial_success", False)
        plan.setdefault("completed_clip_ids", [])
        plan.setdefault("failed_clip_ids", [])
        return _e2_wrap(plan)

    return _unknown(action, [
        "capabilities",
        "recheck_capabilities",
        "install_guidance",
        "resolve_output_root",
        "plan",
        "analyze_file",
        "analyze_clip",
        "analyze_bin",
        "analyze_project",
        "analyze_sequence",
        "analyze_timeline",
        "detect_sync_events",
        "add_sync_event_markers",
        "publish_clip_metadata",
        "commit_vision",
        "review_timeline_markers",
        "summarize",
        "get_report",
        "build_index",
        "rebuild_index",
        "index_status",
        "query_index",
        "start_batch_job",
        "run_batch_job_slice",
        "batch_job_status",
        "list_batch_jobs",
        "cancel_batch_job",
        "resume_batch_job",
        "cleanup_artifacts",
        "get_panel_state",
        "set_panel_state",
        "session_start_context",
        "update_shot_field",
        "update_clip_field",
        "get_field_history",
        "revert_field",
        "list_corrections",
        "db_status",
        "db_ingest",
        "deepen",
        "commit_shot_vision",
        "vision_pending_sweep",
        "build_embeddings",
        "find_similar",
        "detect_entities",
        "commit_entities",
        "list_entities",
        "prepare_bin_briefing",
        "commit_bin_summary",
        "detect_shot_relationships",
        "commit_shot_relationships",
        "list_shot_relationships",
        "get_caps",
        "set_caps_preset",
        "get_usage",
        "coverage_report",
        "get_resolve_ai_usage",
        "get_ai_governance",
        "set_ai_governance",
    ])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 16: timeline
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
def timeline_versioning(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Timeline version-on-mutate, archive, rollback, and brain-edit history (C6).

    Every destructive timeline op auto-archives the working timeline to the Archive
    bin under an analysis_run_id; these actions let you inspect and control that.

    Actions:
      begin_run(label?, initiator?, analysis_run_id?) -> {success, analysis_run_id, label, initiator, started_at}
        Open a run. Subsequent destructive calls without an explicit
        analysis_run_id auto-thread this one — so a multi-step brain operation
        creates ONE archive instead of N. Pair with end_run to capture the
        cumulative metric delta.
      end_run(analysis_run_id?) -> {success, analysis_run_id, ended_at, summary}
        Close the active run (or a specific one). Aggregates brain_edits into
        per-metric rollup in analysis_runs.summary_json.
      list_runs(limit?) -> {success, runs}
        Recent runs with their summaries, newest first.
      archive_current(reason?, analysis_run_id?) -> {success, timeline_name, archived_timeline_name, version, archive_bin, row_id}
        Manually checkpoint the current timeline. If analysis_run_id is supplied
        and that run already archived the current timeline, this is a no-op.
      list_versions(timeline_name) -> [{version, archived_timeline_name, created_at, ...}]
        Version chain for `timeline_name`, oldest first. Includes any retention-
        collapsed versions (drt_export_path populated).
      diff_timelines(from_timeline, to_timeline) -> {added, removed, moved, trimmed, summary}
        Structural diff between two LIVE timelines by name (read-only; no
        archived versions needed). Built for edit-engine variants — tighten/
        selects produce new-name timelines with no shared version chain.
      get_history(timeline_name?, analysis_run_id?, limit?) -> [{edit_type, target_metric, before_value, after_value, delta, ...}]
        Brain-edit history. Filter by timeline_name or analysis_run_id; defaults
        to the most recent 50 across the project.
      rollback(timeline_name, version, analysis_run_id?) -> {success, restored_timeline_name, archive_of_previous}
        Restore an archived version. Archives current state first; restored copy
        gets a "_rolled_back_<HHMMSS>" suffix.
      prune(timeline_name, keep_n=10) -> {success, pruned, kept, details}
        Collapse old versions to .drt exports under _soul/timeline_versions/<slug>/,
        delete the archived timeline from the bin, keep the DB row for rollback.
      registry() -> {entries, registry_path}
        Read the cross-project brain_edits registry that lives one level above
        each project root (analogous to analysis_registry.json).
    """
    r = get_resolve()
    if r is None:
        return _err("Resolve not available")
    ctx = _destructive_versioning_provider()
    if ctx is None:
        return _err("No current project / can't resolve project root")
    resolve_h, project_h, project_root, project_name = ctx
    p = params or {}

    if action == "begin_run":
        return _analysis_runs.begin_run(
            project_root=project_root,
            label=p.get("label"),
            initiator=p.get("initiator"),
            analysis_run_id=p.get("analysis_run_id"),
        )
    if action == "end_run":
        return _analysis_runs.end_run(
            project_root=project_root,
            analysis_run_id=p.get("analysis_run_id"),
        )
    if action == "list_runs":
        return {
            "success": True,
            "runs": _analysis_runs.list_runs(project_root, limit=_safe_int(p.get("limit"), 50, minimum=1, maximum=1000)),
        }
    if action == "archive_current":
        return _timeline_versioning.archive_current_timeline(
            resolve=resolve_h,
            project=project_h,
            project_root=project_root,
            reason=p.get("reason"),
            analysis_run_id=p.get("analysis_run_id"),
        )
    if action == "list_versions":
        if not p.get("timeline_name"):
            return _err("timeline_name required")
        rows = _timeline_versioning.list_timeline_versions(
            project_root=project_root,
            timeline_name=str(p["timeline_name"]),
        )
        return {"success": True, "versions": rows}
    if action == "diff_versions":
        if not p.get("timeline_name") or "from_version" not in p or "to_version" not in p:
            return _err("timeline_name, from_version, to_version required")
        try:
            from_version = int(p["from_version"])
            to_version = int(p["to_version"])
        except (TypeError, ValueError):
            return _err("from_version and to_version must be integers")
        return {
            "success": True,
            **_timeline_versioning.diff_versions(
                project_root=project_root,
                timeline_name=str(p["timeline_name"]),
                from_version=from_version,
                to_version=to_version,
            ),
        }
    if action == "diff_timelines":
        if not p.get("from_timeline") or not p.get("to_timeline"):
            return _err("from_timeline and to_timeline required")
        return _timeline_versioning.diff_timelines(
            project=project_h,
            from_timeline=str(p["from_timeline"]),
            to_timeline=str(p["to_timeline"]),
        )
    if action == "get_history":
        rows = _brain_edits.get_brain_edit_history(
            project_root=project_root,
            timeline_name=p.get("timeline_name"),
            analysis_run_id=p.get("analysis_run_id"),
            limit=_safe_int(p.get("limit"), 50, minimum=1, maximum=1000),
        )
        return {"success": True, "edits": rows}
    if action == "rollback":
        if not p.get("timeline_name") or "version" not in p:
            return _err("timeline_name and version required")
        try:
            version = int(p["version"])
        except (TypeError, ValueError):
            return _err("version must be an integer")
        if version < 0:
            return _err("version must be >= 0")
        return _timeline_versioning.rollback_to_version(
            resolve=resolve_h,
            project=project_h,
            project_root=project_root,
            timeline_name=str(p["timeline_name"]),
            version=version,
            analysis_run_id=p.get("analysis_run_id"),
        )
    if action == "prune":
        if not p.get("timeline_name"):
            return _err("timeline_name required")
        return _timeline_versioning.prune_archived_versions(
            resolve=resolve_h,
            project=project_h,
            project_root=project_root,
            timeline_name=str(p["timeline_name"]),
            keep_n=_safe_int(p.get("keep_n"), 10, minimum=1, maximum=1000),
        )
    if action == "registry":
        return {"success": True, **_brain_edits.read_brain_edits_registry(project_root)}
    if action == "media_pool_changes":
        return {
            "success": True,
            "changes": _media_pool_changes.get_media_pool_change_history(
                project_root=project_root,
                analysis_run_id=p.get("analysis_run_id"),
                action=p.get("media_pool_action"),
                limit=_safe_int(p.get("limit"), 50, minimum=1, maximum=1000),
            ),
        }
    return _err(f"Unknown action: {action}")


def _edit_engine_collect_items(tl, *, track_index: Optional[int] = None) -> List[Dict[str, Any]]:
    """Serialize video timeline items with the source mapping the planner needs."""
    rows: List[Dict[str, Any]] = []
    track_count = int(tl.GetTrackCount("video") or 0)
    indices = [int(track_index)] if track_index else range(1, track_count + 1)
    for index in indices:
        try:
            items = tl.GetItemListInTrack("video", index) or []
        except Exception:
            continue
        for item in items:
            try:
                row: Dict[str, Any] = {
                    "track_index": index,
                    "item_name": item.GetName(),
                    "timeline_start_frame": _frame_int(item.GetStart()),
                    "timeline_end_frame": _frame_int(item.GetEnd()),
                }
            except Exception:
                continue
            source_start = None
            if _has_method(item, "GetSourceStartFrame"):
                try:
                    source_start = _frame_int(item.GetSourceStartFrame())
                except Exception:
                    source_start = None
            if source_start is None and _has_method(item, "GetLeftOffset"):
                try:
                    source_start = _frame_int(item.GetLeftOffset())
                except Exception:
                    source_start = None
            row["source_start_frame"] = source_start or 0
            try:
                mpi = item.GetMediaPoolItem()
                if mpi is not None:
                    row["media_ref"] = mpi.GetUniqueId()
                    try:
                        row["media_path"] = mpi.GetClipProperty("File Path")
                    except Exception:
                        pass
            except Exception:
                pass
            # Linked audio track indices so the planner can mirror kept ranges
            # onto sound (see #67 — tighten variants were coming out silent).
            try:
                audio_indices, _audio_note = _edit_engine_linked_audio_tracks(
                    tl, item, row["timeline_start_frame"], row["timeline_end_frame"]
                )
                row["audio_track_indices"] = audio_indices
            except Exception:
                row["audio_track_indices"] = []
            rows.append(row)
    return rows


def _edit_engine_timeline_fps(tl) -> float:
    try:
        fps = float(tl.GetSetting("timelineFrameRate") or 0)
        return fps if fps > 0 else 24.0
    except Exception:
        return 24.0


def _edit_engine_capture(tl) -> Dict[str, Any]:
    """Duration/clip-count readback for execute results."""
    out: Dict[str, Any] = {}
    try:
        out["duration_seconds"] = _brain_edits.capture_metric(_brain_edits.METRIC_DURATION_SECONDS, tl)
        out["clip_count"] = _brain_edits.capture_metric(_brain_edits.METRIC_CLIP_COUNT, tl)
    except Exception:
        pass
    return out


def _edit_engine_track_counts(tl) -> Dict[str, int]:
    """Per-track-type item counts — the swap symmetry signal in readback."""
    counts: Dict[str, int] = {}
    for tt in ("video", "audio"):
        total = 0
        try:
            n = int(tl.GetTrackCount(tt) or 0)
        except Exception:
            n = 0
        for ti in range(1, n + 1):
            try:
                total += len(tl.GetItemListInTrack(tt, ti) or [])
            except Exception:
                continue
        counts[tt] = total
    return counts


def _edit_engine_find_slot_item(tl, track_index: int, slot_start: int, slot_end: int):
    """The video item occupying exactly [slot_start, slot_end] on a track."""
    try:
        for cand in (tl.GetItemListInTrack("video", int(track_index)) or []):
            if _frame_int(cand.GetStart()) == slot_start and _frame_int(cand.GetEnd()) == slot_end:
                return cand
    except Exception:
        pass
    return None


def _edit_engine_linked_audio_tracks(
    tl, target_item, slot_start: int, slot_end: int,
) -> Tuple[List[int], str]:
    """Audio track indices carrying the target item's linked audio.

    Prefers GetLinkedItems; falls back to matching slot-overlapping audio
    items that share the target's media-pool source. ([], note) when there is
    no linked audio (audio-only handling stays untouched) or no target item.
    """
    if target_item is None:
        return [], "target video item not found on its track; audio left untouched"
    linked_ids: set = set()
    get_linked = getattr(target_item, "GetLinkedItems", None)
    if callable(get_linked):
        try:
            for linked_item in (get_linked() or []):
                uid = getattr(linked_item, "GetUniqueId", None)
                if callable(uid):
                    linked_ids.add(str(uid()))
        except Exception:
            linked_ids = set()
    target_media_id = None
    try:
        mpi = target_item.GetMediaPoolItem()
        if mpi is not None:
            target_media_id = str(mpi.GetUniqueId())
    except Exception:
        target_media_id = None
    if not linked_ids and not target_media_id:
        return [], "GetLinkedItems unavailable and no media id to match; audio left untouched"

    indices: List[int] = []
    try:
        audio_tracks = int(tl.GetTrackCount("audio") or 0)
    except Exception:
        audio_tracks = 0
    for ti in range(1, audio_tracks + 1):
        try:
            items = tl.GetItemListInTrack("audio", ti) or []
        except Exception:
            continue
        for cand in items:
            try:
                c_start = _frame_int(cand.GetStart())
                c_end = _frame_int(cand.GetEnd())
            except Exception:
                continue
            if c_start is None or c_end is None or c_start >= slot_end or c_end <= slot_start:
                continue
            is_linked = False
            if linked_ids:
                uid = getattr(cand, "GetUniqueId", None)
                if callable(uid):
                    try:
                        is_linked = str(uid()) in linked_ids
                    except Exception:
                        is_linked = False
            if not is_linked and target_media_id:
                try:
                    c_mpi = cand.GetMediaPoolItem()
                    is_linked = c_mpi is not None and str(c_mpi.GetUniqueId()) == target_media_id
                except Exception:
                    is_linked = False
            if is_linked and ti not in indices:
                indices.append(ti)
    if not indices:
        return [], "no linked audio found for the target item"
    return indices, ""


@mcp.tool()
@_destructive_op("edit_engine")
def edit_engine(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Evidence-driven edit loops (Phase E): selects assembly, tighten, swap.

    Every loop is plan → confirm → execute. plan_* actions are dry-run by
    construction: they query the DB-canonical analysis store and return a
    per-decision rationale plus a stored plan_id. execute_* actions require a
    confirm_token, run under the version-on-mutate hook (the timeline is
    archived first), and return before/after metrics as readback.

    Actions:
    - plan_selects(min_select_potential?, max_duration_seconds?, timeline_name?,
      max_shots?, handle_seconds?, analysis_root?) — rank shots by deep-tier
      select potential (clip-level fallback), story-spine order. Additive.
    - execute_selects(plan_id, confirm_token?) — creates a NEW selects timeline
      from the plan's clip in/out ranges. Nothing existing is touched.
    - plan_tighten(timeline_name?, target_ratio?, min_pause_seconds?,
      handle_seconds?, include_audio?) — dead-air lifts from transcript-gap
      evidence for the current (or named) timeline. Kept ranges mirror onto the
      items' linked audio tracks by default so the variant is audible; pass
      include_audio=false for a video-only (silent) assembly.
    - execute_tighten(plan_id, confirm_token?) — assembles a tightened VARIANT
      timeline from the plan's keep ranges (video + mirrored audio), never
      mutating the original. Readback includes an audio_accounting block.
    - plan_swap(track_index?, timeline_start_frame | item_name, kind?, limit?)
      — alternates for one timeline item via the similarity index.
    - execute_swap(plan_id, alternate_index, confirm_token?) — replaces the
      item in place (lift + positioned append, same slot) on the current
      timeline (version-archived first).
    - list_plans(limit?) / get_plan(plan_id)
    """
    p = params or {}

    def _project_context(*, need_resolve: bool) -> Tuple[Optional[Any], Optional[Any], Optional[str], Optional[Dict[str, Any]]]:
        # An explicit analysis_root always wins — the evidence DB the caller
        # analyzed into may differ from the provider's derived root (e.g. a
        # headless analysis keyed by project name only).
        analysis_root = p.get("analysis_root") or p.get("analysisRoot")
        explicit_root = str(analysis_root) if analysis_root and os.path.isdir(str(analysis_root)) else None
        vctx = _destructive_versioning_provider()
        if vctx is not None:
            r, proj, project_root, _name = vctx
            return r, proj, explicit_root or project_root, None
        if not need_resolve and explicit_root:
            return None, None, explicit_root, None
        return None, None, None, _err(
            "No project context — open a Resolve project (or pass analysis_root for plan_selects)."
        )

    if action == "list_plans":
        _r, _proj, project_root, err = _project_context(need_resolve=False)
        if err:
            return err
        return _edit_engine_mod.list_plans(project_root, limit=int(p.get("limit") or 20))

    if action == "get_plan":
        _r, _proj, project_root, err = _project_context(need_resolve=False)
        if err:
            return err
        plan = _edit_engine_mod.load_plan(project_root, str(p.get("plan_id") or p.get("planId") or ""))
        if not plan:
            return _err("plan not found")
        if plan.get("_corrupt"):
            return _err("plan file failed its fingerprint check — re-plan")
        return {"success": True, "plan": plan}

    if action == "plan_selects":
        _r, _proj, project_root, err = _project_context(need_resolve=False)
        if err:
            return err
        return _edit_engine_mod.plan_selects(
            project_root,
            timeline_name=p.get("timeline_name") or p.get("timelineName"),
            max_duration_seconds=p.get("max_duration_seconds") or p.get("maxDurationSeconds"),
            min_select_potential=str(p.get("min_select_potential") or p.get("minSelectPotential") or "medium"),
            handle_seconds=float(p.get("handle_seconds") or p.get("handleSeconds") or _edit_engine_mod.DEFAULT_HANDLE_SECONDS),
            max_shots=int(p.get("max_shots") or p.get("maxShots") or 60),
        )

    if action == "plan_tighten":
        _r, proj, project_root, err = _project_context(need_resolve=True)
        if err:
            return err
        tl = (_find_timeline_by_name(proj, p.get("timeline_name") or p.get("timelineName"))[0] if (p.get("timeline_name") or p.get("timelineName")) else proj.GetCurrentTimeline())
        if not tl:
            return _err("Timeline not found")
        items = _edit_engine_collect_items(tl, track_index=p.get("track_index") or p.get("trackIndex"))
        return _edit_engine_mod.plan_tighten(
            project_root,
            items=items,
            timeline_name=tl.GetName(),
            timeline_fps=_edit_engine_timeline_fps(tl),
            target_ratio=p.get("target_ratio") or p.get("targetRatio"),
            min_pause_seconds=float(p.get("min_pause_seconds") or p.get("minPauseSeconds") or _edit_engine_mod.DEFAULT_MIN_PAUSE_SECONDS),
            handle_seconds=float(p.get("handle_seconds") or p.get("handleSeconds") or _edit_engine_mod.DEFAULT_HANDLE_SECONDS),
            include_audio=str(p.get("include_audio", p.get("includeAudio", True))).strip().lower() not in {"false", "0", "no", "none", "off"},
        )

    if action == "plan_swap":
        _r, proj, project_root, err = _project_context(need_resolve=True)
        if err:
            return err
        tl = (_find_timeline_by_name(proj, p.get("timeline_name") or p.get("timelineName"))[0] if (p.get("timeline_name") or p.get("timelineName")) else proj.GetCurrentTimeline())
        if not tl:
            return _err("Timeline not found")
        items = _edit_engine_collect_items(tl, track_index=p.get("track_index") or p.get("trackIndex"))
        target = None
        wanted_start = p.get("timeline_start_frame") if p.get("timeline_start_frame") is not None else p.get("timelineStartFrame")
        wanted_name = p.get("item_name") or p.get("itemName")
        for row in items:
            if wanted_start is not None and int(row["timeline_start_frame"]) == int(wanted_start):
                target = row
                break
            if wanted_name and row.get("item_name") == wanted_name:
                target = row
                break
        if target is None:
            return _err(
                "Target item not found — pass timeline_start_frame or item_name "
                f"(items: {[{'name': r.get('item_name'), 'start': r['timeline_start_frame']} for r in items[:20]]})"
            )
        return _edit_engine_mod.plan_swap(
            project_root,
            item=target,
            timeline_name=tl.GetName(),
            timeline_fps=_edit_engine_timeline_fps(tl),
            kind=str(p.get("kind") or "visual"),
            limit=int(p.get("limit") or 5),
        )

    if action == "execute_selects":
        _r, proj, project_root, err = _project_context(need_resolve=True)
        if err:
            return err
        plan = _edit_engine_mod.load_plan(project_root, str(p.get("plan_id") or p.get("planId") or ""))
        if not plan or plan.get("_corrupt"):
            return _err("plan not found (or failed its fingerprint check) — re-plan")
        if plan.get("kind") != "selects":
            return _err(f"plan {plan.get('plan_id')} is a {plan.get('kind')} plan")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="edit_engine.execute_selects", params=p,
                preview={
                    "operation": "edit_engine.execute_selects",
                    "warning": "Creates a NEW selects timeline; no existing timeline is modified.",
                    "timeline_name": plan.get("timeline_name"),
                    "decision_count": len(plan.get("decisions") or []),
                    "estimated_duration_seconds": plan.get("estimated_duration_seconds"),
                },
            )
        blocked = _consume_confirm_token(action="edit_engine.execute_selects", params=p)
        if blocked:
            return blocked
        mp = proj.GetMediaPool()
        if not mp:
            return _err("No media pool")
        root_folder = mp.GetRootFolder()
        name = str(plan.get("timeline_name") or "Selects")
        if _find_timeline_by_name(proj, name)[0]:
            name = f"{name} {time.strftime('%H%M%S')}"
        tl = mp.CreateEmptyTimeline(name)
        if not tl:
            return _err("Failed to create selects timeline")
        try:
            proj.SetCurrentTimeline(tl)
        except Exception:
            pass
        timeline_start = _timeline_start_frame(tl)
        built = []
        build_errors = []
        record_cursor = 0
        for i, ci in enumerate(plan.get("clip_infos") or []):
            append_ci = dict(ci)
            # Sequential assembly: each select lands after the previous one.
            append_ci.setdefault("record_frame", record_cursor)
            append_ci.setdefault("track_index", 1)
            row, row_err = _build_append_clip_info_dict(root_folder, append_ci, i, timeline_start)
            if row_err:
                build_errors.append({"index": i, "error": row_err.get("error")})
                continue
            built.append(row)
            record_cursor += int(append_ci.get("end_frame", 0)) - int(append_ci.get("start_frame", 0)) + 1
        appended = mp.AppendToTimeline(built) if built else None
        readback = _edit_engine_capture(tl)
        # A diff against a source timeline is meaningless for a fresh assembly;
        # a usage-snapshot summary is the structural readback that fits.
        try:
            usage = _timeline_versioning.capture_timeline_clip_usage(tl)
            by_type: Dict[str, int] = {}
            for usage_row in usage:
                by_type[usage_row["track_type"]] = by_type.get(usage_row["track_type"], 0) + 1
            readback["usage_summary"] = {"items": len(usage), "by_track_type": by_type}
        except Exception:
            pass
        run_id = _analysis_runs.current_run_id()
        try:
            _brain_edits.log_brain_edit(
                project_root=project_root,
                analysis_run_id=run_id or "edit-engine",
                edit_type="edit_engine.selects_result",
                tool_name="edit_engine",
                action_name="execute_selects",
                timeline_after=tl.GetName(),
                target_metric=_brain_edits.METRIC_CLIP_COUNT,
                metric_direction="target_value",
                after_value=readback.get("clip_count"),
                rationale=plan.get("summary"),
                params={"plan_id": plan.get("plan_id")},
                result_summary={"appended": len(built), "build_errors": build_errors},
            )
        except Exception:
            pass
        _edit_engine_mod.mark_plan_executed(project_root, plan["plan_id"], {
            "timeline_name": tl.GetName(),
            "appended": len(built),
            "build_errors": build_errors,
            **readback,
        })
        return {
            "success": bool(appended),
            "timeline_name": tl.GetName(),
            "appended": len(built),
            "build_errors": build_errors,
            "readback": readback,
            "plan_id": plan.get("plan_id"),
        }

    if action == "execute_tighten":
        _r, proj, project_root, err = _project_context(need_resolve=True)
        if err:
            return err
        plan = _edit_engine_mod.load_plan(project_root, str(p.get("plan_id") or p.get("planId") or ""))
        if not plan or plan.get("_corrupt"):
            return _err("plan not found (or failed its fingerprint check) — re-plan")
        if plan.get("kind") != "tighten":
            return _err(f"plan {plan.get('plan_id')} is a {plan.get('kind')} plan")
        lifts = plan.get("lifts") or []
        keep_ranges = plan.get("keep_ranges") or []
        if not keep_ranges:
            return _err("plan has no keep_ranges — re-plan with this version")
        audio_keep_ranges = sum(1 for r in keep_ranges if str(r.get("track_type", "video")).lower() == "audio")
        video_keep_ranges = len(keep_ranges) - audio_keep_ranges
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="edit_engine.execute_tighten", params=p,
                preview={
                    "operation": "edit_engine.execute_tighten",
                    "warning": (
                        "Assembles a tightened VARIANT timeline from the plan's keep "
                        "ranges; the original timeline is not modified."
                    ),
                    "timeline_name": plan.get("timeline_name"),
                    "lift_count": len(lifts),
                    "keep_range_count": len(keep_ranges),
                    "video_keep_range_count": video_keep_ranges,
                    "audio_keep_range_count": audio_keep_ranges,
                    "audio_note": (
                        f"Variant carries audio ({audio_keep_ranges} audio ranges mirror the video cuts)."
                        if audio_keep_ranges
                        else "WARNING: variant is VIDEO-ONLY (silent) — plan has no audio ranges."
                    ),
                    "estimated_removed_seconds": sum(l.get("duration_seconds") or 0 for l in lifts),
                },
            )
        blocked = _consume_confirm_token(action="edit_engine.execute_tighten", params=p)
        if blocked:
            return blocked
        source_tl, _src_index = _find_timeline_by_name(proj, plan.get("timeline_name"))
        if not source_tl:
            return _err(f"Timeline '{plan.get('timeline_name')}' not found")
        before = _edit_engine_capture(source_tl)
        variant_name = f"{plan.get('timeline_name')} — tightened {time.strftime('%H%M%S')}"
        variant = _timeline_create_variant_from_ranges(proj, source_tl, {
            "ranges": keep_ranges,
            "name": variant_name,
        })
        if not variant.get("success"):
            return {"success": False, "error": f"variant assembly failed: {variant.get('error')}", "variant": variant}
        new_tl, _new_index = _find_timeline_by_name(proj, variant.get("name") or variant_name)
        after = _edit_engine_capture(new_tl) if new_tl else {}
        # Cross-name structural diff (source vs variant): trustworthy readback
        # without archived version rows — variants are new-name timelines.
        structural_diff = None
        if new_tl is not None:
            try:
                structural_diff = _timeline_versioning.compare_usage_snapshots(
                    _timeline_versioning.capture_timeline_clip_usage(source_tl),
                    _timeline_versioning.capture_timeline_clip_usage(new_tl),
                )
            except Exception as diff_exc:
                structural_diff = {"error": f"{type(diff_exc).__name__}: {diff_exc}"}
        run_id = _analysis_runs.current_run_id()
        try:
            _brain_edits.log_brain_edit(
                project_root=project_root,
                analysis_run_id=run_id or "edit-engine",
                edit_type="edit_engine.tighten_result",
                tool_name="edit_engine",
                action_name="execute_tighten",
                timeline_before=plan.get("timeline_name"),
                timeline_after=variant.get("name") or variant_name,
                target_metric=_brain_edits.METRIC_DURATION_SECONDS,
                metric_direction="decrease",
                before_value=before.get("duration_seconds"),
                after_value=after.get("duration_seconds"),
                rationale=plan.get("summary"),
                params={"plan_id": plan.get("plan_id")},
                result_summary={"keep_ranges": len(keep_ranges), "lifts": len(lifts)},
            )
        except Exception:
            pass
        _edit_engine_mod.mark_plan_executed(project_root, plan["plan_id"], {
            "variant_timeline": variant.get("name") or variant_name,
            "keep_ranges": len(keep_ranges),
            "lifts": len(lifts),
            "before": before,
            "after": after,
        })
        return {
            "success": True,
            "original_timeline": plan.get("timeline_name"),
            "variant_timeline": variant.get("name") or variant_name,
            "lifts_applied": len(lifts),
            "keep_ranges": len(keep_ranges),
            "lift_rationales": [
                {"lift": [l["timeline_start_frame"], l["timeline_end_frame"]], "rationale": l.get("rationale")}
                for l in lifts
            ],
            "readback": {
                "before": before,
                "after": after,
                "removed_seconds": (
                    round(before["duration_seconds"] - after["duration_seconds"], 2)
                    if before.get("duration_seconds") is not None and after.get("duration_seconds") is not None
                    else None
                ),
                "structural_diff": structural_diff,
                "audio_accounting": {
                    "planned_audio_ranges": audio_keep_ranges,
                    "planned_video_ranges": video_keep_ranges,
                    "variant_audio_items": sum(
                        1 for it in (variant.get("items") or [])
                        if (it.get("range") or {}).get("media_type") == 2
                    ),
                    "variant_video_items": sum(
                        1 for it in (variant.get("items") or [])
                        if (it.get("range") or {}).get("media_type") == 1
                    ),
                    "note": (
                        "Variant carries audio mirrored from the video cuts."
                        if audio_keep_ranges
                        else "Variant is VIDEO-ONLY (silent) — re-plan with include_audio=True for sound."
                    ),
                },
            },
            "plan_id": plan.get("plan_id"),
        }

    if action == "execute_swap":
        _r, proj, project_root, err = _project_context(need_resolve=True)
        if err:
            return err
        plan = _edit_engine_mod.load_plan(project_root, str(p.get("plan_id") or p.get("planId") or ""))
        if not plan or plan.get("_corrupt"):
            return _err("plan not found (or failed its fingerprint check) — re-plan")
        if plan.get("kind") != "swap":
            return _err(f"plan {plan.get('plan_id')} is a {plan.get('kind')} plan")
        alternates = plan.get("alternates") or []
        try:
            alt_index = int(p.get("alternate_index") if p.get("alternate_index") is not None else p.get("alternateIndex"))
        except (TypeError, ValueError):
            return _err(f"execute_swap requires alternate_index (0-{len(alternates) - 1})")
        if not (0 <= alt_index < len(alternates)):
            return _err(f"alternate_index out of range (0-{len(alternates) - 1})")
        alternate = alternates[alt_index]
        item_block = plan.get("item") or {}
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="edit_engine.execute_swap", params=p,
                preview={
                    "operation": "edit_engine.execute_swap",
                    "warning": (
                        "Replaces one timeline item in place (lift + positioned append). "
                        "A timeline version is archived first."
                    ),
                    "timeline_name": plan.get("timeline_name"),
                    "slot": [item_block.get("timeline_start_frame"), item_block.get("timeline_end_frame")],
                    "replacement": {
                        "clip_name": alternate.get("clip_name"),
                        "shot_index": alternate.get("shot_index"),
                        "score": alternate.get("score"),
                    },
                },
            )
        blocked = _consume_confirm_token(action="edit_engine.execute_swap", params=p)
        if blocked:
            return blocked
        tl, _tl_index = _find_timeline_by_name(proj, plan.get("timeline_name"))
        if not tl:
            return _err(f"Timeline '{plan.get('timeline_name')}' not found")
        try:
            proj.SetCurrentTimeline(tl)
        except Exception:
            pass
        before = _edit_engine_capture(tl)
        before["track_counts"] = _edit_engine_track_counts(tl)
        slot_start = int(item_block.get("timeline_start_frame"))
        slot_end = int(item_block.get("timeline_end_frame"))
        target_track = int(item_block.get("track_index") or 1)
        # Capture the target's linked audio BEFORE the lift so the audio lift
        # is scoped to exactly those tracks (the replacement appends linked
        # video+audio, so both sides of the swap stay symmetric).
        target_item = _edit_engine_find_slot_item(tl, target_track, slot_start, slot_end)
        linked_audio_indices, audio_note = _edit_engine_linked_audio_tracks(
            tl, target_item, slot_start, slot_end,
        )
        lift = _timeline_lift_range_impl(tl, {
            "start_frame": slot_start,
            "end_frame": slot_end,
            "track_types": ["video"],
            "track_indices": [target_track],
            "allow_partial_item_delete": True,
            "ripple": False,
        })
        if not lift.get("success"):
            return {"success": False, "error": f"lift failed: {lift.get('error')}", "lift": lift}
        audio_lift = None
        if linked_audio_indices:
            audio_lift = _timeline_lift_range_impl(tl, {
                "start_frame": slot_start,
                "end_frame": slot_end,
                "track_types": ["audio"],
                "track_indices": linked_audio_indices,
                "allow_partial_item_delete": True,
                "ripple": False,
            })
            if not audio_lift.get("success"):
                return {
                    "success": False,
                    "error": f"linked-audio lift failed: {audio_lift.get('error')}",
                    "lift": lift,
                    "audio_lift": audio_lift,
                }
        mp = proj.GetMediaPool()
        root_folder = mp.GetRootFolder()
        timeline_start = _timeline_start_frame(tl)
        frame_range = alternate.get("source_frame_range") or [0, 0]
        ci = {
            "clip_id": alternate.get("resolve_clip_id"),
            "start_frame": int(frame_range[0]),
            "end_frame": int(frame_range[1]),
            # Item starts come from item.GetStart() — absolute timeline frames.
            "record_frame": int(item_block.get("timeline_start_frame")),
            "record_frame_mode": "absolute",
            "track_index": int(item_block.get("track_index") or 1),
        }
        row, row_err = _build_append_clip_info_dict(root_folder, ci, 0, timeline_start)
        if row_err:
            return {"success": False, "error": f"swap append failed: {row_err.get('error')}", "lifted": lift}
        # No mediaType on the clip info: the replacement appends video+audio
        # linked, mirroring the video + linked-audio lift above.
        appended = mp.AppendToTimeline([row])
        after = _edit_engine_capture(tl)
        after["track_counts"] = _edit_engine_track_counts(tl)
        run_id = _analysis_runs.current_run_id()
        try:
            _brain_edits.log_brain_edit(
                project_root=project_root,
                analysis_run_id=run_id or "edit-engine",
                edit_type="edit_engine.swap_result",
                tool_name="edit_engine",
                action_name="execute_swap",
                timeline_after=tl.GetName(),
                target_metric=_brain_edits.METRIC_CLIP_COUNT,
                metric_direction="target_value",
                before_value=before.get("clip_count"),
                after_value=after.get("clip_count"),
                rationale=(
                    f"Swapped slot {item_block.get('timeline_start_frame')}-"
                    f"{item_block.get('timeline_end_frame')} with "
                    f"{alternate.get('clip_name')} shot {alternate.get('shot_index')}: "
                    f"{alternate.get('rationale')}"
                ),
                params={"plan_id": plan.get("plan_id"), "alternate_index": alt_index},
                result_summary={"appended": bool(appended)},
            )
        except Exception:
            pass
        _edit_engine_mod.mark_plan_executed(project_root, plan["plan_id"], {
            "alternate_index": alt_index,
            "replacement": alternate.get("clip_name"),
            "before": before,
            "after": after,
        })
        readback: Dict[str, Any] = {"before": before, "after": after}
        readback["audio_accounting"] = {
            "linked_audio_tracks_lifted": linked_audio_indices,
            "audio_items_lifted": (audio_lift or {}).get("deleted", 0),
            "video_items_lifted": lift.get("deleted", 0),
            **({"note": audio_note} if audio_note else {}),
        }
        return {
            "success": bool(appended),
            "timeline_name": tl.GetName(),
            "replaced_slot": [item_block.get("timeline_start_frame"), item_block.get("timeline_end_frame")],
            "replacement": {
                "clip_name": alternate.get("clip_name"),
                "shot_index": alternate.get("shot_index"),
                "score": alternate.get("score"),
            },
            "readback": readback,
            "plan_id": plan.get("plan_id"),
        }

    return _unknown(action, [
        "plan_selects",
        "execute_selects",
        "plan_tighten",
        "execute_tighten",
        "plan_swap",
        "execute_swap",
        "list_plans",
        "get_plan",
    ])


@mcp.tool()
@_destructive_op("timeline")
def timeline(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Timeline operations: tracks, clips, import/export, generators, titles.

    PREFER probe_* / *_capabilities / *_boundary_report / *_checked / dry_run variants
    where they exist. Raw mutators are kept for advanced callers but bypass guardrails.
    DESTRUCTIVE actions auto-archive the current timeline (C6); pass strict=true for
    refuse-on-archive-failure behavior on the catastrophic ops.

    Actions:
      list() -> {timelines}
      get_current() -> {name, id, start_frame, end_frame, start_timecode}
      set_current(index) -> {success}  — 1-based index
      get_name() -> {name}
      set_name(name) -> {success}
      get_start_frame() -> {frame}
      get_end_frame() -> {frame}
      get_start_timecode() -> {timecode}
      set_start_timecode(timecode) -> {success}
      get_track_count(track_type) -> {count}  — video, audio, subtitle
      add_track(track_type, options?) -> {success}
        — options dict (newTrackOptions per docs line 327): {audio_type, index}.
          audio_type: 'mono', 'stereo', '5.1', '7.1', 'adaptive1'..'adaptive36' for audio.
          index: 1-based slot; appended if omitted/out of bounds.
      delete_track(track_type, index) -> {success}
        CATASTROPHIC. Deletes a track and all items on it. Strict mode auto-applies.
      get_track_sub_type(track_type, index) -> {sub_type}
      set_track_enable(track_type, index, enabled) -> {success}
      get_track_enabled(track_type, index) -> {enabled}
      set_track_lock(track_type, index, locked) -> {success}
      get_track_locked(track_type, index) -> {locked}
      get_track_name(track_type, index) -> {name}
      set_track_name(track_type, index, name) -> {success}
      get_items(track_type, index) -> {items}
      clip_where(filters|track_type?, track_index?, name_contains?, duration_lt?, duration_gt?) -> {clips, match_count, total_clips}
        Find clips on the current timeline matching named filters (AND). Pass filters
        inline or as a `filters` dict. Live filters: track_type, track_index,
        name_contains, duration_lt, duration_gt (frames). No clip enumeration needed.
      delete_clips(clip_ids, ripple?) -> {success}  — clip_ids: list of unique IDs
        DESTRUCTIVE. ripple=True is CATASTROPHIC (closes the gap; cannot be selectively undone).
      set_clips_linked(clip_ids, linked) -> {success}
      duplicate(name?) -> {success, name}
      duplicate_clips(clip_ids?, selected?, target_track_index?, track_offset?, placement?, record_frame?, record_frame_offset?, copy_properties?, include_linked?) -> {results, count}
      — Video clips only. Re-places the same MediaPool media with the same source trim on the
        current timeline (like Alt-drag) via AppendToTimeline. clip_ids: timeline item unique IDs
        from get_items / get_current_video_item; selected=True uses Resolve's selected/current item
        when available. target_track_index overrides track_offset; placement supports same_time,
        offset, at_playhead, track_above, after_source, and next_gap. copy_properties may include
        transform, crop, composite, audio, retime, clip_color, markers, flags, enabled, cache,
        voice_isolation, fusion, grades, takes, and transitions (reported unsupported by Resolve API).
        include_linked=True duplicates linked audio and restores link state.
        # example: action_help(name='<action_name>')
      copy_clips(...) -> {results, count} — alias for duplicate_clips.
      move_clips(...) -> {results, count, deleted_sources} — duplicate, then delete successfully duplicated sources.
      copy_range/duplicate_range(start_frame, end_frame, record_frame, ...) -> {results, count}
      overwrite_range(start_frame, end_frame, record_frame, ...) -> {results, count}
      lift_range(start_frame, end_frame, allow_partial_item_delete?, ripple?) -> {success, deleted}
        DESTRUCTIVE. Removes items in a record-frame range. ripple=True closes the gap.
      story_spine_report() -> {beats, track_summaries, source_ranges, audio_spine}
      create_variant_from_ranges(name, ranges, markers?, cdl?, dry_run?) -> {success, id, items}
        # example: action_help(name='<action_name>')
      bulk_set_item_properties(ops, dry_run?, readback?) -> {results, op_count}
        # example: action_help(name='<action_name>')
      apply_look_to_items(target_ids, cdl?|copy_from_item_id?, dry_run?) -> {success}
        # example: action_help(name='<action_name>')
      thumbnail_contact_sheet(frames?|max_samples?, analysis_root?) -> {path, samples}
        frames are relative to the timeline start (frame 0 = first frame), like marker frameIds.
      marker_thumbnail_review(max_samples?, analysis_root?) -> {path, samples, review_guidance}
      edit_kernel_capabilities() -> {supported, partially_supported, unsupported}
      probe_edit_kernel_item(clip_ids? selected? timeline_item?) -> {items, count}
      title_property_scan(clip_id|timeline_item_id|timeline_item) -> {properties, text_key_candidates, fusion_comp_count, ...}
        — Undocumented generator/Text+ GetProperty map on an item (keys are not in public API docs).
      set_title_text(clip_id|..., text, property_key?, as_styled_xml?, try_plain_first?, try_heuristic_keys?, readback?) -> {success, property_key?, attempts}
        — SetProperty on a heuristic or explicit key; tries plain string then minimal styled XML unless as_styled_xml=True.
        # example: action_help(name='<action_name>')
      bulk_set_title_text(ops, ...) -> {results, op_count}  — list of set_title_text payloads (same params per op).
      create_compound_clip(clip_ids, info?) -> {success}
      create_fusion_clip(clip_ids) -> {success}
      import_into_timeline(path, options?) -> {success}
        UNSAFE. No path sandboxing. Prefer import_timeline_checked.
      export(path, type, subtype?) -> {success}  — type: AAF, EDL, FCPXML, etc.
        UNSAFE. No path sandboxing. Prefer export_timeline_checked.
      get_setting(name?) -> {settings}
      set_setting(name, value) -> {success}
      insert_generator(name) -> {success}
      insert_fusion_generator(name) -> {success}
      insert_fusion_composition() -> {success}
      insert_ofx_generator(name) -> {success}
      insert_title(name) -> {success}
      insert_fusion_title(name) -> {success}
      get_unique_id() -> {id}
      get_node_graph() -> {available}
      get_media_pool_item() -> {name, id}
      get_transcript(with_timecodes?) -> {text, cue_count, has_subtitles, cues}
        Read the timeline's subtitle track(s) as transcript text.
      propose_cuts(cues?, long_pause_frames?) -> {cuts, cut_count, basis_cue_count, pass, note}
        DRY-RUN. Mechanically detect candidate cuts (filler words, long pauses,
        repeated lines) from the subtitle transcript. Proposes only; applies nothing.
      apply_cuts(cuts, dry_run?, confirm_token?, allow_partial_item_delete?) -> {applied, total, results}
        Apply a CutList (from propose_cuts) as lift/ripple deletes. DRY-RUN by
        default; applying is DESTRUCTIVE — confirm-token gated and a timeline
        version is archived first. Cuts apply latest-first.
      get_mark_in_out() -> {mark}
      set_mark_in_out(mark_in, mark_out, type?) -> {success}
      clear_mark_in_out(type?) -> {success}
      convert_to_stereo() -> {success}
      get_items_in_track(track_type, track_index) -> {items}
      get_voice_isolation_state(track_index) -> {isEnabled, amount}
      set_voice_isolation_state(track_index, state) -> {success}
      extract_source_frame_ranges(handles?, gap_max?, skip_extensions?) -> {timeline_name, frame_ranges, occurrences, ...}
        — Same logic as Pr/extract_timeline_frames.py get_resolve_api_frames: all video clips on the
        current timeline; clip name = basename of Media Pool File Path when set; skips audio extensions.
        source_range_final and frame_ranges tuples are inclusive/inclusive endpoints per that script.
        Default handles=24, gap_max=30. Use handles=0 for gap-only auto handles.
      conform_capabilities() -> {supported, partially_supported, unsupported, export_aliases}
      probe_timeline_structure(track_types?, include_markers?, include_clip_properties?) -> {tracks, markers}
      detect_gaps_overlaps(track_types?, min_gap?) -> {gaps, overlaps}
      source_range_report(handles?, merge?) -> {ranges, occurrences}
      export_timeline_checked(path, format?|type?, subtype?, require_temp_path?, dry_run?) -> {success, path, size}
      import_timeline_checked(path, options?, timeline_name?, import_source_clips?, require_temp_path?, dry_run?) -> {success, name, id}
      compare_timelines(right_timeline_id?|right_timeline_index?|left_snapshot?, right_snapshot?) -> {match, differences}
      probe_interchange_roundtrip(format?, output_dir?, cleanup_imported?) -> {success, export, import, comparison}
      detect_missing_media(sanitized?|sanitize_paths?, omit_raw_paths?) -> {missing, missing_count, diagnosis}
      build_relink_plan(search_roots, max_depth?, max_seconds?, max_files_scanned?, skip_search_when_volume_missing?, sanitized?) -> {candidates, diagnosis}
      conform_boundary_report(...) -> {capabilities, timeline, gaps_overlaps, source_ranges, missing_media}
      audio_capabilities() -> {supported, partially_supported, unsupported}
      probe_audio_item(track_type?, track_index?, item_index?) -> {summary, audio_properties, source_audio_mapping}
      probe_audio_track(track_index?) -> {track_count, enabled, locked, sub_type, voice_isolation}
      safe_set_audio_properties(properties, restore?, dry_run?, track_type?, track_index?, item_index?) -> {success, results}
      audio_mix_capability_report(...) -> {capabilities, mix_recommendations}
      voice_isolation_capabilities(track_index?, track_type?, item_index?) -> {timeline_track, item}
      audio_mapping_report(clip_ids?) -> {timeline_items, media_pool_items}
      safe_auto_sync_audio(clip_ids|selected, settings?, dry_run?) -> {success}
      transcription_capabilities(clip_ids?|selected?) -> {clip_methods, folder}
      subtitle_generation_probe(settings?, allow_generate?) -> {success}
      fairlight_boundary_report(...) -> {capabilities, track, item, audio_mapping, transcription}

    For long-form per-action guidance and a worked example, call:
      timeline(action="action_help", params={"name": "<action>"})
    """
    p = params or {}
    # action_help is pull-on-demand metadata; no Resolve connection needed.
    if action == "action_help":
        return _action_help("timeline", p)
    pm, proj, err = _check()
    if err:
        return err

    # Actions that don't need a current timeline
    if action == "list":
        count = proj.GetTimelineCount()
        timelines = []
        for i in range(1, count + 1):
            tl = proj.GetTimelineByIndex(i)
            if tl:
                timelines.append({"name": tl.GetName(), "id": tl.GetUniqueId(), "index": i})
        return {"timelines": timelines}
    elif action == "set_current":
        err, clean = _validate_params(p, {"index": {"type": int, "required": True, "min": 1}})
        if err:
            return _err(err)
        tl = proj.GetTimelineByIndex(clean["index"])
        return {"success": bool(proj.SetCurrentTimeline(tl))} if tl else _err(f"No timeline at index {clean['index']}")
    elif action == "edit_kernel_capabilities":
        return _timeline_edit_kernel_capabilities()
    elif action == "conform_capabilities":
        return _conform_capabilities()
    elif action == "audio_capabilities":
        return _audio_capabilities()
    elif action == "import_timeline_checked":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _import_timeline_checked(proj, mp, p)
    elif action == "safe_auto_sync_audio":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _safe_auto_sync_audio(mp, p)
    elif action == "transcription_capabilities":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _transcription_capabilities(mp, p)
    elif action == "compare_timelines" and isinstance(p.get("left_snapshot"), dict) and isinstance(p.get("right_snapshot"), dict):
        return _compare_timelines(proj, proj.GetCurrentTimeline(), p)

    # Remaining actions need current timeline
    tl = proj.GetCurrentTimeline()
    if not tl:
        return _err("No current timeline")

    if action == "clip_where":
        return _timeline_clip_where(tl, p)
    if action == "get_current":
        return {"name": tl.GetName(), "id": tl.GetUniqueId(), "start_frame": tl.GetStartFrame(), "end_frame": tl.GetEndFrame(), "start_timecode": tl.GetStartTimecode()}
    elif action == "get_name":
        return {"name": tl.GetName()}
    elif action == "set_name":
        err, clean = _validate_params(p, {"name": {"type": str, "required": True, "non_empty": True}})
        if err:
            return _err(err)
        return {"success": bool(tl.SetName(clean["name"]))}
    elif action == "get_start_frame":
        return {"frame": tl.GetStartFrame()}
    elif action == "get_end_frame":
        return {"frame": tl.GetEndFrame()}
    elif action == "get_start_timecode":
        return {"timecode": tl.GetStartTimecode()}
    elif action == "set_start_timecode":
        err, clean = _validate_params(p, {"timecode": {"type": str, "required": True, "non_empty": True}})
        if err:
            return _err(err)
        return {"success": bool(tl.SetStartTimecode(clean["timecode"]))}
    elif action == "get_track_count":
        return {"count": tl.GetTrackCount(p["track_type"])}
    elif action == "add_track":
        err, _clean = _validate_params(p, {"track_type": {"enum": ["video", "audio", "subtitle"], "required": True}})
        if err:
            return _err(err)
        opts_in = p.get("options") or {}
        new_track_options: Dict[str, Any] = {}
        if "audio_type" in opts_in:
            new_track_options["audioType"] = opts_in["audio_type"]
        elif "audioType" in opts_in:
            new_track_options["audioType"] = opts_in["audioType"]
        if "index" in opts_in:
            new_track_options["index"] = opts_in["index"]
        if new_track_options:
            return {"success": bool(tl.AddTrack(p["track_type"], new_track_options))}
        return {"success": bool(tl.AddTrack(p["track_type"]))}
    elif action == "delete_track":
        # B2 — catastrophic: deletes track + every item on it.
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            try:
                items_on_track = tl.GetItemListInTrack(p["track_type"], p["index"]) or []
                item_count = len(items_on_track)
            except Exception:
                item_count = None
            return _issue_confirm_token(
                action="timeline.delete_track",
                params=p,
                preview={"operation": "timeline.delete_track",
                         "warning": "Deletes a track AND every clip on it.",
                         "track_type": p.get("track_type"),
                         "track_index": p.get("index"),
                         "items_lost": item_count},
            )
        blocked = _consume_confirm_token(action="timeline.delete_track", params=p)
        if blocked:
            return blocked
        return {"success": bool(tl.DeleteTrack(p["track_type"], p["index"]))}
    elif action == "get_track_sub_type":
        return {"sub_type": tl.GetTrackSubType(p["track_type"], p["index"])}
    elif action == "set_track_enable":
        return {"success": bool(tl.SetTrackEnable(p["track_type"], p["index"], p["enabled"]))}
    elif action == "get_track_enabled":
        return {"enabled": bool(tl.GetIsTrackEnabled(p["track_type"], p["index"]))}
    elif action == "set_track_lock":
        return {"success": bool(tl.SetTrackLock(p["track_type"], p["index"], p["locked"]))}
    elif action == "get_track_locked":
        return {"locked": bool(tl.GetIsTrackLocked(p["track_type"], p["index"]))}
    elif action == "get_track_name":
        return {"name": tl.GetTrackName(p["track_type"], p["index"])}
    elif action == "set_track_name":
        return {"success": bool(tl.SetTrackName(p["track_type"], p["index"], p["name"]))}
    elif action == "get_items":
        items = tl.GetItemListInTrack(p["track_type"], p["index"])
        return {"items": [{"name": it.GetName(), "id": it.GetUniqueId(), "start": it.GetStart(), "end": it.GetEnd(), "duration": it.GetDuration()} for it in (items or [])]}
    elif action == "delete_clips":
        # Find timeline items by unique IDs
        ids_set = set(p["clip_ids"])
        found = []
        for tt in ["video", "audio", "subtitle"]:
            for ti in range(1, tl.GetTrackCount(tt) + 1):
                for it in (tl.GetItemListInTrack(tt, ti) or []):
                    if it.GetUniqueId() in ids_set:
                        found.append(it)
        # B2 — ripple=True is catastrophic; require confirmation.
        ripple = bool(p.get("ripple", False))
        if ripple:
            if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
                return _issue_confirm_token(
                    action="timeline.delete_clips_ripple",
                    params=p,
                    preview={"operation": "timeline.delete_clips",
                             "ripple": True,
                             "warning": "ripple=True closes the gap left by deleted items; cannot be selectively undone.",
                             "clip_count": len(found),
                             "clip_ids_found": [it.GetUniqueId() for it in found]},
                )
            blocked = _consume_confirm_token(action="timeline.delete_clips_ripple", params=p)
            if blocked:
                return blocked
        return {"success": bool(tl.DeleteClips(found, ripple))}
    elif action == "set_clips_linked":
        ids_set = set(p["clip_ids"])
        found = []
        for tt in ["video", "audio"]:
            for ti in range(1, tl.GetTrackCount(tt) + 1):
                for it in (tl.GetItemListInTrack(tt, ti) or []):
                    if it.GetUniqueId() in ids_set:
                        found.append(it)
        return {"success": bool(tl.SetClipsLinked(found, p["linked"]))}
    elif action == "duplicate":
        dup = tl.DuplicateTimeline(p.get("name", tl.GetName() + " Copy"))
        return _ok(name=dup.GetName()) if dup else _err("Failed to duplicate")
    elif action == "duplicate_clips":
        return _timeline_duplicate_clips_impl(proj, tl, p)
    elif action == "copy_clips":
        return _timeline_duplicate_clips_impl(proj, tl, p)
    elif action == "move_clips":
        return _timeline_duplicate_clips_impl(proj, tl, p, delete_sources=True)
    elif action in {"copy_range", "duplicate_range"}:
        return _timeline_copy_range_impl(proj, tl, p)
    elif action == "overwrite_range":
        return _timeline_copy_range_impl(proj, tl, p, overwrite=True)
    elif action == "lift_range":
        return _timeline_lift_range_impl(tl, p)
    elif action == "story_spine_report":
        return _timeline_story_spine_report(tl, p)
    elif action == "create_variant_from_ranges":
        return _timeline_create_variant_from_ranges(proj, tl, p)
    elif action == "bulk_set_item_properties":
        return _timeline_bulk_set_item_properties(tl, p)
    elif action == "apply_look_to_items":
        return _timeline_apply_look_to_items(tl, p)
    elif action == "thumbnail_contact_sheet":
        return _timeline_thumbnail_contact_sheet(proj, tl, p)
    elif action == "marker_thumbnail_review":
        return _timeline_marker_thumbnail_review(proj, tl, p)
    elif action == "edit_kernel_capabilities":
        return _timeline_edit_kernel_capabilities()
    elif action == "probe_edit_kernel_item":
        return _timeline_probe_edit_kernel_item(tl, p)
    elif action == "title_property_scan":
        return _timeline_title_property_scan(tl, p)
    elif action == "set_title_text":
        return _timeline_set_title_text(tl, p)
    elif action == "bulk_set_title_text":
        return _timeline_bulk_set_title_text(tl, p)
    elif action == "create_compound_clip":
        ids_set = set(p["clip_ids"])
        found = []
        for tt in ["video", "audio", "subtitle"]:
            for ti in range(1, (tl.GetTrackCount(tt) or 0) + 1):
                for it in (tl.GetItemListInTrack(tt, ti) or []):
                    if it.GetUniqueId() in ids_set:
                        found.append(it)
        if not found:
            return _err("None of the provided clip IDs were found in the timeline")
        result = tl.CreateCompoundClip(found, p.get("info", {}))
        return _ok() if result else _err("Failed to create compound clip")
    elif action == "create_fusion_clip":
        ids_set = set(p["clip_ids"])
        found = []
        for tt in ["video", "audio", "subtitle"]:
            for ti in range(1, (tl.GetTrackCount(tt) or 0) + 1):
                for it in (tl.GetItemListInTrack(tt, ti) or []):
                    if it.GetUniqueId() in ids_set:
                        found.append(it)
        if not found:
            return _err("None of the provided clip IDs were found in the timeline")
        result = tl.CreateFusionClip(found)
        return _ok() if result else _err("Failed to create Fusion clip")
    elif action == "import_into_timeline":
        options, ignored_opts = _filter_to_keys(p.get("options", {}), _IMPORT_INTO_TIMELINE_OPTION_KEYS)
        result = {"success": bool(tl.ImportIntoTimeline(p["path"], options))}
        if ignored_opts:
            result["ignored_options"] = ignored_opts
        return result
    elif action == "export":
        # Timeline.Export needs resolved resolve.EXPORT_* enum *values*, which a
        # JSON/MCP caller cannot pass — handing it a string silently fails. Resolve
        # friendly type/subtype names (or EXPORT_* constant names) the same way
        # export_timeline_checked does. This raw action keeps no path sandbox.
        spec = _timeline_export_spec(p, get_resolve())
        with long_resolve_op("timeline.export"):
            success = bool(tl.Export(p["path"], spec["export_type"], spec["export_subtype"]))
        return {
            "success": success,
            "export_type": spec["export_type_name"],
            "export_subtype": spec["export_subtype_name"],
        }
    elif action == "get_setting":
        return {"settings": _ser(tl.GetSetting(p.get("name", "")))}
    elif action == "set_setting":
        return {"success": bool(tl.SetSetting(p["name"], p["value"]))}
    elif action == "insert_generator":
        r = tl.InsertGeneratorIntoTimeline(p["name"])
        return _ok() if r else _err("Failed to insert generator")
    elif action == "insert_fusion_generator":
        r = tl.InsertFusionGeneratorIntoTimeline(p["name"])
        return _ok() if r else _err("Failed to insert Fusion generator")
    elif action == "insert_fusion_composition":
        r = tl.InsertFusionCompositionIntoTimeline()
        return _ok() if r else _err("Failed to insert Fusion composition")
    elif action == "insert_ofx_generator":
        r = tl.InsertOFXGeneratorIntoTimeline(p["name"])
        return _ok() if r else _err("Failed to insert OFX generator")
    elif action == "insert_title":
        r = tl.InsertTitleIntoTimeline(p["name"])
        return _ok() if r else _err("Failed to insert title")
    elif action == "insert_fusion_title":
        r = tl.InsertFusionTitleIntoTimeline(p["name"])
        return _ok() if r else _err("Failed to insert Fusion title")
    elif action == "get_unique_id":
        return {"id": tl.GetUniqueId()}
    elif action == "get_node_graph":
        g = tl.GetNodeGraph()
        return {"available": g is not None}
    elif action == "get_media_pool_item":
        mpi = tl.GetMediaPoolItem()
        return {"name": mpi.GetName(), "id": mpi.GetUniqueId()} if mpi else {"name": None, "id": None}
    elif action == "get_transcript":
        return _timeline_transcript(tl, with_timecodes=bool(p.get("with_timecodes")))
    elif action == "propose_cuts":
        # Dry-run only: detect mechanical cuts (fillers, long pauses, repeats)
        # from the timeline's subtitle transcript. Proposes; never edits.
        cues = p.get("cues")
        if cues is None:
            cues = _timeline_transcript(tl, with_timecodes=True)["cues"]
        return _build_cut_list(cues, long_pause_frames=int(p.get("long_pause_frames", 48)))
    elif action == "apply_cuts":
        # Apply a CutList (from propose_cuts) to the timeline. DRY-RUN by default;
        # applying is destructive (confirm-token gated, a version is archived
        # first by the destructive hook). Cuts are applied latest-first so ripple
        # deletes don't invalidate earlier spans.
        cuts = p.get("cuts")
        if not isinstance(cuts, list):
            return _err("apply_cuts requires 'cuts' (a list, e.g. from propose_cuts)")
        applicable = [
            c for c in cuts
            if isinstance(c, dict) and c.get("action") in ("lift", "ripple_delete")
            and isinstance(c.get("span"), dict)
            and c["span"].get("start") is not None and c["span"].get("end") is not None
        ]
        applicable.sort(key=lambda c: c["span"]["start"], reverse=True)
        plan = [{"action": c["action"], "span": c["span"], "kind": c.get("kind")} for c in applicable]

        if p.get("dry_run", True):
            return {
                "dry_run": True,
                "would_apply": len(applicable),
                "plan": plan,
                "note": "No edits made. Re-run with dry_run=false (and a confirm_token) to apply.",
            }

        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="timeline.apply_cuts", params=p,
                preview={
                    "operation": "timeline.apply_cuts",
                    "warning": "Applies lift/ripple deletes to the timeline; ripple closes "
                               "gaps and cannot be selectively undone. A timeline version is "
                               "archived first.",
                    "would_apply": len(applicable),
                    "plan": plan,
                },
            )
        blocked = _consume_confirm_token(action="timeline.apply_cuts", params=p)
        if blocked:
            return blocked

        allow_partial = bool(p.get("allow_partial_item_delete", True))
        results = []
        for c in applicable:
            sp = c["span"]
            res = _timeline_lift_range_impl(tl, {
                "start_frame": sp["start"],
                "end_frame": sp["end"],
                "ripple": c["action"] == "ripple_delete",
                "allow_partial_item_delete": allow_partial,
            })
            results.append({"action": c["action"], "span": sp, "result": res})
        applied = sum(1 for r in results
                      if isinstance(r["result"], dict) and r["result"].get("success"))
        return {"success": True, "applied": applied, "total": len(applicable), "results": results}
    elif action == "get_mark_in_out":
        return _ser(tl.GetMarkInOut())
    elif action == "set_mark_in_out":
        err, clean = _validate_params(
            p,
            {"mark_in": {"type": int, "required": True}, "mark_out": {"type": int, "required": True}},
            invariants=[lambda c: f"mark_in ({c['mark_in']}) must be <= mark_out ({c['mark_out']})"
                        if c["mark_in"] > c["mark_out"] else None],
        )
        if err:
            return _err(err)
        return {"success": bool(tl.SetMarkInOut(clean["mark_in"], clean["mark_out"], p.get("type", "all")))}
    elif action == "clear_mark_in_out":
        return {"success": bool(tl.ClearMarkInOut(p.get("type", "all")))}
    elif action == "convert_to_stereo":
        return {"success": bool(tl.ConvertTimelineToStereo())}
    elif action == "get_items_in_track":
        return {"items": _ser(tl.GetItemListInTrack(p["track_type"], p["track_index"]))}
    elif action == "get_voice_isolation_state":
        missing = _requires_method(tl, "GetVoiceIsolationState", "20.1")
        if missing:
            return missing
        state = tl.GetVoiceIsolationState(p["track_index"])
        return _ser(state) if state else {"isEnabled": False, "amount": 0}
    elif action == "set_voice_isolation_state":
        missing = _requires_method(tl, "SetVoiceIsolationState", "20.1")
        if missing:
            return missing
        state, ignored_state = _filter_to_keys(p["state"], _VOICE_ISOLATION_STATE_KEYS)
        result = {"success": bool(tl.SetVoiceIsolationState(p["track_index"], state))}
        if ignored_state:
            result["ignored_state_keys"] = ignored_state
        return result
    elif action == "extract_source_frame_ranges":
        p = params or {}
        handles = int(p.get("handles", 24))
        gap_max = int(p.get("gap_max", 30))
        audio_ext = tuple(
            x.lower() for x in p.get(
                "skip_extensions",
                (".wav", ".mp3", ".aiff", ".aac", ".m4a"),
            )
        )

        def _ifr(v):
            """Resolve sometimes returns None — skip clip if unset."""
            if v is None:
                return None
            try:
                return int(round(float(v)))
            except (TypeError, ValueError):
                return None

        clip_rows = []
        nvid = tl.GetTrackCount("video") or 0
        for track_index in range(1, nvid + 1):
            clips = tl.GetItemListInTrack("video", track_index) or []
            for clip in clips:
                name = clip.GetName() or ""
                try:
                    mpi = clip.GetMediaPoolItem()
                    if mpi:
                        fp = mpi.GetClipProperty("File Path")
                        if fp:
                            name = os.path.basename(str(fp).replace("\\", "/"))
                except Exception:
                    pass
                low = name.lower()
                if any(low.endswith(ext) for ext in audio_ext):
                    continue
                try:
                    t_start = _ifr(clip.GetStart())
                    t_end_excl = _ifr(clip.GetEnd())
                    lo = _ifr(clip.GetLeftOffset())
                    if lo is None and _has_method(clip, "GetSourceStartFrame"):
                        lo = _ifr(clip.GetSourceStartFrame())
                except Exception:
                    continue
                if t_start is None or t_end_excl is None or lo is None:
                    continue
                duration_tl = t_end_excl - t_start
                if duration_tl < 0:
                    continue
                source_boundary = lo + duration_tl
                timeline_end_inc = t_end_excl - 1
                clip_rows.append({
                    "clip": clip,
                    "name": name,
                    "track": track_index,
                    "timeline_start": t_start,
                    "timeline_end_inclusive": timeline_end_inc,
                    "source_boundary": source_boundary,
                    "offset": lo,
                })
        frame_ranges: Dict[str, List[List[int]]] = {}
        occurrences = []
        for row in clip_rows:
            clip = row["clip"]
            name = row["name"]
            track_index = row["track"]
            t_start = row["timeline_start"]
            t_end_inc = row["timeline_end_inclusive"]
            source_start = row["offset"]
            source_end = row["source_boundary"]
            clips_on_track = tl.GetItemListInTrack("video", track_index) or []
            max_handle = handles
            if handles == 0:
                max_handle = 0
                for other in clips_on_track:
                    oe = _ifr(other.GetEnd())
                    os_ = _ifr(other.GetStart())
                    if oe is None or os_ is None:
                        continue
                    other_end_inc = oe - 1
                    if other_end_inc < t_start:
                        gap = t_start - other_end_inc - 1
                        if 0 < gap <= gap_max:
                            max_handle = max(max_handle, gap)
                    if os_ > t_end_inc:
                        gap = os_ - t_end_inc - 1
                        if 0 < gap <= gap_max:
                            max_handle = max(max_handle, gap)
            final_s = max(0, int(source_start) - int(max_handle))
            final_e = int(source_end) - 1 + int(max_handle)
            frame_ranges.setdefault(name, []).append([final_s, final_e])
            uid = clip.GetUniqueId()
            occurrences.append({
                "clip_name": name,
                "timeline_item_id": "" if uid is None else str(uid),
                "track": track_index,
                "timeline_start": t_start,
                "timeline_end_inclusive": t_end_inc,
                "source_used_inclusive_end": source_end - 1,
                "handle_frames_applied": max_handle,
                "source_range_final": [final_s, final_e],
            })
        return _ok(
            timeline_name=tl.GetName() or "",
            handles_param=handles,
            gap_max=gap_max,
            clip_count=len(occurrences),
            frame_ranges=frame_ranges,
            occurrences=occurrences,
            notes=(
                "Same rules as Pr/extract_timeline_frames.py get_resolve_api_frames (video only, "
                "current timeline). frame_ranges lists can be merged/overlapped per clip name."
            ),
        )
    elif action == "conform_capabilities":
        return _conform_capabilities()
    elif action == "probe_timeline_structure":
        return _timeline_conform_snapshot(tl, p)
    elif action == "detect_gaps_overlaps":
        return _detect_gaps_overlaps_from_snapshot(_timeline_conform_snapshot(tl, p), p)
    elif action == "source_range_report":
        return _source_ranges_from_snapshot(_timeline_conform_snapshot(tl, p), p)
    elif action == "export_timeline_checked":
        return _export_timeline_checked(tl, p)
    elif action == "import_timeline_checked":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _import_timeline_checked(proj, mp, p)
    elif action == "compare_timelines":
        return _compare_timelines(proj, tl, p)
    elif action == "probe_interchange_roundtrip":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _probe_interchange_roundtrip(proj, mp, tl, p)
    elif action == "detect_missing_media":
        return _detect_missing_media(tl, p)
    elif action == "build_relink_plan":
        return _build_relink_plan(tl, p)
    elif action == "conform_boundary_report":
        return _conform_boundary_report(tl, p)
    elif action == "audio_capabilities":
        return _audio_capabilities()
    elif action == "probe_audio_item":
        return _probe_audio_item(tl, p)
    elif action == "probe_audio_track":
        return _audio_track_probe(tl, p)
    elif action == "safe_set_audio_properties":
        return _safe_set_audio_properties(tl, p)
    elif action == "audio_mix_capability_report":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _audio_mix_capability_report(proj, mp, tl, p)
    elif action == "voice_isolation_capabilities":
        return _voice_isolation_capabilities(tl, p)
    elif action == "audio_mapping_report":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _audio_mapping_report(mp, tl, p)
    elif action == "safe_auto_sync_audio":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _safe_auto_sync_audio(mp, p)
    elif action == "transcription_capabilities":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _transcription_capabilities(mp, p)
    elif action == "subtitle_generation_probe":
        return _subtitle_generation_probe(tl, p)
    elif action == "fairlight_boundary_report":
        _, _, mp, mp_err = _get_mp()
        if mp_err:
            return mp_err
        return _fairlight_boundary_report(proj, mp, tl, p)
    return _unknown(action, ["list","get_current","set_current","get_name","set_name","get_start_frame","get_end_frame","get_start_timecode","set_start_timecode","get_track_count","add_track","delete_track","get_track_sub_type","set_track_enable","get_track_enabled","set_track_lock","get_track_locked","get_track_name","set_track_name","get_items","delete_clips","set_clips_linked","duplicate","duplicate_clips","copy_clips","move_clips","copy_range","duplicate_range","overwrite_range","lift_range","story_spine_report","create_variant_from_ranges","bulk_set_item_properties","apply_look_to_items","thumbnail_contact_sheet","marker_thumbnail_review","edit_kernel_capabilities","probe_edit_kernel_item","title_property_scan","set_title_text","bulk_set_title_text","create_compound_clip","create_fusion_clip","import_into_timeline","export","get_setting","set_setting","insert_generator","insert_fusion_generator","insert_fusion_composition","insert_ofx_generator","insert_title","insert_fusion_title","get_unique_id","get_node_graph","get_media_pool_item","get_transcript","propose_cuts","apply_cuts","get_mark_in_out","set_mark_in_out","clear_mark_in_out","convert_to_stereo","get_items_in_track","get_voice_isolation_state","set_voice_isolation_state","extract_source_frame_ranges","audio_mix_capability_report","clip_where","action_help",*_TIMELINE_CONFORM_KERNEL_ACTIONS,*_TIMELINE_AUDIO_KERNEL_ACTIONS])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 16: timeline_markers
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
@_destructive_op("timeline_markers")
def timeline_markers(action: str, params: Optional[Dict[str, Any]] = None) -> Any:
    """Markers and playhead operations on the current timeline.

    Marker frames are RELATIVE to the timeline start: frame 0 is the first
    frame of the timeline, even when the timeline starts at 01:00:00:00.
    Timecode params are absolute timeline timecode as shown in the Resolve UI
    (timecodes before the start timecode are treated as elapsed time) and are
    converted to relative frames automatically.

    Actions:
      add(frame|frame_id|frameId|timecode?, color?, name?, note?, duration?, custom_data?) -> {success, frame}
        If frame/timecode is omitted, add uses the current playhead timecode.
      get_all() -> {markers}
      get_by_custom_data(custom_data) -> {markers}
      update_custom_data(frame|frame_id|frameId|timecode, custom_data) -> {success}
      get_custom_data(frame|frame_id|frameId|timecode) -> {data}
      delete_by_color(color) -> {success}
      delete_at_frame(frame|frame_id|frameId|timecode) -> {success}
      delete_by_custom_data(custom_data) -> {success}
      get_current_timecode() -> {timecode}
      set_current_timecode(timecode) -> {success}
      get_current_video_item() -> {name, id}
      get_thumbnail() -> {thumbnail}
      get_thumbnail_image() -> MCP image content for the current Color-page frame
      annotation_capabilities() -> {scopes, marker_colors, frame_aliases}
      probe_annotations(scope?, ...) -> {scopes, count}
      normalize_marker_payload(frame|timecode?, color?, name?, note?, duration?, custom_data?) -> {marker}
      copy_annotations(source={scope,...}, target={scope,...}, include_flags?, include_clip_color?) -> {success}
      move_annotations(source={scope,...}, target={scope,...}) -> {success}
      sync_marker_custom_data(scope?, frame|timecode, custom_data, ...) -> {success}
      clear_annotations_by_scope(scope?, color?, custom_data?, all?, clear_flags?, clear_clip_color?) -> {success}
      export_review_report(scope?, include_capabilities?) -> {title, annotations, capabilities?}
      annotation_boundary_report(scope?) -> {capabilities, annotations}
    """
    p = params or {}
    _, tl, err = _get_tl()
    if err:
        return err

    if action == "add":
        marker, marker_err = _marker_add_payload(p, tl=tl, default_to_current=True)
        if marker_err:
            return marker_err
        return _add_marker(tl, marker)
    elif action == "get_all":
        return {"markers": _ser(tl.GetMarkers())}
    elif action == "get_by_custom_data":
        return {"markers": _ser(tl.GetMarkerByCustomData(_first_param(p, "custom_data", "customData", default="")))}
    elif action == "update_custom_data":
        frame, frame_err = _marker_frame_from_params(p, tl=tl)
        if frame_err:
            return frame_err
        return {"success": bool(tl.UpdateMarkerCustomData(frame, _first_param(p, "custom_data", "customData", default="")))}
    elif action == "get_custom_data":
        frame, frame_err = _marker_frame_from_params(p, tl=tl)
        if frame_err:
            return frame_err
        return {"data": tl.GetMarkerCustomData(frame)}
    elif action == "delete_by_color":
        if not p.get("color"):
            return _err("delete_by_color requires color")
        return {"success": bool(tl.DeleteMarkersByColor(p["color"]))}
    elif action == "delete_at_frame":
        frame, frame_err = _marker_frame_from_params(p, tl=tl)
        if frame_err:
            return frame_err
        return {"success": bool(tl.DeleteMarkerAtFrame(frame))}
    elif action == "delete_by_custom_data":
        return {"success": bool(tl.DeleteMarkerByCustomData(_first_param(p, "custom_data", "customData", default="")))}
    elif action == "get_current_timecode":
        return {"timecode": tl.GetCurrentTimecode()}
    elif action == "set_current_timecode":
        return {"success": bool(tl.SetCurrentTimecode(p["timecode"]))}
    elif action == "get_current_video_item":
        it = tl.GetCurrentVideoItem()
        return {"name": it.GetName(), "id": it.GetUniqueId()} if it else {"name": None, "id": None}
    elif action == "get_thumbnail":
        thumbnail = tl.GetCurrentClipThumbnailImage()
        if thumbnail is None:
            return {
                "success": False,
                "thumbnail": None,
                "error": "Resolve did not return a thumbnail for the current playhead. Open the Color page and ensure a video item is under the playhead.",
            }
        return _ser(thumbnail)
    elif action == "get_thumbnail_image":
        thumbnail = tl.GetCurrentClipThumbnailImage()
        if not thumbnail:
            return _err("No thumbnail available. Open the Color page with a current clip selected.")
        try:
            return Image(data=_thumbnail_data_to_png_bytes(thumbnail), format="png")
        except ValueError as exc:
            return _err(str(exc))
    elif action == "annotation_capabilities":
        return _annotation_capabilities()
    elif action == "probe_annotations":
        return _probe_annotations(tl, p)
    elif action == "normalize_marker_payload":
        return _normalize_marker_payload_action(tl, p)
    elif action == "copy_annotations":
        return _copy_annotations(tl, p)
    elif action == "move_annotations":
        return _copy_annotations(tl, p, move=True)
    elif action == "sync_marker_custom_data":
        return _sync_marker_custom_data(tl, p)
    elif action == "clear_annotations_by_scope":
        return _clear_annotations_by_scope(tl, p)
    elif action == "export_review_report":
        return _export_review_report(tl, p)
    elif action == "annotation_boundary_report":
        return _annotation_boundary_report(tl, p)
    return _unknown(action, ["add","get_all","get_by_custom_data","update_custom_data","get_custom_data","delete_by_color","delete_at_frame","delete_by_custom_data","get_current_timecode","set_current_timecode","get_current_video_item","get_thumbnail","get_thumbnail_image",*_ANNOTATION_KERNEL_ACTIONS])


# ═══════════════════════════════════════════════════════════════════════════════
# TOOL 17: timeline_ai
# ═══════════════════════════════════════════════════════════════════════════════

@mcp.tool()
@_destructive_op("timeline_ai")
def timeline_ai(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """AI and analysis operations on the current timeline.

    Actions:
      create_subtitles(settings?) -> {success}  — auto-caption from audio
      detect_scene_cuts() -> {success}
      analyze_dolby_vision(clip_ids?, analysis_type?) -> {success}
      grab_still() -> {success}
      grab_all_stills(source?) -> {count}
    """
    p = params or {}
    _, tl, err = _get_tl()
    if err:
        return err

    if action == "create_subtitles":
        with long_resolve_op("timeline_ai.create_subtitles"):
            return _safe_create_subtitles(tl, p)
    elif action == "detect_scene_cuts":
        with long_resolve_op("timeline_ai.detect_scene_cuts"):
            return {"success": bool(tl.DetectSceneCuts())}
    elif action == "analyze_dolby_vision":
        clip_ids = p.get("clip_ids", [])
        items = []
        if clip_ids:
            for tt in ["video"]:
                for ti in range(1, tl.GetTrackCount(tt) + 1):
                    for it in (tl.GetItemListInTrack(tt, ti) or []):
                        if it.GetUniqueId() in clip_ids:
                            items.append(it)
        analysis_type = p.get("analysis_type")
        with long_resolve_op("timeline_ai.analyze_dolby_vision"):
            return {"success": bool(tl.AnalyzeDolbyVision(items, analysis_type))}
    elif action == "grab_still":
        still = tl.GrabStill()
        return _ok() if still else _err("Failed to grab still")
    elif action == "grab_all_stills":
        stills = tl.GrabAllStills(p.get("source", 1))
        return {"count": len(stills) if stills else 0}
    return _unknown(action, ["create_subtitles","detect_scene_cuts","analyze_dolby_vision","grab_still","grab_all_stills"])


